package io.github.kryen.chancemantrackersync;

import com.google.gson.Gson;
import com.google.gson.annotations.SerializedName;
import com.google.gson.reflect.TypeToken;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.lang.reflect.Type;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import javax.inject.Inject;
import net.runelite.api.Client;

final class AchievementDiaryVarResolver
{
    private static final String SPECS_RESOURCE = "/achievement_diary_var_specs.json";
    private static final Type SPECS_TYPE = new TypeToken<LinkedHashMap<String, LinkedHashMap<String, TierSpec>>>() { }.getType();
    private static final String[] DIARY_ORDER = {
        "Ardougne",
        "Desert",
        "Falador",
        "Fremennik",
        "Kandarin",
        "Karamja",
        "Kourend & Kebos",
        "Lumbridge & Draynor",
        "Morytania",
        "Varrock",
        "Western Provinces",
        "Wilderness"
    };
    private static final String[] TIER_ORDER = {"Easy", "Medium", "Hard", "Elite"};

    private final Map<String, Map<String, TierSpec>> specs;

    @Inject
    AchievementDiaryVarResolver(Gson gson)
    {
        this.specs = loadSpecs(gson);
    }

    Map<String, Map<String, TrackerBlobExporter.AchievementDiaryTierBlob>> resolve(Client client)
    {
        Map<String, Map<String, TrackerBlobExporter.AchievementDiaryTierBlob>> diaries = new LinkedHashMap<>();
        for (String diaryName : DIARY_ORDER)
        {
            Map<String, TierSpec> diarySpec = specs.get(diaryName);
            if (diarySpec == null)
            {
                throw new IllegalStateException("Missing achievement diary definition for " + diaryName);
            }

            Map<String, TrackerBlobExporter.AchievementDiaryTierBlob> tiers = new LinkedHashMap<>();
            for (String tierName : TIER_ORDER)
            {
                tiers.put(tierName, buildTierBlob(client, diaryName, tierName, diarySpec.get(tierName)));
            }
            diaries.put(diaryName, tiers);
        }
        return diaries;
    }

    private TrackerBlobExporter.AchievementDiaryTierBlob buildTierBlob(Client client, String diaryName, String tierName, TierSpec spec)
    {
        if (spec == null || spec.complete == null || spec.tasks == null)
        {
            throw new IllegalStateException("Missing achievement diary spec for " + diaryName + " / " + tierName);
        }

        TrackerBlobExporter.AchievementDiaryTierBlob tier = new TrackerBlobExporter.AchievementDiaryTierBlob();
        tier.complete = resolveSpec(spec.complete, client, diaryName, tierName, -1);
        tier.taskStatesAvailable = true;
        tier.tasks = new ArrayList<>(spec.tasks.size());
        for (int taskIndex = 0; taskIndex < spec.tasks.size(); taskIndex++)
        {
            tier.tasks.add(resolveSpec(spec.tasks.get(taskIndex), client, diaryName, tierName, taskIndex));
        }
        return tier;
    }

    private boolean resolveSpec(VarSpec spec, Client client, String diaryName, String tierName, int taskIndex)
    {
        if (spec == null || spec.type == null)
        {
            return false;
        }

        if ("Desert".equals(diaryName) && "Medium".equals(tierName) && taskIndex == 10)
        {
            return isBitSet(client.getVarpValue(1199), 9) || isBitSet(client.getVarpValue(1198), 22);
        }

        switch (spec.type)
        {
            case "bits":
                return spec.value != null && client.getVarbitValue(spec.varId) == spec.value;
            case "player":
                return spec.offset != null && isBitSet(client.getVarpValue(spec.varId), spec.offset);
            default:
                return false;
        }
    }

    private boolean isBitSet(int value, int offset)
    {
        return ((value >>> offset) & 1) != 0;
    }

    private Map<String, Map<String, TierSpec>> loadSpecs(Gson gson)
    {
        InputStream stream = AchievementDiaryVarResolver.class.getResourceAsStream(SPECS_RESOURCE);
        if (stream == null)
        {
            throw new IllegalStateException("Missing achievement diary specs resource: " + SPECS_RESOURCE);
        }

        try (InputStreamReader reader = new InputStreamReader(stream, StandardCharsets.UTF_8))
        {
            Map<String, Map<String, TierSpec>> parsed = gson.fromJson(reader, SPECS_TYPE);
            if (parsed == null || parsed.isEmpty())
            {
                throw new IllegalStateException("Achievement diary specs resource is empty");
            }
            return parsed;
        }
        catch (Exception ex)
        {
            throw new IllegalStateException("Failed to load achievement diary specs", ex);
        }
    }

    static final class TierSpec
    {
        VarSpec complete;
        List<VarSpec> tasks;
    }

    static final class VarSpec
    {
        String type;
        Integer value;
        Integer offset;
        @SerializedName("var_id")
        int varId;
    }
}

package io.github.kryen.chancemantrackersync;

import com.google.gson.Gson;
import com.google.inject.Provides;
import java.awt.Toolkit;
import java.awt.datatransfer.StringSelection;
import java.awt.image.BufferedImage;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import javax.inject.Inject;
import javax.swing.SwingUtilities;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Client;
import net.runelite.api.events.ChatMessage;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.NavigationButton;
import net.runelite.client.util.ImageUtil;
import net.runelite.client.util.LinkBrowser;

@Slf4j
@PluginDescriptor(
    name = "Chanceman Tracker Sync",
    description = "Exports tracker data and can open chanceman-tracker.github.io via a temporary localhost bridge",
    tags = {"chanceman", "tracker", "sync", "clipboard", "upload"}
)
public class ChancemanTrackerSyncPlugin extends Plugin
{
    static final String PLUGIN_VERSION = "0.1.0-SNAPSHOT";

    private static final Pattern HUNTER_RUMOUR_KC_PATTERN =
        Pattern.compile("You have completed <col=[0-9a-f]{6}>([0-9,]+)</col> rumours? for the Hunter Guild\\.");

    @Inject
    private Gson gson;

    @Inject
    private TrackerBlobExporter exporter;

    @Inject
    private TrackerDirectUploadService directUploadService;

    private Gson prettyGson;

    @Inject
    private Client client;

    @Inject
    private ClientThread clientThread;

    @Inject
    private ClientToolbar clientToolbar;

    @Inject
    private ChancemanTrackerSyncConfig config;

    @Inject
    private ConfigManager configManager;

    private NavigationButton navigationButton;
    private ChancemanTrackerSyncPanel panel;

    @Override
    protected void startUp()
    {
        prettyGson = gson.newBuilder()
            .disableHtmlEscaping()
            .setPrettyPrinting()
            .create();

        panel = new ChancemanTrackerSyncPanel(this);
        BufferedImage icon = ImageUtil.loadImageResource(ChancemanTrackerSyncPlugin.class, "icon.png");
        navigationButton = NavigationButton.builder()
            .tooltip("Chanceman Tracker Sync")
            .icon(icon)
            .priority(5)
            .panel(panel)
            .build();
        clientToolbar.addNavigation(navigationButton);
        log.debug("Chanceman Tracker Sync started");
    }

    @Override
    protected void shutDown()
    {
        directUploadService.stop();
        if (navigationButton != null)
        {
            clientToolbar.removeNavigation(navigationButton);
            navigationButton = null;
        }
        panel = null;
        log.debug("Chanceman Tracker Sync stopped");
    }

    @Subscribe
    public void onChatMessage(ChatMessage event)
    {
        Matcher matcher = HUNTER_RUMOUR_KC_PATTERN.matcher(event.getMessage());
        if (!matcher.find())
        {
            return;
        }

        int kc = Integer.parseInt(matcher.group(1).replace(",", ""));
        configManager.setConfiguration("chancemantrackersync", "hunterRumoursCompleted", kc);
        log.debug("Captured Hunter Rumours count: {}", kc);
    }

    void copyTrackerBlob()
    {
        if (panel != null)
        {
            panel.setBusy("Collecting tracker data...");
        }

        clientThread.invoke(() ->
        {
            try
            {
                TrackerBlobExporter.ExportResult exportResult = exporter.export(
                    client,
                    config.hunterRumoursCompleted()
                );
                String json = prettyGson.toJson(exportResult.blob);
                copyToClipboard(json);

                if (log.isDebugEnabled())
                {
                    log.debug("Tracker blob:{}{}", System.lineSeparator(), json);
                    log.debug("Named var snapshot:{}{}", System.lineSeparator(), prettyGson.toJson(exporter.buildDebugNamedVars(client)));
                }

                SwingUtilities.invokeLater(() ->
                {
                    if (panel != null)
                    {
                        panel.setResult("Copied tracker blob to clipboard.", exportResult.summary + System.lineSeparator() + System.lineSeparator() + json);
                    }
                });
            }
            catch (Exception ex)
            {
                log.warn("Failed to export tracker blob", ex);
                SwingUtilities.invokeLater(() ->
                {
                    if (panel != null)
                    {
                        panel.setError(ex.getMessage() != null ? ex.getMessage() : "Failed to export tracker blob.");
                    }
                });
            }
        });
    }

    void openTrackerWithData()
    {
        if (panel != null)
        {
            panel.setBusy("Preparing tracker upload...");
        }

        clientThread.invoke(() ->
        {
            try
            {
                TrackerBlobExporter.ExportResult exportResult = exporter.export(
                    client,
                    config.hunterRumoursCompleted()
                );
                String compactJson = gson.toJson(exportResult.blob);
                String previewJson = prettyGson.toJson(exportResult.blob);
                TrackerDirectUploadService.DirectUploadResult uploadResult =
                    directUploadService.buildUrl(exportResult.blob.player.name, compactJson);

                SwingUtilities.invokeLater(() ->
                {
                    LinkBrowser.browse(uploadResult.url);
                    if (panel != null)
                    {
                        panel.setResult(
                            "Opened tracker with synced data.",
                            uploadResult.summary + System.lineSeparator() + System.lineSeparator() + previewJson
                        );
                    }
                });
            }
            catch (Exception ex)
            {
                log.warn("Failed to prepare direct tracker upload", ex);
                SwingUtilities.invokeLater(() ->
                {
                    if (panel != null)
                    {
                        panel.setError(ex.getMessage() != null ? ex.getMessage() : "Failed to prepare direct tracker upload.");
                    }
                });
            }
        });
    }

    private void copyToClipboard(String text)
    {
        Toolkit.getDefaultToolkit().getSystemClipboard().setContents(new StringSelection(text), null);
    }

    @Provides
    ChancemanTrackerSyncConfig provideConfig(ConfigManager configManager)
    {
        return configManager.getConfig(ChancemanTrackerSyncConfig.class);
    }
}

