@Value
public class DonationInfo
{
    /// Display name of the donor.
    @With
    private String from;

    /// Display name of the receiver.
    @NonNull
    private String to;

    /// A non-negative amount of GP.
    private int amount;

    /// Screenshot of the trade, price check or looting bag screen.
    @NonNull
