package com.mylosis.roster.ui;

import com.mylosis.roster.ui.components.SearchBar;
import com.mylosis.roster.ui.components.Theme;
import lombok.Getter;

import javax.swing.*;
import java.awt.*;
import java.util.function.Consumer;

/**
 * Builds the header section of the Roster panel.
 * Contains title, version badge, search bar, and action buttons.
 */
public class PanelHeaderBuilder
{
    @Getter
    private SearchBar searchBar;

    /**
     * Create the full header panel with title, search, and action buttons.
     */
    public JPanel build(Consumer<String> onSearchChanged, Runnable onAddAccount, Runnable onAddCategory)
    {
        JPanel header = new JPanel();
        header.setLayout(new BoxLayout(header, BoxLayout.Y_AXIS));
        header.setBackground(Theme.BACKGROUND);
        header.setBorder(BorderFactory.createEmptyBorder(0, 0, Theme.SPACING_LG, 0));

        header.add(createTitleRow());
        header.add(Box.createVerticalStrut(Theme.SPACING_MD));

        searchBar = createSearchBar(onSearchChanged);
        header.add(searchBar);
        header.add(Box.createVerticalStrut(Theme.SPACING_MD));

        header.add(createActionButtonsRow(onAddAccount, onAddCategory));

        return header;
    }

    private JPanel createTitleRow()
    {
        JPanel titleRow = new JPanel(new BorderLayout());
        titleRow.setBackground(Theme.BACKGROUND);
        titleRow.setMaximumSize(new Dimension(Integer.MAX_VALUE, 30));
        titleRow.setAlignmentX(Component.LEFT_ALIGNMENT);

        JLabel titleLabel = new JLabel("Roster");
        titleLabel.setForeground(Theme.TEXT_PRIMARY);
        titleLabel.setFont(Theme.fontBold(titleLabel.getFont(), Theme.FONT_SIZE_TITLE));
        titleRow.add(titleLabel, BorderLayout.WEST);

        JLabel versionLabel = new JLabel("v" + Theme.VERSION);
        versionLabel.setForeground(Theme.TEXT_MUTED);
        versionLabel.setFont(Theme.fontRegular(versionLabel.getFont(), Theme.FONT_SIZE_TINY));
        titleRow.add(versionLabel, BorderLayout.EAST);

        return titleRow;
    }

    private SearchBar createSearchBar(Consumer<String> onSearchChanged)
    {
        SearchBar bar = new SearchBar();
        bar.setPlaceholder("Filter...");
        bar.setMaximumSize(new Dimension(Integer.MAX_VALUE, 32));
        bar.setAlignmentX(Component.LEFT_ALIGNMENT);
        bar.setOnSearchChanged(onSearchChanged::accept);
        return bar;
    }

    private JPanel createActionButtonsRow(Runnable onAddAccount, Runnable onAddCategory)
    {
        JPanel buttonRow = new JPanel(new GridBagLayout());
        buttonRow.setBackground(Theme.BACKGROUND);
        buttonRow.setMaximumSize(new Dimension(Integer.MAX_VALUE, Theme.BUTTON_HEIGHT + 4));
        buttonRow.setAlignmentX(Component.LEFT_ALIGNMENT);

        GridBagConstraints gbc = new GridBagConstraints();
        gbc.fill = GridBagConstraints.BOTH;
        gbc.gridy = 0;

        gbc.gridx = 0;
        gbc.weightx = 0.75;
        gbc.insets = new Insets(0, 0, 0, Theme.SPACING_XS);
        buttonRow.add(createActionButton("+ Account", "Add a new account", onAddAccount), gbc);

        gbc.gridx = 1;
        gbc.weightx = 0.25;
        gbc.insets = new Insets(0, 0, 0, 0);
        buttonRow.add(createActionButton("+ Category", "Add category", onAddCategory), gbc);

        return buttonRow;
    }

    private JButton createActionButton(String text, String tooltip, Runnable onClick)
    {
        JButton button = new JButton(text);
        button.setBackground(Theme.BUTTON_SECONDARY);
        button.setForeground(Theme.TEXT_PRIMARY);
        button.setFocusPainted(false);
        button.setBorderPainted(false);
        button.setFont(Theme.fontRegular(button.getFont(), Theme.FONT_SIZE_BODY));
        button.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        button.setToolTipText(tooltip);
        button.addActionListener(e -> onClick.run());
        button.addMouseListener(new java.awt.event.MouseAdapter()
        {
            @Override
            public void mouseEntered(java.awt.event.MouseEvent e)
            {
                button.setBackground(Theme.BUTTON_SECONDARY_HOVER);
            }

            @Override
            public void mouseExited(java.awt.event.MouseEvent e)
            {
                button.setBackground(Theme.BUTTON_SECONDARY);
            }
        });
        return button;
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.ui.components.Theme;
import com.mylosis.roster.ui.dnd.CategoryDragListener;
import com.mylosis.roster.ui.dnd.DragDropManager;
import com.mylosis.roster.ui.dnd.AccountDragListener;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.util.List;

@Slf4j
public class CategoryPanel extends JPanel
{
    private final RosterPlugin plugin;
    @Getter
    private final ProfileGroup group;
    private final List<Account> profiles;
    private final DragDropManager dragDropManager;
    private final CategoryFormHandler formHandler;

    private final JPanel contentWrapper;
    private final JLabel chevronLabel;
    private boolean collapsed;

    public CategoryPanel(RosterPlugin plugin, ProfileGroup group, List<Account> profiles, DragDropManager dragDropManager)
    {
        this.plugin = plugin;
        this.group = group;
        this.profiles = profiles;
        this.dragDropManager = dragDropManager;
        this.collapsed = group.isCollapsed();
        this.formHandler = new CategoryFormHandler(plugin, group, this::toggleCollapsed);

        setLayout(new BorderLayout());
        setBackground(Theme.BACKGROUND);
        setMaximumSize(new Dimension(Integer.MAX_VALUE, Integer.MAX_VALUE));

        add(createHeader(), BorderLayout.NORTH);

        boolean gridMode = plugin.getConfig().gridView();

        contentWrapper = new JPanel();
        contentWrapper.setBackground(Theme.BACKGROUND);

        if (gridMode)
        {
            // Grid: use GridLayout inside a NORTH-aligned wrapper so it doesn't stretch
            int cols = 2;
            JPanel gridPanel = new JPanel(new GridLayout(0, cols, Theme.SPACING_XS, Theme.SPACING_XS));
            gridPanel.setBackground(Theme.BACKGROUND);

            for (Account profile : profiles)
            {
                AccountCardPanel card = new AccountCardPanel(plugin, profile, plugin.getPanel());
                AccountDragListener dragListener = new AccountDragListener(dragDropManager, profile, card);
                dragListener.attachToComponent(card);
                gridPanel.add(card);
            }

            contentWrapper.setLayout(new BorderLayout());
            contentWrapper.setBorder(new EmptyBorder(Theme.SPACING_SM, 0, 0, 0));
            contentWrapper.add(gridPanel, BorderLayout.NORTH);
            contentWrapper.add(formHandler.getOrCreateFormPanel(), BorderLayout.CENTER);
        }
        else
        {
            contentWrapper.setLayout(new BoxLayout(contentWrapper, BoxLayout.Y_AXIS));
            contentWrapper.setBorder(new EmptyBorder(Theme.SPACING_SM, 0, 0, 0));

            for (Account profile : profiles)
            {
                AccountCardPanel card = new AccountCardPanel(plugin, profile, plugin.getPanel());
                AccountDragListener dragListener = new AccountDragListener(dragDropManager, profile, card);
                dragListener.attachToComponent(card);
                contentWrapper.add(card);
                contentWrapper.add(Box.createVerticalStrut(Theme.SPACING_XS));
            }

            contentWrapper.add(formHandler.getOrCreateFormPanel());
        }

        add(contentWrapper, BorderLayout.CENTER);

        chevronLabel = new JLabel(collapsed ? "\u25B6" : "\u25BC");
        chevronLabel.setForeground(Theme.TEXT_SECONDARY);
        chevronLabel.setFont(Theme.fontRegular(chevronLabel.getFont(), Theme.FONT_SIZE_TINY));

        updateCollapsedState();
    }

    private JPanel createHeader()
    {
        JPanel headerPanel = new JPanel(new BorderLayout(Theme.SPACING_MD, 0));
        headerPanel.setBackground(Theme.GROUP_HEADER);
        headerPanel.setBorder(BorderFactory.createCompoundBorder(
            BorderFactory.createMatteBorder(0, 0, 1, 0, Theme.CARD_BORDER),
            new EmptyBorder(Theme.SPACING_SM, Theme.SPACING_MD, Theme.SPACING_SM, Theme.SPACING_MD)
        ));
        headerPanel.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));

        JPanel leftPanel = new JPanel(new FlowLayout(FlowLayout.LEFT, Theme.SPACING_SM, 0));
        leftPanel.setOpaque(false);

        // Chevron colored by category color when enabled
        Color catColor = Theme.parseColor(group.getColor());

        JLabel chevron = new JLabel(collapsed ? "\u25B6" : "\u25BC");
        chevron.setForeground(catColor != null ? catColor : Theme.TEXT_SECONDARY);
        chevron.setFont(Theme.fontRegular(chevron.getFont(), Theme.FONT_SIZE_TINY));
        leftPanel.add(chevron);

        JLabel nameLabel = new JLabel(group.getName());
        nameLabel.setForeground(Theme.TEXT_PRIMARY);
        nameLabel.setFont(Theme.fontBold(nameLabel.getFont(), Theme.FONT_SIZE_BODY));
        leftPanel.add(nameLabel);

        JLabel countLabel = new JLabel("\u2022 " + profiles.size());
        countLabel.setForeground(Theme.TEXT_SECONDARY);
        countLabel.setFont(Theme.fontBold(countLabel.getFont(), Theme.FONT_SIZE_BODY));
        leftPanel.add(countLabel);

        headerPanel.add(leftPanel, BorderLayout.CENTER);

        JPanel rightPanel = new JPanel(new FlowLayout(FlowLayout.RIGHT, 2, 0));
        rightPanel.setOpaque(false);
        rightPanel.add(createAddButton());
        rightPanel.add(createMenuButton());
        headerPanel.add(rightPanel, BorderLayout.EAST);

        CategoryDragListener categoryDragListener = new CategoryDragListener(dragDropManager, group);
        headerPanel.addMouseListener(categoryDragListener);
        headerPanel.addMouseMotionListener(categoryDragListener);

        headerPanel.addMouseListener(new MouseAdapter()
        {
            private long pressTime = 0;
            private Point pressPoint = null;

            @Override
            public void mousePressed(MouseEvent e) { pressTime = System.currentTimeMillis(); pressPoint = e.getPoint(); }

            @Override
            public void mouseReleased(MouseEvent e)
            {
                if (pressPoint != null)
                {
                    long duration = System.currentTimeMillis() - pressTime;
                    int dx = Math.abs(e.getPoint().x - pressPoint.x);
                    int dy = Math.abs(e.getPoint().y - pressPoint.y);
                    if (duration < 300 && dx < 5 && dy < 5 && e.getButton() == MouseEvent.BUTTON1)
                    {
                        toggleCollapsed();
                        Component[] components = leftPanel.getComponents();
                        if (components.length > 0 && components[0] instanceof JLabel)
                        {
                            ((JLabel) components[0]).setText(collapsed ? "\u25B6" : "\u25BC");
                        }
                    }
                }
                pressPoint = null;
            }

            @Override
            public void mouseEntered(MouseEvent e) { headerPanel.setBackground(Theme.GROUP_HEADER_HOVER); }

            @Override
            public void mouseExited(MouseEvent e) { headerPanel.setBackground(Theme.GROUP_HEADER); }
        });

        return headerPanel;
    }

    private JButton createAddButton()
    {
        JButton button = new JButton("+");
        button.setBackground(Theme.GROUP_HEADER);
        button.setForeground(Theme.TEXT_SECONDARY);
        button.setFocusPainted(false);
        button.setBorderPainted(false);
        button.setPreferredSize(new Dimension(28, Theme.BUTTON_HEIGHT_SM));
        button.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        button.setToolTipText("Add account to this category");
        button.setFont(button.getFont().deriveFont(Font.BOLD, 18f));
        button.addActionListener(e -> formHandler.toggleAddForm(collapsed, this));
        button.addMouseListener(new MouseAdapter()
        {
            @Override
            public void mouseClicked(MouseEvent e) { e.consume(); }

            @Override
            public void mouseEntered(MouseEvent e) { button.setBackground(Theme.BUTTON_PRIMARY); button.setForeground(Theme.TEXT_PRIMARY); }

            @Override
            public void mouseExited(MouseEvent e) { button.setBackground(Theme.GROUP_HEADER); button.setForeground(Theme.TEXT_SECONDARY); }
        });
        return button;
    }

    private JButton createMenuButton()
    {
        JButton button = new JButton("\u22EE");
        button.setBackground(Theme.GROUP_HEADER);
        button.setForeground(Theme.TEXT_SECONDARY);
        button.setFocusPainted(false);
        button.setBorderPainted(false);
        button.setPreferredSize(new Dimension(24, Theme.BUTTON_HEIGHT_SM));
        button.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));

        JPopupMenu menu = formHandler.createContextMenu();
        button.addActionListener(e -> menu.show(button, 0, button.getHeight()));
        button.addMouseListener(new MouseAdapter()
        {
            @Override
            public void mouseClicked(MouseEvent e) { e.consume(); }

            @Override
            public void mouseEntered(MouseEvent e) { button.setBackground(Theme.GROUP_HEADER_HOVER); }

            @Override
            public void mouseExited(MouseEvent e) { button.setBackground(Theme.GROUP_HEADER); }
        });
        return button;
    }

    private void toggleCollapsed()
    {
        collapsed = !collapsed;
        group.setCollapsed(collapsed);
        plugin.getAccountStorage().saveGroup(group);
        updateCollapsedState();
    }

    private void updateCollapsedState()
    {
        contentWrapper.setVisible(!collapsed);
        chevronLabel.setText(collapsed ? "\u25B6" : "\u25BC");
        revalidate();
        repaint();
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterConfig;
import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.AccountMetadata;
import com.mylosis.roster.ui.components.InlineAccountForm;
import com.mylosis.roster.ui.components.Theme;
import lombok.Getter;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;

public class AccountCardPanel extends JPanel
{
    private final RosterPlugin plugin;
    @Getter
    private final Account profile;
    private final RosterConfig config;

    private boolean hovered = false;
    private Color currentBackground;
    private JPanel headerPanel;
    private CardExpansionHandler expansionHandler;
    private boolean gridEditMode = false;
    private RosterPanel parentPanel;

    public AccountCardPanel(RosterPlugin plugin, Account profile, RosterPanel parentPanel)
    {
        this.plugin = plugin;
        this.profile = profile;
        this.config = plugin.getConfig();
        this.parentPanel = parentPanel;
        boolean isSelected = profile.getId().equals(plugin.getSelectedAccountId());
        this.currentBackground = isSelected ? Theme.CARD_SELECTED : Theme.CARD_BACKGROUND;

        setLayout(new BorderLayout(0, 0));
        setBackground(currentBackground);
        setBorder(createCardBorder());
        setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));

        if (config.gridView())
        {
            GridAccountBuilder.build(this, plugin, profile, this::expandGridEdit);
            setPreferredSize(new Dimension(0, GridAccountBuilder.GRID_CARD_HEIGHT));
            setMaximumSize(new Dimension(Integer.MAX_VALUE, GridAccountBuilder.GRID_CARD_HEIGHT));
        }
        else
        {
            setMaximumSize(new Dimension(Integer.MAX_VALUE, Theme.CARD_HEIGHT));
            buildCard(parentPanel);
        }
        setupMouseListeners();
    }

    private javax.swing.border.Border createCardBorder()
    {
        if (profile.getGroupId() != null)
        {
            var group = plugin.getAccountStorage().getGroup(profile.getGroupId());
            if (group != null)
            {
                Color catColor = Theme.parseColor(group.getColor());
                if (catColor != null)
                {
                    return BorderFactory.createCompoundBorder(
                        BorderFactory.createMatteBorder(0, Theme.CATEGORY_BORDER_WIDTH, 0, 0, catColor),
                        BorderFactory.createLineBorder(Theme.CARD_BORDER, 1)
                    );
                }
            }
        }
        return BorderFactory.createLineBorder(Theme.CARD_BORDER, 1);
    }

    private void buildCard(RosterPanel parentPanel)
    {
        headerPanel = new JPanel(new BorderLayout(Theme.SPACING_MD, 0));
        headerPanel.setOpaque(false);
        headerPanel.setBorder(new EmptyBorder(Theme.SPACING_MD, Theme.SPACING_LG, Theme.SPACING_MD, Theme.SPACING_LG));

        headerPanel.add(createInfoPanel(), BorderLayout.CENTER);
        headerPanel.add(createActionButtons(), BorderLayout.EAST);

        add(headerPanel, BorderLayout.NORTH);

        expansionHandler = new CardExpansionHandler(plugin, profile, parentPanel, this, headerPanel);
        JPanel formPanel = expansionHandler.createFormPanel();
        formPanel.setVisible(false);
        add(formPanel, BorderLayout.CENTER);
    }

    private JPanel createInfoPanel()
    {
        JPanel infoPanel = new JPanel(new GridBagLayout());
        infoPanel.setOpaque(false);

        GridBagConstraints gbc = new GridBagConstraints();
        gbc.gridx = 0;
        gbc.gridy = 0;
        gbc.anchor = GridBagConstraints.WEST;
        gbc.fill = GridBagConstraints.HORIZONTAL;
        gbc.weightx = 1.0;

        // Display name — determine what to show based on privacy settings
        String displayName = AccountCardHelper.resolveDisplayName(profile, config);
        String loggedIn = plugin.getLoggedInDisplayName();
        boolean isOnline = loggedIn != null && displayName != null && loggedIn.equalsIgnoreCase(profile.getDisplayName());

        if (isOnline)
        {
            JPanel nameRow = new JPanel(new FlowLayout(FlowLayout.LEFT, Theme.SPACING_XS, 0));
            nameRow.setOpaque(false);
            nameRow.add(AccountCardHelper.createOnlineDot());
            nameRow.add(AccountCardHelper.createTruncatingLabel(displayName, Theme.TEXT_PRIMARY,
                Theme.fontBold(getFont(), Theme.FONT_SIZE_HEADING), 14));
            infoPanel.add(nameRow, gbc);
        }
        else
        {
            infoPanel.add(AccountCardHelper.createTruncatingLabel(displayName, Theme.TEXT_PRIMARY,
                Theme.fontBold(getFont(), Theme.FONT_SIZE_HEADING), 16), gbc);
        }
        gbc.gridy++;

        // Username (shown if not hidden and different from display name)
        if (!config.hideLogin())
        {
            String username = profile.getUsername();
            if (username != null && !username.equals(displayName))
            {
                infoPanel.add(AccountCardHelper.createTruncatingLabel(username, Theme.TEXT_SECONDARY,
                    Theme.fontRegular(getFont(), Theme.FONT_SIZE_HEADING), 25), gbc);
                gbc.gridy++;
            }
        }

        // Notes preview
        if (!config.hideNotes())
        {
            AccountMetadata meta = profile.getMetadata();
            if (meta != null && meta.getNotes() != null && !meta.getNotes().isEmpty())
            {
                String notes = meta.getNotes();
                JLabel notesLabel = AccountCardHelper.createTruncatingLabel(notes, Theme.TEXT_SECONDARY,
                    Theme.fontRegular(getFont(), Theme.FONT_SIZE_BODY), 22);
                notesLabel.setToolTipText("<html><body style='width: 200px'>" + AccountCardHelper.escapeHtml(notes) + "</body></html>");
                infoPanel.add(notesLabel, gbc);
            }
        }

        return infoPanel;
    }

    private JPanel createActionButtons()
    {
        JPanel rightPanel = new JPanel();
        rightPanel.setLayout(new BoxLayout(rightPanel, BoxLayout.Y_AXIS));
        rightPanel.setOpaque(false);
        rightPanel.add(createEditButton());
        rightPanel.add(createMenuButton());
        return rightPanel;
    }

    private JButton createEditButton()
    {
        JButton button = new JButton("\u270E");
        button.setBackground(Theme.CARD_BACKGROUND);
        button.setForeground(Theme.TEXT_PRIMARY);
        button.setFocusPainted(false);
        button.setBorderPainted(false);
        button.setPreferredSize(new Dimension(Theme.MENU_BUTTON_SIZE, Theme.MENU_BUTTON_SIZE));
        button.setFont(button.getFont().deriveFont(14f));
        button.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        button.setToolTipText("Edit account");
        button.addActionListener(e -> { if (expansionHandler != null) expansionHandler.toggleExpanded(); });
        button.addMouseListener(new MouseAdapter()
        {
            @Override
            public void mouseEntered(MouseEvent e) { button.setBackground(Theme.CARD_HOVER); }

            @Override
            public void mouseExited(MouseEvent e) { button.setBackground(hovered ? Theme.CARD_HOVER : getBaseBackground()); }
        });
        return button;
    }

    private JButton createMenuButton()
    {
        JButton button = new JButton("\u22EE");
        button.setBackground(Theme.CARD_BACKGROUND);
        button.setForeground(Theme.TEXT_PRIMARY);
        button.setFocusPainted(false);
        button.setBorderPainted(false);
        button.setPreferredSize(new Dimension(Theme.MENU_BUTTON_SIZE, Theme.MENU_BUTTON_SIZE));
        button.setFont(button.getFont().deriveFont(16f));
        button.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        button.setToolTipText("More options");

        Runnable onExpand = () -> { if (expansionHandler != null) expansionHandler.expand(); };
        AccountCardActions actions = new AccountCardActions(plugin, profile, onExpand);
        JPopupMenu menu = actions.createContextMenu();
        button.addActionListener(e -> menu.show(button, 0, button.getHeight()));

        button.addMouseListener(new MouseAdapter()
        {
            @Override
            public void mouseEntered(MouseEvent e) { button.setBackground(Theme.CARD_HOVER); }

            @Override
            public void mouseExited(MouseEvent e) { button.setBackground(hovered ? Theme.CARD_HOVER : getBaseBackground()); }
        });
        return button;
    }

    public boolean isExpanded()
    {
        if (gridEditMode) return true;
        return expansionHandler != null && expansionHandler.isExpanded();
    }

    public void expand()
    {
        if (config.gridView()) expandGridEdit();
        else if (expansionHandler != null) expansionHandler.expand();
    }

    public void collapse()
    {
        if (gridEditMode) collapseGridEdit();
        else if (expansionHandler != null) expansionHandler.collapse();
    }

    private void expandGridEdit()
    {
        if (gridEditMode) return;
        // Collapse any other expanded card first
        if (parentPanel != null)
        {
            parentPanel.collapseExpandedCard();
            parentPanel.setExpandedCard(this);
        }
        gridEditMode = true;

        // Replace grid content with inline edit form
        removeAll();
        setLayout(new BorderLayout(0, 0));
        setBackground(Theme.FORM_BACKGROUND);
        setCursor(Cursor.getDefaultCursor());

        InlineAccountForm editForm = new InlineAccountForm(plugin, profile, true, null);
        editForm.setOnSave(savedAccount -> {
            plugin.getAccountStorage().saveAccount(savedAccount);
            collapseGridEdit();
            plugin.getPanel().rebuild();
        });
        editForm.setOnCancel(this::collapseGridEdit);
        add(editForm, BorderLayout.CENTER);

        // Remove fixed height so the form can size naturally
        setPreferredSize(null);
        setMaximumSize(new Dimension(Integer.MAX_VALUE, Integer.MAX_VALUE));

        editForm.focusUsernameField();
        AccountCardHelper.revalidateToWindow(this);
    }

    private void collapseGridEdit()
    {
        if (!gridEditMode) return;
        gridEditMode = false;
        if (parentPanel != null) parentPanel.setExpandedCard(null);
        // Just rebuild the whole panel — simpler than trying to restore grid card state
        plugin.getPanel().rebuild();
    }

    private void setupMouseListeners()
    {
        if (headerPanel != null)
        {
            headerPanel.addMouseListener(new MouseAdapter()
            {
                @Override
                public void mouseEntered(MouseEvent e) { hovered = true; animateBackground(Theme.CARD_HOVER); }

                @Override
                public void mouseExited(MouseEvent e) { hovered = false; animateBackground(getBaseBackground()); }

                @Override
                public void mouseClicked(MouseEvent e)
                {
                    if (e.getButton() == MouseEvent.BUTTON1 && e.getClickCount() == 1
                        && (expansionHandler == null || !expansionHandler.isExpanded()))
                    {
                        plugin.selectAccount(profile);
                    }
                }
            });
        }

        addMouseListener(new MouseAdapter()
        {
            @Override
            public void mouseEntered(MouseEvent e) { hovered = true; animateBackground(Theme.CARD_HOVER); }

            @Override
            public void mouseExited(MouseEvent e) { hovered = false; animateBackground(getBaseBackground()); }

            @Override
            public void mouseClicked(MouseEvent e)
            {
                if (headerPanel == null && e.getButton() == MouseEvent.BUTTON1)
                {
                    if (e.getClickCount() == 2 && !gridEditMode)
                    {
                        expandGridEdit();
                    }
                    else if (e.getClickCount() == 1 && !gridEditMode)
                    {
                        plugin.selectAccount(profile);
                    }
                }
            }
        });
    }

    private Color getBaseBackground()
    {
        boolean isSelected = profile.getId().equals(plugin.getSelectedAccountId());
        return isSelected ? Theme.CARD_SELECTED : Theme.CARD_BACKGROUND;
    }

    private void animateBackground(Color target)
    {
        currentBackground = target;
        setBackground(target);
        repaint();
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterConfig;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.ui.components.Theme;

import javax.swing.*;
import java.awt.*;

/**
 * Shared utility methods for profile card rendering.
 * Extracted from AccountCardPanel to keep file sizes manageable.
 */
public final class AccountCardHelper
{
    private AccountCardHelper() {} // Prevent instantiation

    /**
     * Creates a small green dot indicating the profile is currently logged in.
     */
    public static JPanel createOnlineDot()
    {
        int size = Theme.ONLINE_DOT_SIZE;
        JPanel dot = new JPanel() {
            @Override
            protected void paintComponent(Graphics g) {
                super.paintComponent(g);
                Graphics2D g2 = (Graphics2D) g.create();
                g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
                g2.setColor(Theme.ONLINE_INDICATOR);
                g2.fillOval(0, 0, size, size);
                g2.dispose();
            }
        };
        dot.setOpaque(false);
        dot.setPreferredSize(new Dimension(size, size));
        dot.setMaximumSize(new Dimension(size, size));
        dot.setToolTipText("Currently logged in");
        return dot;
    }

    /**
     * Creates a JLabel that truncates text beyond maxChars with an ellipsis.
     */
    public static JLabel createTruncatingLabel(String text, Color color, Font font, int maxChars)
    {
        String display = text;
        if (text != null && text.length() > maxChars)
        {
            // Truncate at last space before limit to avoid cutting mid-word
            String trimmed = text.substring(0, maxChars);
            int lastSpace = trimmed.lastIndexOf(' ');
            display = (lastSpace > maxChars / 2) ? trimmed.substring(0, lastSpace) + "..." : trimmed + "...";
        }
        JLabel label = new JLabel(display);
        label.setForeground(color);
        label.setFont(font);
        if (text != null && text.length() > maxChars) label.setToolTipText(text);
        return label;
    }

    /**
     * Escapes HTML special characters for safe display in HTML-rendered labels.
     */
    public static String escapeHtml(String text)
    {
        if (text == null) return "";
        return text.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
            .replace("\"", "&quot;").replace("\n", "<br>");
    }

    /**
     * Forces revalidation up the entire component tree to the window ancestor.
     */
    public static void revalidateToWindow(Component component)
    {
        Container ancestor = component.getParent();
        while (ancestor != null)
        {
            ancestor.revalidate();
            ancestor.repaint();
            ancestor = ancestor.getParent();
        }
        SwingUtilities.invokeLater(() -> {
            Window window = SwingUtilities.getWindowAncestor(component);
            if (window != null)
            {
                window.revalidate();
                window.repaint();
            }
        });
    }

    /**
     * Resolves the display name for a profile based on privacy settings.
     * Used by both AccountCardPanel (list view) and GridAccountBuilder (grid view).
     */
    public static String resolveDisplayName(Account profile, RosterConfig config)
    {
        boolean allHidden = config.hideAlias() && config.hideLogin();
        String displayName;
        if (allHidden)
        {
            displayName = "Account";
        }
        else if (config.hideAlias())
        {
            displayName = profile.getUsername();
        }
        else
        {
            displayName = profile.getDisplayName();
        }
        if (displayName == null) displayName = profile.getUsername();
        return displayName;
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.storage.AccountStorage;
import com.mylosis.roster.ui.components.NotificationToast;
import com.mylosis.roster.ui.components.Theme;
import com.mylosis.roster.ui.dnd.DragDropManager;
import com.mylosis.roster.ui.dnd.DragOverlay;
import lombok.Getter;
import lombok.Setter;
import lombok.extern.slf4j.Slf4j;
import net.runelite.client.ui.PluginPanel;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;

/**
 * Main panel for the Roster plugin.
 * Orchestrates header, form, profile list, footer, and notification components.
 */
@Slf4j
public class RosterPanel extends PluginPanel
{
    private final RosterPlugin plugin;
    private final AccountStorage storage;

    @Getter
    private final DragDropManager dragDropManager;
    private final AccountListBuilder listBuilder;
    @Getter
    private final PanelFormManager formManager;

    private JPanel profileListPanel;
    private JScrollPane scrollPane;
    private final JLayeredPane layeredPane;
    private final DragOverlay dragOverlay;
    private JPanel notificationPanel;
    private JLabel accountCountLabel;

    private String searchFilter = "";

    @Setter
    private AccountCardPanel expandedCard = null;

    public RosterPanel(RosterPlugin plugin)
    {
        this.plugin = plugin;
        this.storage = plugin.getAccountStorage();
        this.dragDropManager = new DragDropManager(plugin, this);
        this.dragOverlay = dragDropManager.getOverlay();
        this.listBuilder = new AccountListBuilder(plugin, this, dragDropManager);
        this.formManager = new PanelFormManager(plugin, this::rebuild, this::doRevalidate);

        setLayout(new BorderLayout());
        setBackground(Theme.BACKGROUND);

        layeredPane = new JLayeredPane();
        layeredPane.setLayout(new OverlayLayout(layeredPane));

        JPanel contentPanel = buildContentPanel();
        layeredPane.add(contentPanel, JLayeredPane.DEFAULT_LAYER);

        notificationPanel = buildNotificationPanel();
        layeredPane.add(notificationPanel, JLayeredPane.POPUP_LAYER);

        layeredPane.addComponentListener(new java.awt.event.ComponentAdapter()
        {
            @Override
            public void componentResized(java.awt.event.ComponentEvent e)
            {
                repositionNotificationPanel();
            }
        });

        dragOverlay.setVisible(false);
        layeredPane.add(dragOverlay, JLayeredPane.DRAG_LAYER);

        add(layeredPane, BorderLayout.CENTER);
        rebuild();
    }

    private JPanel buildContentPanel()
    {
        JPanel contentPanel = new JPanel(new BorderLayout());
        contentPanel.setBackground(Theme.BACKGROUND);
        contentPanel.setBorder(new EmptyBorder(Theme.SPACING_MD, Theme.SPACING_SM, Theme.SPACING_SM, Theme.SPACING_SM));

        // Header with search and action buttons
        PanelHeaderBuilder headerBuilder = new PanelHeaderBuilder();
        JPanel headerPanel = headerBuilder.build(
            filter -> { searchFilter = filter; rebuild(); },
            () -> formManager.toggleAddProfileForm(this::collapseExpandedCardOnly),
            () -> formManager.toggleAddCategoryForm(this::collapseExpandedCardOnly)
        );

        // Attach form panels below action buttons
        JPanel headerWithForms = new JPanel();
        headerWithForms.setLayout(new BoxLayout(headerWithForms, BoxLayout.Y_AXIS));
        headerWithForms.setBackground(Theme.BACKGROUND);
        headerWithForms.add(headerPanel);
        headerWithForms.add(formManager.getAddProfileFormPanel());
        headerWithForms.add(formManager.getAddCategoryFormPanel());

        contentPanel.add(headerWithForms, BorderLayout.NORTH);

        // Scrollable profile list
        profileListPanel = new JPanel();
        profileListPanel.setLayout(new BoxLayout(profileListPanel, BoxLayout.Y_AXIS));
        profileListPanel.setBackground(Theme.BACKGROUND);

        scrollPane = new JScrollPane(profileListPanel);
        scrollPane.setHorizontalScrollBarPolicy(ScrollPaneConstants.HORIZONTAL_SCROLLBAR_NEVER);
        scrollPane.setVerticalScrollBarPolicy(ScrollPaneConstants.VERTICAL_SCROLLBAR_AS_NEEDED);
        scrollPane.setBorder(null);
        scrollPane.getVerticalScrollBar().setUnitIncrement(16);
        scrollPane.setBackground(Theme.BACKGROUND);
        scrollPane.getViewport().setBackground(Theme.BACKGROUND);
        contentPanel.add(scrollPane, BorderLayout.CENTER);

        // Footer with count and actions
        accountCountLabel = new JLabel("0 Accounts");
        accountCountLabel.setForeground(Theme.TEXT_SECONDARY);
        accountCountLabel.setFont(Theme.fontRegular(accountCountLabel.getFont(), Theme.FONT_SIZE_SMALL));

        PanelFooterBuilder footerBuilder = new PanelFooterBuilder(plugin, this::showNotification, this::rebuild);
        contentPanel.add(footerBuilder.build(accountCountLabel), BorderLayout.SOUTH);

        return contentPanel;
    }

    private JPanel buildNotificationPanel()
    {
        JPanel panel = new JPanel(new FlowLayout(FlowLayout.CENTER, 0, 0))
        {
            @Override
            public boolean isOptimizedDrawingEnabled()
            {
                return false;
            }
        };
        panel.setOpaque(false);
        panel.setAlignmentX(0f);
        panel.setAlignmentY(0.5f);
        panel.setMaximumSize(new Dimension(0, 0));
        return panel;
    }

    public void rebuild()
    {
        // Create a fresh panel to avoid stale layout caches from BoxLayout
        JPanel newListPanel = new JPanel();
        newListPanel.setLayout(new BoxLayout(newListPanel, BoxLayout.Y_AXIS));
        newListPanel.setBackground(Theme.BACKGROUND);

        int[] counts = listBuilder.rebuild(newListPanel, searchFilter);
        updateProfileCount(counts[0], counts[1]);

        // Swap the viewport to the fresh panel — forces complete layout recalculation
        profileListPanel = newListPanel;
        scrollPane.setViewportView(profileListPanel);
        scrollPane.getVerticalScrollBar().setValue(0);

        // Force immediate repaint up the entire component tree —
        // without this, Swing defers the repaint until a window focus event
        SwingUtilities.invokeLater(() -> {
            Window window = SwingUtilities.getWindowAncestor(this);
            if (window != null)
            {
                window.revalidate();
                window.repaint();
            }
        });
    }

    private void updateProfileCount(int filtered, int total)
    {
        if (filtered == total)
        {
            accountCountLabel.setText(total + " Account" + (total != 1 ? "s" : ""));
        }
        else
        {
            accountCountLabel.setText(filtered + " / " + total + " Accounts");
        }
    }

    /**
     * Collapse any currently expanded profile card and hide add form.
     */
    public void collapseExpandedCard()
    {
        collapseExpandedCardOnly();
        formManager.hideAddForm();
    }

    private void collapseExpandedCardOnly()
    {
        if (expandedCard != null)
        {
            expandedCard.collapse();
            expandedCard = null;
        }
    }

    public void showNotification(String message, NotificationToast.Type type)
    {
        NotificationToast toast = new NotificationToast(message, type, 3000);
        notificationPanel.removeAll();
        notificationPanel.add(toast);
        notificationPanel.revalidate();
        SwingUtilities.invokeLater(this::repositionNotificationPanel);
    }

    private void repositionNotificationPanel()
    {
        if (notificationPanel.getComponentCount() == 0)
        {
            notificationPanel.setBounds(0, 0, 0, 0);
            return;
        }

        int panelWidth = layeredPane.getWidth();
        int panelHeight = layeredPane.getHeight();
        notificationPanel.setSize(panelWidth, 100);
        notificationPanel.doLayout();
        Dimension pref = notificationPanel.getPreferredSize();
        int y = panelHeight - pref.height - 50;
        notificationPanel.setBounds(0, y, panelWidth, pref.height + 20);
        notificationPanel.repaint();
    }

    private void doRevalidate()
    {
        revalidate();
        repaint();
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.storage.AccountStorage;
import com.mylosis.roster.ui.components.InlineAccountForm;
import com.mylosis.roster.ui.components.Theme;
import lombok.extern.slf4j.Slf4j;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;

/**
 * Manages the inline add-profile and add-category forms.
 */
@Slf4j
public class PanelFormManager
{
    private final RosterPlugin plugin;
    private final AccountStorage storage;
    private final Runnable onRebuild;
    private final Runnable onRevalidate;

    private JPanel addAccountFormPanel;
    private InlineAccountForm addAccountForm;
    private boolean addFormVisible = false;

    private JPanel addCategoryFormPanel;
    private JTextField categoryNameField;
    private boolean addCategoryFormVisible = false;

    public PanelFormManager(RosterPlugin plugin, Runnable onRebuild, Runnable onRevalidate)
    {
        this.plugin = plugin;
        this.storage = plugin.getAccountStorage();
        this.onRebuild = onRebuild;
        this.onRevalidate = onRevalidate;
    }

    public JPanel getAddProfileFormPanel()
    {
        if (addAccountFormPanel == null)
        {
            addAccountFormPanel = buildAddProfileFormPanel();
        }
        return addAccountFormPanel;
    }

    public JPanel getAddCategoryFormPanel()
    {
        if (addCategoryFormPanel == null)
        {
            addCategoryFormPanel = buildAddCategoryFormPanel();
        }
        return addCategoryFormPanel;
    }

    public boolean isAddFormVisible()
    {
        return addFormVisible;
    }

    public void hideAddForm()
    {
        if (addFormVisible)
        {
            addAccountFormPanel.setVisible(false);
            addFormVisible = false;
        }
    }

    public void toggleAddProfileForm(Runnable collapseExpandedCard)
    {
        if (addAccountFormPanel == null)
        {
            log.error("addAccountFormPanel is null!");
            return;
        }

        if (addCategoryFormVisible)
        {
            addCategoryFormPanel.setVisible(false);
            addCategoryFormVisible = false;
        }

        if (!addFormVisible)
        {
            collapseExpandedCard.run();
        }

        addFormVisible = !addFormVisible;
        addAccountFormPanel.setVisible(addFormVisible);

        if (addFormVisible)
        {
            SwingUtilities.invokeLater(() -> {
                if (addAccountForm != null)
                {
                    addAccountForm.focusUsernameField();
                }
            });
        }

        onRevalidate.run();
    }

    public void toggleAddCategoryForm(Runnable collapseExpandedCard)
    {
        if (addFormVisible)
        {
            addAccountFormPanel.setVisible(false);
            addFormVisible = false;
        }

        collapseExpandedCard.run();

        addCategoryFormVisible = !addCategoryFormVisible;
        addCategoryFormPanel.setVisible(addCategoryFormVisible);

        if (addCategoryFormVisible)
        {
            categoryNameField.setText("");
            SwingUtilities.invokeLater(() -> categoryNameField.requestFocusInWindow());
        }

        onRevalidate.run();
    }

    private JPanel buildAddProfileFormPanel()
    {
        JPanel panel = new JPanel(new BorderLayout());
        panel.setBackground(Theme.FORM_BACKGROUND);
        panel.setBorder(BorderFactory.createCompoundBorder(
            new EmptyBorder(Theme.SPACING_SM, 0, 0, 0),
            BorderFactory.createLineBorder(Theme.CARD_BORDER, 1)
        ));
        panel.setMaximumSize(new Dimension(Integer.MAX_VALUE, 170));
        panel.setPreferredSize(new Dimension(200, 170));
        panel.setAlignmentX(Component.LEFT_ALIGNMENT);
        panel.setVisible(false);

        addAccountForm = new InlineAccountForm(plugin, null, true, null);
        addAccountForm.setOnSave(profile -> {
            storage.saveAccount(profile);
            addAccountForm.clearFields();
            panel.setVisible(false);
            addFormVisible = false;
            onRebuild.run();
        });
        addAccountForm.setOnCancel(() -> {
            addAccountForm.clearFields();
            panel.setVisible(false);
            addFormVisible = false;
            onRevalidate.run();
        });

        panel.add(addAccountForm, BorderLayout.CENTER);
        return panel;
    }

    private JPanel buildAddCategoryFormPanel()
    {
        JPanel panel = new JPanel(new BorderLayout());
        panel.setBackground(Theme.FORM_BACKGROUND);
        panel.setBorder(BorderFactory.createCompoundBorder(
            new EmptyBorder(Theme.SPACING_SM, 0, 0, 0),
            BorderFactory.createLineBorder(Theme.CARD_BORDER, 1)
        ));
        panel.setMaximumSize(new Dimension(Integer.MAX_VALUE, 70));
        panel.setPreferredSize(new Dimension(200, 70));
        panel.setAlignmentX(Component.LEFT_ALIGNMENT);
        panel.setVisible(false);

        JPanel innerPanel = new JPanel();
        innerPanel.setLayout(new BoxLayout(innerPanel, BoxLayout.Y_AXIS));
        innerPanel.setBackground(Theme.FORM_BACKGROUND);
        innerPanel.setBorder(new EmptyBorder(Theme.SPACING_SM, Theme.SPACING_SM, Theme.SPACING_SM, Theme.SPACING_SM));

        innerPanel.add(buildCategoryNameRow());
        innerPanel.add(Box.createVerticalStrut(Theme.SPACING_SM));
        innerPanel.add(buildCategoryButtonRow());

        panel.add(innerPanel, BorderLayout.CENTER);

        categoryNameField.getInputMap().put(KeyStroke.getKeyStroke("ESCAPE"), "cancel");
        categoryNameField.getActionMap().put("cancel", new AbstractAction()
        {
            @Override
            public void actionPerformed(java.awt.event.ActionEvent e)
            {
                cancelCategoryForm();
            }
        });

        return panel;
    }

    private JPanel buildCategoryNameRow()
    {
        JPanel nameRow = new JPanel(new BorderLayout(Theme.SPACING_XS, 0));
        nameRow.setOpaque(false);
        nameRow.setMaximumSize(new Dimension(Integer.MAX_VALUE, Theme.BUTTON_HEIGHT));
        nameRow.setAlignmentX(Component.LEFT_ALIGNMENT);

        JLabel nameLabel = new JLabel("Name");
        nameLabel.setForeground(Theme.TEXT_SECONDARY);
        nameLabel.setFont(Theme.fontRegular(nameLabel.getFont(), Theme.FONT_SIZE_SMALL));
        nameLabel.setPreferredSize(new Dimension(55, Theme.BUTTON_HEIGHT));
        nameRow.add(nameLabel, BorderLayout.WEST);

        categoryNameField = new JTextField();
        categoryNameField.setBackground(Theme.BACKGROUND_DARKER);
        categoryNameField.setForeground(Theme.TEXT_PRIMARY);
        categoryNameField.setCaretColor(Theme.TEXT_PRIMARY);
        categoryNameField.setBorder(BorderFactory.createCompoundBorder(
            BorderFactory.createLineBorder(Theme.CARD_BORDER),
            new EmptyBorder(Theme.SPACING_XS, Theme.SPACING_SM, Theme.SPACING_XS, Theme.SPACING_SM)
        ));
        categoryNameField.setFont(Theme.fontRegular(categoryNameField.getFont(), Theme.FONT_SIZE_BODY));
        categoryNameField.addActionListener(e -> saveCategoryForm());
        nameRow.add(categoryNameField, BorderLayout.CENTER);

        return nameRow;
    }

    private JPanel buildCategoryButtonRow()
    {
        JPanel buttonPanel = new JPanel(new GridLayout(1, 2, Theme.SPACING_XS, 0));
        buttonPanel.setOpaque(false);
        buttonPanel.setMaximumSize(new Dimension(Integer.MAX_VALUE, Theme.BUTTON_HEIGHT_SM));
        buttonPanel.setAlignmentX(Component.LEFT_ALIGNMENT);

        JButton cancelButton = new JButton("Cancel");
        cancelButton.setBackground(Theme.BUTTON_SECONDARY);
        cancelButton.setForeground(Theme.TEXT_PRIMARY);
        cancelButton.setFocusPainted(false);
        cancelButton.setBorderPainted(false);
        cancelButton.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        cancelButton.setFont(Theme.fontRegular(cancelButton.getFont(), Theme.FONT_SIZE_HEADING));
        cancelButton.addActionListener(e -> cancelCategoryForm());
        buttonPanel.add(cancelButton);

        JButton saveButton = new JButton("Save");
        saveButton.setBackground(Theme.BUTTON_PRIMARY);
        saveButton.setForeground(Theme.TEXT_PRIMARY);
        saveButton.setFocusPainted(false);
        saveButton.setBorderPainted(false);
        saveButton.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        saveButton.setFont(Theme.fontRegular(saveButton.getFont(), Theme.FONT_SIZE_HEADING));
        saveButton.addActionListener(e -> saveCategoryForm());
        buttonPanel.add(saveButton);

        return buttonPanel;
    }

    private void saveCategoryForm()
    {
        String name = categoryNameField.getText().trim();
        if (!name.isEmpty())
        {
            ProfileGroup group = ProfileGroup.createNew(name);
            // Auto-assign a default color based on existing category count
            int existingCount = storage.getGroups().size();
            Color[] palette = Theme.DEFAULT_CATEGORY_COLORS;
            if (existingCount < palette.length)
            {
                Color c = palette[existingCount];
                group.setColor(String.format("#%02X%02X%02X", c.getRed(), c.getGreen(), c.getBlue()));
            }
            storage.saveGroup(group);
            categoryNameField.setText("");
            addCategoryFormPanel.setVisible(false);
            addCategoryFormVisible = false;
            onRebuild.run();
        }
    }

    private void cancelCategoryForm()
    {
        categoryNameField.setText("");
        addCategoryFormPanel.setVisible(false);
        addCategoryFormVisible = false;
        onRevalidate.run();
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.ui.components.Theme;

import javax.swing.*;
import java.awt.*;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;

/**
 * Builds the compact grid card layout for AccountCardPanel when grid view is enabled.
 * Text layout with a small 3-dot menu button in the top-right corner.
 */
public class GridAccountBuilder
{
    private GridAccountBuilder() {}

    public static final int GRID_CARD_HEIGHT = 56;

    public static void build(JPanel card, RosterPlugin plugin, Account profile, Runnable onEdit)
    {
        card.setLayout(new BorderLayout(0, 0));

        // Centered text with overlaid menu button in top-right
        JPanel content = new JPanel(new GridBagLayout());
        content.setOpaque(false);

        JPanel inner = new JPanel();
        inner.setLayout(new BoxLayout(inner, BoxLayout.Y_AXIS));
        inner.setOpaque(false);

        String displayName = AccountCardHelper.resolveDisplayName(profile, plugin.getConfig());

        JLabel nameLabel = new JLabel(truncate(displayName, 14));
        nameLabel.setForeground(Theme.TEXT_PRIMARY);
        nameLabel.setFont(Theme.fontBold(card.getFont(), Theme.FONT_SIZE_BODY));
        nameLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
        nameLabel.setHorizontalAlignment(SwingConstants.CENTER);
        if (displayName.length() > 14) nameLabel.setToolTipText(displayName);
        inner.add(nameLabel);

        String subtitle = getSubtitle(plugin, profile);
        if (subtitle != null)
        {
            inner.add(Box.createVerticalStrut(1));
            JLabel subLabel = new JLabel(truncate(subtitle, 14));
            subLabel.setForeground(Theme.TEXT_SECONDARY);
            subLabel.setFont(Theme.fontRegular(card.getFont(), Theme.FONT_SIZE_SMALL));
            subLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
            subLabel.setHorizontalAlignment(SwingConstants.CENTER);
            if (subtitle.length() > 14) subLabel.setToolTipText(subtitle);
            inner.add(subLabel);
        }

        content.add(inner);
        card.add(content, BorderLayout.CENTER);

        // 3-dot menu button on right, with matching spacer on left to keep text centered
        int btnSize = 16;
        JButton menuBtn = new JButton("\u22EE");
        menuBtn.setBackground(Theme.CARD_BACKGROUND);
        menuBtn.setForeground(Theme.TEXT_SECONDARY);
        menuBtn.setFocusPainted(false);
        menuBtn.setBorderPainted(false);
        menuBtn.setPreferredSize(new Dimension(btnSize, btnSize));
        menuBtn.setFont(menuBtn.getFont().deriveFont(12f));
        menuBtn.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        menuBtn.setToolTipText("More options");

        AccountCardActions actions = new AccountCardActions(plugin, profile, onEdit);
        JPopupMenu menu = actions.createContextMenu();
        menuBtn.addActionListener(e -> menu.show(menuBtn, 0, menuBtn.getHeight()));
        menuBtn.addMouseListener(new MouseAdapter()
        {
            @Override
            public void mouseEntered(MouseEvent e) { menuBtn.setBackground(Theme.CARD_HOVER); }

            @Override
            public void mouseExited(MouseEvent e) { menuBtn.setBackground(Theme.CARD_BACKGROUND); }
        });

        JPanel btnPanel = new JPanel(new GridBagLayout());
        btnPanel.setOpaque(false);
        btnPanel.setPreferredSize(new Dimension(btnSize + 4, 0));
        btnPanel.add(menuBtn);
        card.add(btnPanel, BorderLayout.EAST);

        // Matching spacer on left to balance the button width
        JPanel spacer = new JPanel();
        spacer.setOpaque(false);
        spacer.setPreferredSize(new Dimension(btnSize + 4, 0));
        card.add(spacer, BorderLayout.WEST);
    }

    private static String getSubtitle(RosterPlugin plugin, Account profile)
    {
        boolean hideNotes = plugin.getConfig().hideNotes();
        boolean hideLogin = plugin.getConfig().hideLogin();
        boolean hideAlias = plugin.getConfig().hideAlias();

        if (!hideNotes && profile.getMetadata() != null && profile.getMetadata().getNotes() != null
            && !profile.getMetadata().getNotes().isEmpty())
        {
            return profile.getMetadata().getNotes();
        }
        if (!hideLogin && !hideAlias && profile.getUsername() != null
            && !profile.getUsername().equals(profile.getAlias()))
        {
            return profile.getUsername();
        }
        return null;
    }

    private static String truncate(String text, int maxChars)
    {
        if (text == null) return "";
        return text.length() > maxChars ? text.substring(0, maxChars) + "..." : text;
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.AccountData;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.storage.AccountStorage;
import com.mylosis.roster.ui.components.Icons;
import com.mylosis.roster.ui.components.Theme;
import com.mylosis.roster.ui.dnd.DragDropManager;
import com.mylosis.roster.ui.dnd.AccountDragListener;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;
import java.util.ArrayList;
import java.util.List;

/**
 * Builds the scrollable profile list content.
 * Handles filtering, grouping, and empty state rendering.
 */
public class AccountListBuilder
{
    private final RosterPlugin plugin;
    private final AccountStorage storage;
    private final RosterPanel parentPanel;
    private final DragDropManager dragDropManager;

    public AccountListBuilder(RosterPlugin plugin, RosterPanel parentPanel,
                              DragDropManager dragDropManager)
    {
        this.plugin = plugin;
        this.storage = plugin.getAccountStorage();
        this.parentPanel = parentPanel;
        this.dragDropManager = dragDropManager;
    }

    /**
     * Rebuild the profile list into the target panel.
     * Returns the count of filtered profiles for the footer label.
     */
    public int[] rebuild(JPanel targetPanel, String searchFilter)
    {
        targetPanel.removeAll();

        List<Account> allProfiles = storage.getAccounts();
        List<Account> filteredProfiles = filterProfiles(allProfiles, searchFilter);
        List<ProfileGroup> sortedGroups = getSortedGroups();
        List<String> addedProfileIds = new ArrayList<>();

        buildGroupedProfiles(targetPanel, filteredProfiles, sortedGroups, addedProfileIds, searchFilter);
        buildUngroupedProfiles(targetPanel, filteredProfiles, sortedGroups, addedProfileIds);

        if (filteredProfiles.isEmpty() && sortedGroups.isEmpty())
        {
            targetPanel.add(createEmptyStatePanel(searchFilter));
        }

        targetPanel.revalidate();
        targetPanel.repaint();

        return new int[]{filteredProfiles.size(), allProfiles.size()};
    }

    private List<ProfileGroup> getSortedGroups()
    {
        List<ProfileGroup> groups = new ArrayList<>(storage.getGroups());
        groups.sort((a, b) -> Integer.compare(a.getSortOrder(), b.getSortOrder()));
        return groups;
    }

    private void buildGroupedProfiles(JPanel target, List<Account> filteredProfiles,
                                      List<ProfileGroup> groups, List<String> addedProfileIds,
                                      String searchFilter)
    {
        for (ProfileGroup group : groups)
        {
            List<Account> groupProfiles = new ArrayList<>();
            for (Account profile : filteredProfiles)
            {
                if (group.getId().equals(profile.getGroupId()))
                {
                    groupProfiles.add(profile);
                    addedProfileIds.add(profile.getId());
                }
            }

            sortBySortOrder(groupProfiles);

            if (!groupProfiles.isEmpty() || searchFilter.isEmpty())
            {
                CategoryPanel categoryPanel = new CategoryPanel(plugin, group, groupProfiles, dragDropManager);
                target.add(categoryPanel);
                target.add(Box.createVerticalStrut(Theme.SPACING_LG));
            }
        }
    }

    private void buildUngroupedProfiles(JPanel target, List<Account> filteredProfiles,
                                        List<ProfileGroup> groups, List<String> addedProfileIds)
    {
        List<Account> ungrouped = new ArrayList<>();
        for (Account profile : filteredProfiles)
        {
            if (!addedProfileIds.contains(profile.getId()))
            {
                ungrouped.add(profile);
            }
        }

        if (ungrouped.isEmpty() && groups.isEmpty())
        {
            return;
        }

        sortBySortOrder(ungrouped);

        if (!groups.isEmpty())
        {
            target.add(createUncategorizedHeader());
            target.add(Box.createVerticalStrut(Theme.SPACING_SM));
        }

        if (!ungrouped.isEmpty())
        {
            boolean gridMode = plugin.getConfig().gridView();

            if (gridMode)
            {
                int cols = 2;
                JPanel gridPanel = new JPanel(new GridLayout(0, cols, Theme.SPACING_XS, Theme.SPACING_XS));
                gridPanel.setBackground(Theme.BACKGROUND);
                for (Account profile : ungrouped)
                {
                    AccountCardPanel card = new AccountCardPanel(plugin, profile, parentPanel);
                    AccountDragListener dragListener = new AccountDragListener(dragDropManager, profile, card);
                    dragListener.attachToComponent(card);
                    gridPanel.add(card);
                }
                JPanel wrapper = new JPanel(new BorderLayout());
                wrapper.setBackground(Theme.BACKGROUND);
                wrapper.add(gridPanel, BorderLayout.NORTH);
                target.add(wrapper);
            }
            else
            {
                JPanel ungroupedPanel = new JPanel();
                ungroupedPanel.setLayout(new BoxLayout(ungroupedPanel, BoxLayout.Y_AXIS));
                ungroupedPanel.setBackground(Theme.BACKGROUND);
                for (Account profile : ungrouped)
                {
                    AccountCardPanel card = new AccountCardPanel(plugin, profile, parentPanel);
                    AccountDragListener dragListener = new AccountDragListener(dragDropManager, profile, card);
                    dragListener.attachToComponent(card);
                    ungroupedPanel.add(card);
                    ungroupedPanel.add(Box.createVerticalStrut(Theme.SPACING_XS));
                }
                target.add(ungroupedPanel);
            }

            target.add(Box.createVerticalStrut(Theme.SPACING_SM));
        }
    }

    private void sortBySortOrder(List<Account> profiles)
    {
        profiles.sort(AccountData.SORT_ORDER_COMPARATOR);
    }

    private List<Account> filterProfiles(List<Account> profiles, String searchFilter)
    {
        if (searchFilter.isEmpty())
        {
            return new ArrayList<>(profiles);
        }

        List<Account> filtered = new ArrayList<>();
        for (Account profile : profiles)
        {
            String alias = profile.getAlias() != null ? profile.getAlias().toLowerCase() : "";
            String username = profile.getUsername() != null ? profile.getUsername().toLowerCase() : "";
            String notes = profile.getMetadata() != null && profile.getMetadata().getNotes() != null
                ? profile.getMetadata().getNotes().toLowerCase() : "";

            if (alias.contains(searchFilter) || username.contains(searchFilter) || notes.contains(searchFilter))
            {
                filtered.add(profile);
            }
        }
        return filtered;
    }

    private JPanel createEmptyStatePanel(String searchFilter)
    {
        JPanel panel = new JPanel();
        panel.setLayout(new BoxLayout(panel, BoxLayout.Y_AXIS));
        panel.setBackground(Theme.BACKGROUND);
        panel.setBorder(new EmptyBorder(40, Theme.SPACING_LG, 40, Theme.SPACING_LG));

        JLabel iconLabel = new JLabel(Icons.get(Icons.USER, 48));
        iconLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
        panel.add(iconLabel);
        panel.add(Box.createVerticalStrut(Theme.SPACING_LG));

        String messageText = searchFilter.isEmpty() ? "No accounts yet" : "No matching accounts";
        JLabel message = new JLabel(messageText);
        message.setForeground(Theme.TEXT_SECONDARY);
        message.setFont(Theme.fontRegular(message.getFont(), Theme.FONT_SIZE_HEADING));
        message.setAlignmentX(Component.CENTER_ALIGNMENT);
        panel.add(message);

        if (searchFilter.isEmpty())
        {
            panel.add(Box.createVerticalStrut(Theme.SPACING_SM));
            JLabel hint = new JLabel("Click + to add your first account");
            hint.setForeground(Theme.TEXT_SECONDARY);
            hint.setFont(Theme.fontRegular(hint.getFont(), Theme.FONT_SIZE_BODY));
            hint.setAlignmentX(Component.CENTER_ALIGNMENT);
            panel.add(hint);
        }

        return panel;
    }

    private JPanel createUncategorizedHeader()
    {
        JPanel header = new JPanel(new BorderLayout(Theme.SPACING_MD, 0));
        header.setBackground(Theme.GROUP_HEADER);
        header.setBorder(BorderFactory.createCompoundBorder(
            BorderFactory.createMatteBorder(0, 0, 1, 0, Theme.CARD_BORDER),
            new EmptyBorder(Theme.SPACING_SM, Theme.SPACING_MD, Theme.SPACING_SM, Theme.SPACING_MD)
        ));

        header.putClientProperty("UNCATEGORIZED_HEADER", Boolean.TRUE);

        JLabel label = new JLabel("Uncategorized");
        label.setForeground(Theme.TEXT_SECONDARY);
        label.setFont(Theme.fontBold(label.getFont(), Theme.FONT_SIZE_BODY));
        header.add(label, BorderLayout.CENTER);

        // Add profile button (matches category + button style)
        JButton addButton = new JButton("+");
        addButton.setBackground(Theme.GROUP_HEADER);
        addButton.setForeground(Theme.TEXT_SECONDARY);
        addButton.setFocusPainted(false);
        addButton.setBorderPainted(false);
        addButton.setPreferredSize(new Dimension(28, Theme.BUTTON_HEIGHT_SM));
        addButton.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        addButton.setToolTipText("Add account");
        addButton.setFont(addButton.getFont().deriveFont(Font.BOLD, 18f));
        addButton.addActionListener(e ->
            parentPanel.getFormManager().toggleAddProfileForm(
                parentPanel::collapseExpandedCard));
        addButton.addMouseListener(new java.awt.event.MouseAdapter()
        {
            @Override
            public void mouseEntered(java.awt.event.MouseEvent e) { addButton.setBackground(Theme.GROUP_HEADER_HOVER); }

            @Override
            public void mouseExited(java.awt.event.MouseEvent e) { addButton.setBackground(Theme.GROUP_HEADER); }
        });
        header.add(addButton, BorderLayout.EAST);

        return header;
    }
}

package com.mylosis.roster.ui;

import com.google.gson.Gson;
import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.AccountData;
import com.mylosis.roster.ui.components.NotificationToast;
import com.mylosis.roster.ui.components.Theme;

import javax.swing.*;
import java.awt.*;
import java.awt.datatransfer.StringSelection;

/**
 * Handles context menu actions for an account card:
 * edit, copy username, move to category, and delete.
 */
public class AccountCardActions
{
    private final RosterPlugin plugin;
    private final Account profile;
    private final Runnable onExpand;

    public AccountCardActions(RosterPlugin plugin, Account profile, Runnable onExpand)
    {
        this.plugin = plugin;
        this.profile = profile;
        this.onExpand = onExpand;
    }

    public JPopupMenu createContextMenu()
    {
        JPopupMenu menu = new JPopupMenu();

        JMenuItem editItem = new JMenuItem("Edit");
        editItem.addActionListener(e -> onExpand.run());
        menu.add(editItem);

        JMenuItem copyUsernameItem = new JMenuItem("Copy Username");
        copyUsernameItem.addActionListener(e -> copyToClipboard(profile.getUsername()));
        menu.add(copyUsernameItem);

        JMenuItem exportItem = new JMenuItem("Export to Clipboard");
        exportItem.addActionListener(e -> exportProfile());
        menu.add(exportItem);

        menu.addSeparator();

        JMenuItem moveToCategoryItem = new JMenuItem("Move to Category...");
        moveToCategoryItem.addActionListener(e -> showMoveToCategoryDialog());
        menu.add(moveToCategoryItem);

        menu.addSeparator();

        JMenuItem deleteItem = new JMenuItem("Delete");
        deleteItem.setForeground(Theme.BUTTON_DANGER);
        deleteItem.addActionListener(e -> confirmDelete());
        menu.add(deleteItem);

        return menu;
    }

    private void showMoveToCategoryDialog()
    {
        var groups = plugin.getAccountStorage().getGroups();

        String[] categoryNames = new String[groups.size() + 1];
        String[] categoryIds = new String[groups.size() + 1];

        categoryNames[0] = "Uncategorized";
        categoryIds[0] = null;

        for (int i = 0; i < groups.size(); i++)
        {
            categoryNames[i + 1] = groups.get(i).getName();
            categoryIds[i + 1] = groups.get(i).getId();
        }

        String selected = (String) JOptionPane.showInputDialog(
            SwingUtilities.getWindowAncestor(plugin.getPanel()),
            "Select category:",
            "Move to Category",
            JOptionPane.PLAIN_MESSAGE,
            null,
            categoryNames,
            categoryNames[0]
        );

        if (selected != null)
        {
            int index = java.util.Arrays.asList(categoryNames).indexOf(selected);
            profile.setGroupId(categoryIds[index]);
            plugin.getAccountStorage().saveAccount(profile);
            plugin.getPanel().rebuild();
        }
    }

    private void confirmDelete()
    {
        if (plugin.getConfig().confirmDelete())
        {
            int result = JOptionPane.showConfirmDialog(
                SwingUtilities.getWindowAncestor(plugin.getPanel()),
                "Are you sure you want to delete \"" + profile.getDisplayName() + "\"?",
                "Confirm Delete",
                JOptionPane.YES_NO_OPTION,
                JOptionPane.WARNING_MESSAGE
            );

            if (result != JOptionPane.YES_OPTION)
            {
                return;
            }
        }

        plugin.getAccountStorage().deleteProfile(profile.getId());
        plugin.getPanel().rebuild();
    }

    private void exportProfile()
    {
        Gson gson = plugin.getGson().newBuilder().setPrettyPrinting().create();
        // Wrap single profile in AccountData envelope for consistent import format
        AccountData wrapper = AccountData.builder()
            .version(AccountData.CURRENT_VERSION)
            .accounts(java.util.Collections.singletonList(profile))
            .groups(new java.util.ArrayList<>())
            .build();
        String json = gson.toJson(wrapper);
        copyToClipboard(json);
        if (plugin.getPanel() != null)
        {
            plugin.getPanel().showNotification("Exported " + profile.getDisplayName(), NotificationToast.Type.SUCCESS);
        }
    }

    private void copyToClipboard(String text)
    {
        if (text != null)
        {
            Toolkit.getDefaultToolkit()
                .getSystemClipboard()
                .setContents(new StringSelection(text), null);
        }
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.ui.components.InlineAccountForm;
import com.mylosis.roster.ui.components.Theme;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;

/**
 * Handles the inline add-profile form within a CategoryPanel.
 * Also handles category rename and delete actions.
 */
public class CategoryFormHandler
{
    private final RosterPlugin plugin;
    private final ProfileGroup group;
    private final Runnable onToggleCollapsed;

    private JPanel addFormPanel;
    private InlineAccountForm addForm;
    private boolean addFormVisible = false;

    public CategoryFormHandler(RosterPlugin plugin, ProfileGroup group, Runnable onToggleCollapsed)
    {
        this.plugin = plugin;
        this.group = group;
        this.onToggleCollapsed = onToggleCollapsed;
    }

    public JPanel getOrCreateFormPanel()
    {
        if (addFormPanel == null)
        {
            addFormPanel = buildFormPanel();
        }
        return addFormPanel;
    }

    public void toggleAddForm(boolean isCollapsed, Component parent)
    {
        addFormVisible = !addFormVisible;
        addFormPanel.setVisible(addFormVisible);

        if (addFormVisible)
        {
            if (isCollapsed) onToggleCollapsed.run();
            addForm.focusUsernameField();
        }

        parent.revalidate();
        ((JComponent) parent).repaint();
    }

    public JPopupMenu createContextMenu()
    {
        JPopupMenu menu = new JPopupMenu();

        JMenuItem renameItem = new JMenuItem("Rename");
        renameItem.addActionListener(e -> renameCategory());
        menu.add(renameItem);

        JMenuItem addAccountItem = new JMenuItem("Add Account");
        addAccountItem.addActionListener(e ->
            toggleAddForm(false, plugin.getPanel()));
        menu.add(addAccountItem);

        menu.addSeparator();
        JMenu colorMenu = new JMenu("Set Color");
            for (int i = 0; i < Theme.CATEGORY_COLORS.length; i++)
            {
                JMenuItem swatch = createColorSwatch(Theme.CATEGORY_COLORS[i], Theme.CATEGORY_COLOR_NAMES[i]);
                colorMenu.add(swatch);
            }
            colorMenu.addSeparator();
            JMenuItem customColor = new JMenuItem("Custom...");
            customColor.addActionListener(e ->
            {
                Color current = Theme.parseColor(group.getColor());
                net.runelite.client.ui.components.colorpicker.RuneliteColorPicker picker =
                    plugin.getColorPickerManager().create(
                        SwingUtilities.getWindowAncestor(plugin.getPanel()),
                        current != null ? current : Theme.ACCENT_ORANGE,
                        group.getName() + " Color",
                        true // hide alpha slider
                    );
                picker.setOnClose(chosen -> {
                    group.setColor(Theme.colorToHex(chosen));
                    plugin.getAccountStorage().saveGroup(group);
                    plugin.getPanel().rebuild();
                });
                picker.setVisible(true);
            });
            colorMenu.add(customColor);
            JMenuItem resetColor = new JMenuItem("Reset Color");
            resetColor.addActionListener(e -> {
                group.setColor(null);
                plugin.getAccountStorage().saveGroup(group);
                plugin.getPanel().rebuild();
            });
            colorMenu.add(resetColor);
        menu.add(colorMenu);

        menu.addSeparator();

        JMenuItem deleteItem = new JMenuItem("Delete Category");
        deleteItem.setForeground(Theme.BUTTON_DANGER);
        deleteItem.addActionListener(e -> confirmDelete());
        menu.add(deleteItem);

        return menu;
    }

    private JMenuItem createColorSwatch(Color color, String name)
    {
        // Create a small colored icon for the menu item
        ImageIcon icon = new ImageIcon(new java.awt.image.BufferedImage(12, 12, java.awt.image.BufferedImage.TYPE_INT_ARGB))
        {
            @Override
            public void paintIcon(Component c, Graphics g, int x, int y)
            {
                g.setColor(color);
                g.fillRect(x, y, 12, 12);
                g.setColor(Theme.CARD_BORDER);
                g.drawRect(x, y, 11, 11);
            }

            @Override
            public int getIconWidth() { return 12; }

            @Override
            public int getIconHeight() { return 12; }
        };

        JMenuItem item = new JMenuItem(name, icon);
        item.addActionListener(e -> {
            group.setColor(Theme.colorToHex(color));
            plugin.getAccountStorage().saveGroup(group);
            plugin.getPanel().rebuild();
        });
        return item;
    }

    private JPanel buildFormPanel()
    {
        JPanel panel = new JPanel(new BorderLayout());
        panel.setBackground(Theme.FORM_BACKGROUND);
        panel.setBorder(BorderFactory.createCompoundBorder(
            BorderFactory.createLineBorder(Theme.CARD_BORDER, 1),
            new EmptyBorder(0, 0, 0, 0)
        ));
        panel.setMaximumSize(new Dimension(Integer.MAX_VALUE, 180));
        panel.setVisible(false);

        addForm = new InlineAccountForm(plugin, null, false, group.getId());
        addForm.setOnSave(profile -> {
            plugin.getAccountStorage().saveAccount(profile);
            addForm.clearFields();
            addFormPanel.setVisible(false);
            addFormVisible = false;
            plugin.getPanel().rebuild();
        });
        addForm.setOnCancel(() -> {
            addForm.clearFields();
            addFormPanel.setVisible(false);
            addFormVisible = false;
        });

        panel.add(addForm, BorderLayout.CENTER);
        return panel;
    }

    private void renameCategory()
    {
        String newName = JOptionPane.showInputDialog(
            SwingUtilities.getWindowAncestor(plugin.getPanel()),
            "Enter new category name:",
            group.getName()
        );
        if (newName != null && !newName.trim().isEmpty())
        {
            group.setName(newName.trim());
            plugin.getAccountStorage().saveGroup(group);
            plugin.getPanel().rebuild();
        }
    }

    private void confirmDelete()
    {
        int result = JOptionPane.showConfirmDialog(
            SwingUtilities.getWindowAncestor(plugin.getPanel()),
            "Delete category \"" + group.getName() + "\"?\n" +
                "Accounts in this category will be moved to Uncategorized.",
            "Confirm Delete",
            JOptionPane.YES_NO_OPTION,
            JOptionPane.WARNING_MESSAGE
        );
        if (result == JOptionPane.YES_OPTION)
        {
            plugin.getAccountStorage().deleteGroup(group.getId());
            plugin.getPanel().rebuild();
        }
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterConfig;
import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.ImportDuplicateMode;
import com.mylosis.roster.storage.ExportResult;
import com.mylosis.roster.storage.ImportExportService;
import com.mylosis.roster.storage.ImportResult;
import com.mylosis.roster.storage.AccountStorage;
import com.mylosis.roster.ui.components.ExpandingMenuButton;
import com.mylosis.roster.ui.components.IconButton;
import com.mylosis.roster.ui.components.Icons;
import com.mylosis.roster.ui.components.NotificationToast;
import com.mylosis.roster.ui.components.Theme;
import lombok.extern.slf4j.Slf4j;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;
import java.util.function.BiConsumer;

/**
 * Builds the footer section of the Roster panel.
 * Contains profile count, clear-all button, and import/export menu.
 */
@Slf4j
public class PanelFooterBuilder
{
    private final RosterPlugin plugin;
    private final AccountStorage storage;
    private final BiConsumer<String, NotificationToast.Type> showNotification;
    private final Runnable onRebuild;

    public PanelFooterBuilder(RosterPlugin plugin, BiConsumer<String, NotificationToast.Type> showNotification,
                              Runnable onRebuild)
    {
        this.plugin = plugin;
        this.storage = plugin.getAccountStorage();
        this.showNotification = showNotification;
        this.onRebuild = onRebuild;
    }

    public JPanel build(JLabel accountCountLabel)
    {
        JPanel footer = new JPanel(new BorderLayout(Theme.SPACING_SM, Theme.SPACING_SM));
        footer.setBackground(Theme.BACKGROUND);
        footer.setBorder(new EmptyBorder(Theme.SPACING_LG, 0, 0, 0));

        footer.add(accountCountLabel, BorderLayout.WEST);

        JPanel rightPanel = new JPanel(new FlowLayout(FlowLayout.RIGHT, Theme.SPACING_XS, 0));
        rightPanel.setOpaque(false);
        rightPanel.add(createViewToggleButton());
        rightPanel.add(createImportExportMenu());
        rightPanel.add(createClearAllButton());

        footer.add(rightPanel, BorderLayout.EAST);
        return footer;
    }

    private IconButton createViewToggleButton()
    {
        boolean isGrid = plugin.getConfig().gridView();
        String icon = isGrid ? Icons.LIST : Icons.GRID;
        String tooltip = isGrid ? "Switch to list view" : "Switch to grid view";
        IconButton button = new IconButton(icon, tooltip);
        button.addActionListener(e -> {
            net.runelite.client.config.ConfigManager configManager = plugin.getConfigManager();
            boolean current = plugin.getConfig().gridView();
            boolean next = !current;
            configManager.setConfiguration(RosterConfig.CONFIG_GROUP, "gridView", next);
            // Update button icon and tooltip to reflect new state
            button.updateIcon(next ? Icons.LIST : Icons.GRID);
            button.setToolTipText(next ? "Switch to list view" : "Switch to grid view");
        });
        return button;
    }

    private IconButton createClearAllButton()
    {
        IconButton button = new IconButton(Icons.DELETE, "Clear...");
        JPopupMenu clearMenu = new JPopupMenu();

        JMenuItem clearProfiles = new JMenuItem("Clear All Accounts");
        clearProfiles.addActionListener(e -> confirmClear("accounts"));
        clearMenu.add(clearProfiles);

        JMenuItem clearCategories = new JMenuItem("Clear All Categories");
        clearCategories.addActionListener(e -> confirmClear("categories"));
        clearMenu.add(clearCategories);

        clearMenu.addSeparator();

        JMenuItem clearBoth = new JMenuItem("Clear Everything");
        clearBoth.setForeground(Theme.BUTTON_DANGER);
        clearBoth.addActionListener(e -> confirmClear("both"));
        clearMenu.add(clearBoth);

        button.addActionListener(e -> clearMenu.show(button, 0, -clearMenu.getPreferredSize().height));
        return button;
    }

    private ExpandingMenuButton createImportExportMenu()
    {
        ExpandingMenuButton menu = new ExpandingMenuButton(Icons.CLIPBOARD, "Export/Import accounts");
        menu.addMenuItem("Import from clipboard", this::doImport);
        menu.addMenuItem("Copy to clipboard", this::doExport);
        return menu;
    }

    private void doExport()
    {
        ImportExportService service = plugin.getImportExportService();
        ExportResult result = service.exportToClipboard();

        if (result.success)
        {
            showNotification.accept("Copied " + result.accountCount + " accounts, " + result.groupCount + " categories",
                NotificationToast.Type.SUCCESS);
        }
        else
        {
            showNotification.accept("Copy failed: " + result.error, NotificationToast.Type.ERROR);
        }
    }

    private void doImport()
    {
        ImportExportService service = plugin.getImportExportService();
        ImportDuplicateMode duplicateMode = plugin.getConfig().importDuplicateMode();
        ImportResult result = service.importFromClipboard(false, duplicateMode);

        log.info("Import result: success={}, added={}, skipped={}, updated={}, error={}",
            result.success, result.accountsAdded, result.accountsSkipped, result.accountsUpdated, result.error);

        if (result.success)
        {
            NotificationToast.Type type = result.hasChanges() ? NotificationToast.Type.SUCCESS : NotificationToast.Type.WARNING;
            showNotification.accept(result.getDetailedMessage(), type);
            if (result.hasChanges()) onRebuild.run();
        }
        else
        {
            showNotification.accept("Import failed: " + result.error, NotificationToast.Type.ERROR);
        }
    }

    private void confirmClear(String mode)
    {
        int accountCount = storage.getAccounts().size();
        int groupCount = storage.getGroups().size();

        String message;
        String title;
        switch (mode)
        {
            case "accounts":
                if (accountCount == 0) { showNotification.accept("No accounts to clear", NotificationToast.Type.INFO); return; }
                message = "Delete all " + accountCount + " accounts?\n\nThis cannot be undone.";
                title = "Clear Accounts";
                break;
            case "categories":
                if (groupCount == 0) { showNotification.accept("No categories to clear", NotificationToast.Type.INFO); return; }
                message = "Delete all " + groupCount + " categories?\nProfiles will be moved to Uncategorized.";
                title = "Clear Categories";
                break;
            default:
                if (accountCount == 0 && groupCount == 0) { showNotification.accept("Nothing to clear", NotificationToast.Type.INFO); return; }
                message = "Delete all " + accountCount + " accounts and " + groupCount + " categories?\n\nThis cannot be undone.";
                title = "Clear Everything";
                break;
        }

        int result = JOptionPane.showConfirmDialog(
            SwingUtilities.getWindowAncestor(plugin.getPanel()),
            message, title, JOptionPane.YES_NO_OPTION, JOptionPane.WARNING_MESSAGE
        );

        if (result == JOptionPane.YES_OPTION)
        {
            if ("accounts".equals(mode) || "both".equals(mode))
            {
                storage.deleteAllProfiles();
            }
            if ("categories".equals(mode) || "both".equals(mode))
            {
                storage.deleteAllGroups();
            }
            showNotification.accept("Cleared " + mode, NotificationToast.Type.SUCCESS);
            onRebuild.run();
        }
    }
}

package com.mylosis.roster.ui.components;

import com.mylosis.roster.RosterPlugin;
