    public static final Color BUTTON_PRIMARY_HOVER = new Color(65, 145, 80);
    public static final Color BUTTON_SECONDARY = ColorScheme.DARKER_GRAY_COLOR;
    public static final Color BUTTON_SECONDARY_HOVER = ColorScheme.DARK_GRAY_HOVER_COLOR;
    public static final Color BUTTON_DANGER = new Color(220, 53, 69);
    public static final Color BUTTON_DANGER_HOVER = new Color(240, 73, 89);

    // Accent colors
    public static final Color ACCENT_ORANGE = ColorScheme.BRAND_ORANGE;
    public static final Color ACCENT_BLUE = new Color(66, 135, 245);
    public static final Color ACCENT_YELLOW = new Color(220, 180, 80);

    // Online indicator
    public static final Color ONLINE_INDICATOR = new Color(60, 180, 75);
    public static final int ONLINE_DOT_SIZE = 8;

    // Category color palette (preset options for user selection) — names paired with colors
    public static final String[] CATEGORY_COLOR_NAMES = {
        "Red", "Orange", "Yellow", "Green", "Blue", "Purple", "Pink", "Teal"
    };
    public static final Color[] CATEGORY_COLORS = {
        new Color(220, 53, 69),   // Red
        new Color(255, 140, 0),   // Orange
        new Color(220, 180, 80),  // Yellow
        new Color(60, 180, 75),   // Green
        new Color(66, 135, 245),  // Blue
        new Color(130, 80, 200),  // Purple
        new Color(200, 80, 160),  // Pink
        new Color(0, 180, 180),   // Teal
    };

    // Default colors auto-assigned to new categories by creation order
    public static final Color[] DEFAULT_CATEGORY_COLORS = {
        new Color(66, 135, 245),  // 1. Blue
        new Color(130, 80, 200),  // 2. Purple
        new Color(60, 180, 75),   // 3. Green
        new Color(220, 180, 80),  // 4. Yellow
        new Color(140, 160, 180), // 5. Slate
        new Color(255, 140, 0),   // 6. Orange
        new Color(200, 80, 160),  // 7. Pink
        new Color(0, 180, 180),   // 8. Teal
        new Color(220, 53, 69),   // 9. Red
        new Color(180, 130, 80),  // 10. Bronze
    };

    public static final int CATEGORY_BORDER_WIDTH = 3;

    // Spacing constants
    public static final int SPACING_XS = 3;
    public static final int SPACING_SM = 6;
    public static final int SPACING_MD = 10;
    public static final int SPACING_LG = 14;
    public static final int SPACING_XL = 20;

    // Border radius (for reference, actual rounding done in painting)
    public static final int BORDER_RADIUS_SM = 4;
    public static final int BORDER_RADIUS_MD = 6;
    public static final int BORDER_RADIUS_LG = 8;

    // Component sizes
    public static final int BUTTON_HEIGHT = 32;
    public static final int BUTTON_HEIGHT_SM = 26;
    public static final int ICON_SIZE = 18;
    public static final int ICON_SIZE_SM = 14;
    public static final int CARD_HEIGHT = 80;
    public static final int SCROLLBAR_WIDTH = 18;
    public static final int MENU_BUTTON_SIZE = 32;

    // Font sizes
    public static final float FONT_SIZE_TITLE = 20f;
    public static final float FONT_SIZE_HEADING = 16f;
    public static final float FONT_SIZE_BODY = 14f;
    public static final float FONT_SIZE_SMALL = 13f;
    public static final float FONT_SIZE_TINY = 12f;

    /**
     * Parses a hex color string (e.g. "#FF5733") into a Color. Returns null if input is null/empty.
     */
    public static Color parseColor(String hex)
    {
        if (hex == null || hex.isEmpty())
        {
            return null;
        }
        try
        {
            return Color.decode(hex);
        }
        catch (NumberFormatException e)
        {
            return null;
        }
    }

    /**
     * Converts a Color to a hex string (e.g. "#FF5733").
     */
    public static String colorToHex(Color color)
    {
        return String.format("#%02X%02X%02X", color.getRed(), color.getGreen(), color.getBlue());
    }

    /**
     * Creates a font with the specified style and size.
     */
    public static Font font(Font base, int style, float size)
    {
        return base.deriveFont(style, size);
    }

    /**
     * Creates a bold font.
     */
    public static Font fontBold(Font base, float size)
    {
        return font(base, Font.BOLD, size);
    }

    /**
     * Creates a regular font.
     */
    public static Font fontRegular(Font base, float size)
    {
        return font(base, Font.PLAIN, size);
    }
}

package com.mylosis.roster.ui.components;

import javax.swing.JButton;
import javax.swing.ImageIcon;
import javax.swing.border.EmptyBorder;
import java.awt.Color;
import java.awt.Cursor;
import java.awt.Dimension;
import java.awt.Graphics;
import java.awt.Graphics2D;
import java.awt.RenderingHints;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;

/**
 * A styled icon button with hover effects.
 */
public class IconButton extends JButton
{
    private Color normalBackground;
    private Color hoverBackground;
    private Color activeBackground;
    private boolean isHovered = false;
    private boolean isPressed = false;
    private int cornerRadius = Theme.BORDER_RADIUS_SM;

    public IconButton(String iconName)
    {
        this(iconName, null);
    }

    public IconButton(String iconName, String tooltip)
    {
        super();
        setIcon(Icons.get(iconName));
        if (tooltip != null)
        {
            setToolTipText(tooltip);
        }

        initDefaults();
        setupListeners();
    }

    public IconButton(ImageIcon icon, String tooltip)
    {
        super(icon);
        if (tooltip != null)
        {
            setToolTipText(tooltip);
        }

        initDefaults();
        setupListeners();
    }

    private void initDefaults()
    {
        setContentAreaFilled(false);
        setBorderPainted(false);
        setFocusPainted(false);
        setOpaque(false);

        normalBackground = Theme.BUTTON_SECONDARY;
        hoverBackground = Theme.BUTTON_SECONDARY_HOVER;
        activeBackground = Theme.CARD_SELECTED;

        setForeground(Theme.TEXT_PRIMARY);
        setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        setBorder(new EmptyBorder(Theme.SPACING_XS, Theme.SPACING_SM, Theme.SPACING_XS, Theme.SPACING_SM));

        setPreferredSize(new Dimension(Theme.BUTTON_HEIGHT + 8, Theme.BUTTON_HEIGHT));
    }

    private void setupListeners()
    {
        addMouseListener(new MouseAdapter()
        {
            @Override
            public void mouseEntered(MouseEvent e)
            {
                isHovered = true;
                repaint();
            }

            @Override
            public void mouseExited(MouseEvent e)
            {
                isHovered = false;
                isPressed = false;
                repaint();
            }

            @Override
            public void mousePressed(MouseEvent e)
            {
                isPressed = true;
                repaint();
            }

            @Override
            public void mouseReleased(MouseEvent e)
            {
                isPressed = false;
                repaint();
            }
        });
    }

    public void updateIcon(String iconName)
    {
        setIcon(Icons.get(iconName));
        repaint();
    }

    public void setColors(Color normal, Color hover, Color active)
    {
        this.normalBackground = normal;
        this.hoverBackground = hover;
        this.activeBackground = active;
        repaint();
    }

    public void setPrimaryStyle()
    {
        setColors(Theme.BUTTON_PRIMARY, Theme.BUTTON_PRIMARY_HOVER, Theme.BUTTON_PRIMARY);
    }

    public void setDangerStyle()
    {
        setColors(Theme.BUTTON_DANGER, Theme.BUTTON_DANGER_HOVER, Theme.BUTTON_DANGER);
    }

    public void setCornerRadius(int radius)
    {
        this.cornerRadius = radius;
        repaint();
    }

    @Override
    protected void paintComponent(Graphics g)
    {
        Graphics2D g2 = (Graphics2D) g.create();
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

        Color bgColor;
        if (isPressed)
        {
            bgColor = activeBackground;
        }
        else if (isHovered)
        {
            bgColor = hoverBackground;
        }
        else
        {
            bgColor = normalBackground;
        }

        g2.setColor(bgColor);
        g2.fillRoundRect(0, 0, getWidth(), getHeight(), cornerRadius, cornerRadius);

        g2.dispose();
        super.paintComponent(g);
    }
}

package com.mylosis.roster.ui.components;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;
import java.awt.event.*;
import java.util.ArrayList;
import java.util.List;

/**
 * A button that expands into a dropdown menu panel when clicked.
 * Similar to the "+" button pattern that shows options like "Add new setup.."
 */
public class ExpandingMenuButton extends JPanel
{
    private final IconButton triggerButton;
    private final JPanel menuPanel;
    private final List<MenuItem> menuItems = new ArrayList<>();
    private boolean expanded = false;
    private JWindow popupWindow;
    private AWTEventListener outsideClickListener;

    public ExpandingMenuButton(String iconName, String tooltip)
    {
        setLayout(new BorderLayout());
        setOpaque(false);

        // The trigger button
        triggerButton = new IconButton(iconName, tooltip);
        triggerButton.addActionListener(e -> toggleMenu());
        add(triggerButton, BorderLayout.CENTER);

        // The menu panel (shown in popup)
        menuPanel = new JPanel();
        menuPanel.setLayout(new BoxLayout(menuPanel, BoxLayout.Y_AXIS));
        menuPanel.setBackground(Theme.CARD_BACKGROUND);
        menuPanel.setBorder(BorderFactory.createCompoundBorder(
            BorderFactory.createLineBorder(Theme.CARD_BORDER, 1),
            new EmptyBorder(Theme.SPACING_XS, 0, Theme.SPACING_XS, 0)
        ));

        // Initialize outside click listener (must be after triggerButton is set)
        outsideClickListener = createOutsideClickListener();
    }

    private AWTEventListener createOutsideClickListener()
    {
        return event -> {
            if (event instanceof MouseEvent)
            {
                MouseEvent me = (MouseEvent) event;
                if (me.getID() == MouseEvent.MOUSE_PRESSED)
                {
                    if (popupWindow != null && popupWindow.isVisible() && triggerButton.isShowing())
                    {
                        Point p = me.getLocationOnScreen();
                        Rectangle bounds = popupWindow.getBounds();
                        Rectangle buttonBounds = new Rectangle(
                            triggerButton.getLocationOnScreen(),
                            triggerButton.getSize()
                        );

                        if (!bounds.contains(p) && !buttonBounds.contains(p))
                        {
                            SwingUtilities.invokeLater(this::hideMenu);
                        }
                    }
                }
            }
        };
    }

    public void addMenuItem(String label, Runnable action)
    {
        MenuItem item = new MenuItem(label, action);
        menuItems.add(item);

        if (menuPanel.getComponentCount() > 0)
        {
            // Add subtle separator line between items
            JSeparator sep = new JSeparator(SwingConstants.HORIZONTAL);
            sep.setForeground(Theme.CARD_BORDER);
            sep.setBackground(Theme.CARD_BACKGROUND);
            sep.setMaximumSize(new Dimension(Integer.MAX_VALUE, 1));
            menuPanel.add(sep);
        }

        menuPanel.add(item);
    }

    private void toggleMenu()
    {
        if (expanded)
        {
            hideMenu();
        }
        else
        {
            showMenu();
        }
    }

    private void showMenu()
    {
        if (popupWindow != null)
        {
            popupWindow.dispose();
        }

        Window owner = SwingUtilities.getWindowAncestor(this);
        popupWindow = new JWindow(owner);
        popupWindow.setType(Window.Type.POPUP);
        popupWindow.add(menuPanel);
        popupWindow.pack();

        // Position above the button, aligned to the right edge
        Point buttonLocation = triggerButton.getLocationOnScreen();
        int x = buttonLocation.x + triggerButton.getWidth() - popupWindow.getWidth();
        int y = buttonLocation.y - popupWindow.getHeight() - 2;

        // If would go off screen top, show below instead
        if (y < 0)
        {
            y = buttonLocation.y + triggerButton.getHeight() + 2;
        }

        popupWindow.setLocation(x, y);
        popupWindow.setVisible(true);
        expanded = true;

        // Close when clicking outside
        Toolkit.getDefaultToolkit().addAWTEventListener(outsideClickListener, AWTEvent.MOUSE_EVENT_MASK);
    }

    private void hideMenu()
    {
        if (popupWindow != null)
        {
            popupWindow.dispose();
            popupWindow = null;
        }
        expanded = false;
        Toolkit.getDefaultToolkit().removeAWTEventListener(outsideClickListener);
    }

    /**
     * Individual menu item with hover effect
     */
    private class MenuItem extends JPanel
    {
        private boolean hovered = false;

        MenuItem(String label, Runnable action)
        {
            setLayout(new BorderLayout());
            setBackground(Theme.CARD_BACKGROUND);
            setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
            setBorder(new EmptyBorder(Theme.SPACING_SM, Theme.SPACING_MD, Theme.SPACING_SM, Theme.SPACING_MD));
            setMaximumSize(new Dimension(Integer.MAX_VALUE, 30));

            JLabel textLabel = new JLabel(label);
            textLabel.setForeground(Theme.TEXT_SECONDARY);
            textLabel.setFont(Theme.fontRegular(textLabel.getFont(), Theme.FONT_SIZE_SMALL));
            add(textLabel, BorderLayout.WEST);

            addMouseListener(new MouseAdapter()
            {
                @Override
                public void mouseEntered(MouseEvent e)
                {
                    hovered = true;
                    setBackground(Theme.CARD_HOVER);
                    textLabel.setForeground(Theme.TEXT_PRIMARY);
                }

                @Override
                public void mouseExited(MouseEvent e)
                {
                    hovered = false;
                    setBackground(Theme.CARD_BACKGROUND);
                    textLabel.setForeground(Theme.TEXT_SECONDARY);
                }

                @Override
                public void mousePressed(MouseEvent e)
                {
                    hideMenu();
                    action.run();
                }
            });
        }
    }
}

package com.mylosis.roster.ui.components;

import javax.swing.*;
import javax.swing.border.EmptyBorder;
import java.awt.*;
import java.awt.event.ActionEvent;
import java.awt.event.ActionListener;

/**
 * A temporary in-panel notification toast that auto-dismisses.
 */
public class NotificationToast extends JPanel
{
    public enum Type { SUCCESS, ERROR, INFO, WARNING }

    private final Timer dismissTimer;
    private final JLabel messageLabel;
    private float opacity = 0f;
    private boolean fadingIn = true;
    private final Timer fadeTimer;

    private static final int MAX_WIDTH = 220;

    public NotificationToast(String message, Type type, int durationMs)
    {
        setLayout(new BorderLayout());
        setOpaque(false);

        // Inner panel with background
        JPanel inner = new JPanel(new BorderLayout(Theme.SPACING_SM, 0))
        {
            @Override
            protected void paintComponent(Graphics g)
            {
                Graphics2D g2 = (Graphics2D) g.create();
                g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
                g2.setComposite(AlphaComposite.getInstance(AlphaComposite.SRC_OVER, opacity));
                g2.setColor(getBackgroundColor(type));
                g2.fillRoundRect(0, 0, getWidth(), getHeight(), Theme.BORDER_RADIUS_MD, Theme.BORDER_RADIUS_MD);
                g2.dispose();
                super.paintComponent(g);
            }
        };
        inner.setOpaque(false);
        inner.setBorder(new EmptyBorder(Theme.SPACING_MD, Theme.SPACING_MD, Theme.SPACING_MD, Theme.SPACING_MD));

        // Icon at top
        JLabel iconLabel = new JLabel(getIcon(type));
        iconLabel.setHorizontalAlignment(SwingConstants.CENTER);

        // Message with HTML wrapping
        String htmlMessage = "<html><div style='width: " + (MAX_WIDTH - 50) + "px; text-align: center;'>" +
            escapeHtml(message) + "</div></html>";
        messageLabel = new JLabel(htmlMessage)
        {
            @Override
            protected void paintComponent(Graphics g)
            {
                Graphics2D g2 = (Graphics2D) g.create();
                g2.setComposite(AlphaComposite.getInstance(AlphaComposite.SRC_OVER, opacity));
                super.paintComponent(g2);
                g2.dispose();
            }
        };
        messageLabel.setForeground(Theme.TEXT_PRIMARY);
        messageLabel.setFont(Theme.fontRegular(messageLabel.getFont(), Theme.FONT_SIZE_SMALL));
        messageLabel.setHorizontalAlignment(SwingConstants.CENTER);

        // Stack icon on top, message below
        JPanel contentPanel = new JPanel();
        contentPanel.setLayout(new BoxLayout(contentPanel, BoxLayout.Y_AXIS));
        contentPanel.setOpaque(false);
        iconLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
        messageLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
        contentPanel.add(iconLabel);
        contentPanel.add(Box.createVerticalStrut(Theme.SPACING_XS));
        contentPanel.add(messageLabel);

        inner.add(contentPanel, BorderLayout.CENTER);
        add(inner, BorderLayout.CENTER);

        // Fade animation
        fadeTimer = new Timer(16, e -> {
            if (fadingIn)
            {
                opacity = Math.min(1f, opacity + 0.1f);
                if (opacity >= 1f)
                {
                    fadingIn = false;
                    ((Timer) e.getSource()).stop();
                }
            }
            else
            {
                opacity = Math.max(0f, opacity - 0.1f);
                if (opacity <= 0f)
                {
                    ((Timer) e.getSource()).stop();
                    Container parent = getParent();
                    if (parent != null)
                    {
                        parent.remove(NotificationToast.this);
                        parent.revalidate();
                        parent.repaint();
                    }
                }
            }
            repaint();
        });

        // Auto-dismiss timer
        dismissTimer = new Timer(durationMs, e -> {
            fadingIn = false;
            fadeTimer.start();
        });
        dismissTimer.setRepeats(false);

        // Start fade in
        fadeTimer.start();
        dismissTimer.start();
    }

    private Color getBackgroundColor(Type type)
    {
        switch (type)
        {
            case SUCCESS:
                return new Color(40, 120, 60, 230);
            case WARNING:
                return new Color(160, 130, 30, 230);
            case ERROR:
                return new Color(150, 50, 50, 230);
            case INFO:
            default:
                return new Color(60, 60, 60, 230);
        }
    }

    private Icon getIcon(Type type)
    {
        // Simple colored circle as icon
        int size = 12;
        return new Icon()
        {
            @Override
            public void paintIcon(Component c, Graphics g, int x, int y)
            {
                Graphics2D g2 = (Graphics2D) g.create();
                g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
                g2.setComposite(AlphaComposite.getInstance(AlphaComposite.SRC_OVER, opacity));

                Color color;
                switch (type)
                {
                    case SUCCESS:
                        color = new Color(100, 220, 120);
                        break;
                    case WARNING:
                        color = new Color(255, 210, 70);
                        break;
                    case ERROR:
                        color = new Color(255, 100, 100);
                        break;
                    case INFO:
                    default:
                        color = Theme.TEXT_SECONDARY;
                        break;
                }

                g2.setColor(color);
                g2.fillOval(x, y, size, size);
                g2.dispose();
            }

            @Override
            public int getIconWidth() { return size; }

            @Override
            public int getIconHeight() { return size; }
        };
    }

    public void dismiss()
    {
        dismissTimer.stop();
        fadingIn = false;
        fadeTimer.start();
    }

    private static String escapeHtml(String text)
    {
        if (text == null) return "";
        return text.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;");
    }
}

package com.mylosis.roster.ui.components;

import lombok.extern.slf4j.Slf4j;
import net.runelite.client.util.ImageUtil;

import javax.swing.ImageIcon;
import java.awt.Color;
import java.awt.Graphics2D;
import java.awt.RenderingHints;
import java.awt.image.BufferedImage;
import java.util.HashMap;
import java.util.Map;

/**
 * Icon registry for the plugin. Provides access to icon resources with caching.
 */
@Slf4j
public final class Icons
{
    private Icons() {} // Prevent instantiation

    private static final String ICON_PATH = "/com/mylosis/roster/";
    private static final Map<String, ImageIcon> iconCache = new HashMap<>();

    // Icon names
    public static final String ADD = "add";
    public static final String EDIT = "edit";
    public static final String DELETE = "delete";
    public static final String EXPORT = "export";
    public static final String IMPORT = "import";
    public static final String CLIPBOARD = "clipboard";
    public static final String TRANSFER = "transfer";
    public static final String GROUP = "group";
    public static final String CATEGORY = "category";
    public static final String EXPAND = "expand";
    public static final String COLLAPSE = "collapse";
    public static final String MENU = "menu";
    public static final String SEARCH = "search";
    public static final String USER = "user";
    public static final String LOGIN = "login";
    public static final String GRID = "grid";
    public static final String LIST = "list";

    /**
     * Gets an icon by name. Returns a fallback if the icon is not found.
     */
    public static ImageIcon get(String name)
    {
        return get(name, Theme.ICON_SIZE);
    }

    /**
     * Gets an icon by name with a specific size.
     */
    public static ImageIcon get(String name, int size)
    {
        String cacheKey = name + "_" + size;
        if (iconCache.containsKey(cacheKey))
        {
            return iconCache.get(cacheKey);
        }

        ImageIcon icon = loadIcon(name, size);
        iconCache.put(cacheKey, icon);
        return icon;
    }

    private static ImageIcon loadIcon(String name, int size)
    {
        try
        {
            BufferedImage img = ImageUtil.loadImageResource(Icons.class, ICON_PATH + name + ".png");
            if (img.getWidth() != size || img.getHeight() != size)
            {
                img = ImageUtil.resizeImage(img, size, size);
            }
            return new ImageIcon(img);
        }
        catch (Exception e)
        {
            log.debug("Icon not found: {}, using fallback", name);
            return new ImageIcon(createFallbackIcon(name, size));
        }
    }

    /**
     * Creates a simple fallback icon when the actual icon is not found.
     * Delegates to specific draw methods per icon type.
     */
    private static BufferedImage createFallbackIcon(String name, int size)
    {
        BufferedImage img = new BufferedImage(size, size, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = img.createGraphics();
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

        switch (name)
        {
            case ADD:
                drawAddIcon(g, size);
                break;
            case DELETE:
                drawDeleteIcon(g, size);
                break;
            case EXPAND:
                drawExpandIcon(g, size);
                break;
            case COLLAPSE:
                drawCollapseIcon(g, size);
                break;
            case MENU:
                drawMenuIcon(g, size);
                break;
            case USER:
                drawUserIcon(g, size);
                break;
            case GROUP:
            case CATEGORY:
                drawFolderIcon(g, size);
                break;
            case LOGIN:
                drawLoginIcon(g, size);
                break;
            case EDIT:
                drawEditIcon(g, size);
                break;
            case EXPORT:
            case IMPORT:
                drawExportImportIcon(g, size, EXPORT.equals(name));
                break;
            case CLIPBOARD:
                drawClipboardIcon(g, size);
                break;
            case TRANSFER:
                drawTransferIcon(g, size);
                break;
            case SEARCH:
                drawSearchIcon(g, size);
                break;
            case GRID:
                drawGridIcon(g, size);
                break;
            case LIST:
                drawListIcon(g, size);
                break;
            default:
                drawDefaultIcon(g, size);
                break;
        }

        g.dispose();
        return img;
    }

    private static void drawAddIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.BUTTON_PRIMARY);
        int center = size / 2;
        int barLength = (int) (size * 0.6);
        int barThickness = Math.max(2, size / 8);
        g.fillRect(center - barLength / 2, center - barThickness / 2, barLength, barThickness);
        g.fillRect(center - barThickness / 2, center - barLength / 2, barThickness, barLength);
    }

    private static void drawDeleteIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.BUTTON_DANGER);
        g.setStroke(new java.awt.BasicStroke(Math.max(2, size / 6f)));
        int margin = size / 4;
        g.drawLine(margin, margin, size - margin, size - margin);
        g.drawLine(size - margin, margin, margin, size - margin);
    }

    private static void drawExpandIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        int[] xPoints = {size / 3, size * 2 / 3, size / 3};
        int[] yPoints = {size / 4, size / 2, size * 3 / 4};
        g.fillPolygon(xPoints, yPoints, 3);
    }

    private static void drawCollapseIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        int[] xPoints = {size / 4, size / 2, size * 3 / 4};
        int[] yPoints = {size / 3, size * 2 / 3, size / 3};
        g.fillPolygon(xPoints, yPoints, 3);
    }

    private static void drawMenuIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        int dotSize = Math.max(3, size / 5);
        int dotX = size / 2 - dotSize / 2;
        g.fillOval(dotX, size / 4 - dotSize / 2, dotSize, dotSize);
        g.fillOval(dotX, size / 2 - dotSize / 2, dotSize, dotSize);
        g.fillOval(dotX, size * 3 / 4 - dotSize / 2, dotSize, dotSize);
    }

    private static void drawUserIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        int headRadius = size / 4;
        g.fillOval(size / 2 - headRadius, size / 6, headRadius * 2, headRadius * 2);
        g.fillArc(size / 6, size / 2, size * 2 / 3, size * 2 / 3, 0, 180);
    }

    private static void drawFolderIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        int folderMargin = size / 6;
        int folderWidth = size - folderMargin * 2;
        int folderHeight = (int) (folderWidth * 0.7);
        int tabWidth = folderWidth / 3;
        int tabHeight = folderHeight / 5;
        g.fillRoundRect(folderMargin, folderMargin + tabHeight, tabWidth, tabHeight, 2, 2);
        g.fillRoundRect(folderMargin, folderMargin + tabHeight * 2, folderWidth, folderHeight, 3, 3);
    }

    private static void drawLoginIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.BUTTON_PRIMARY);
        g.setStroke(new java.awt.BasicStroke(Math.max(2, size / 8f)));
        int arrowY = size / 2;
        g.drawLine(size / 4, arrowY, size * 3 / 4, arrowY);
        g.drawLine(size / 2, size / 4, size * 3 / 4, arrowY);
        g.drawLine(size / 2, size * 3 / 4, size * 3 / 4, arrowY);
    }

    private static void drawEditIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        g.setStroke(new java.awt.BasicStroke(Math.max(1, size / 8f)));
        g.drawLine(size / 4, size * 3 / 4, size * 3 / 4, size / 4);
        g.drawLine(size / 4 - 2, size * 3 / 4 + 2, size / 4 + 2, size * 3 / 4 - 2);
    }

    private static void drawExportImportIcon(Graphics2D g, int size, boolean isExport)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        g.setStroke(new java.awt.BasicStroke(Math.max(2, size / 8f)));
        int arrowStart = isExport ? size * 2 / 3 : size / 3;
        int arrowEnd = isExport ? size / 3 : size * 2 / 3;
        g.drawLine(size / 2, arrowStart, size / 2, arrowEnd);
        int tipY = arrowEnd;
        int tipDir = isExport ? 1 : -1;
        g.drawLine(size / 3, tipY + tipDir * size / 6, size / 2, tipY);
        g.drawLine(size * 2 / 3, tipY + tipDir * size / 6, size / 2, tipY);
    }

    private static void drawClipboardIcon(Graphics2D g, int size)
    {
        Color iconColor = Theme.TEXT_SECONDARY;
        g.setColor(iconColor);
        int clipMargin = size / 5;
        int clipWidth = size - clipMargin * 2;
        int clipHeight = (int) (size * 0.75);
        g.fillRoundRect(clipMargin, size / 4, clipWidth, clipHeight, 3, 3);
        g.setColor(Theme.BACKGROUND);
        int clipTopWidth = clipWidth / 2;
        g.fillRoundRect(size / 2 - clipTopWidth / 2, size / 6, clipTopWidth, size / 5, 2, 2);
        g.setColor(iconColor);
        g.drawRoundRect(size / 2 - clipTopWidth / 2, size / 6, clipTopWidth, size / 5, 2, 2);
    }

    private static void drawTransferIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        g.setStroke(new java.awt.BasicStroke(Math.max(2, size / 8f)));
        int leftX = size / 3;
        g.drawLine(leftX, size * 2 / 3, leftX, size / 4);
        g.drawLine(leftX - size / 8, size / 4 + size / 6, leftX, size / 4);
        g.drawLine(leftX + size / 8, size / 4 + size / 6, leftX, size / 4);
        int rightX = size * 2 / 3;
        g.drawLine(rightX, size / 3, rightX, size * 3 / 4);
        g.drawLine(rightX - size / 8, size * 3 / 4 - size / 6, rightX, size * 3 / 4);
        g.drawLine(rightX + size / 8, size * 3 / 4 - size / 6, rightX, size * 3 / 4);
    }

    private static void drawSearchIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        g.setStroke(new java.awt.BasicStroke(Math.max(2, size / 8f)));
        int circleSize = size / 2;
        g.drawOval(size / 6, size / 6, circleSize, circleSize);
        g.drawLine(size / 6 + circleSize - 2, size / 6 + circleSize - 2, size * 5 / 6, size * 5 / 6);
    }

    private static void drawGridIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        int gs = (size - 6) / 2;
        int gap = 2;
        int off = 2;
        g.fillRect(off, off, gs, gs);
        g.fillRect(off + gs + gap, off, gs, gs);
        g.fillRect(off, off + gs + gap, gs, gs);
        g.fillRect(off + gs + gap, off + gs + gap, gs, gs);
    }

    private static void drawListIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        g.setStroke(new java.awt.BasicStroke(Math.max(2, size / 6f)));
        int lm = size / 5;
        g.drawLine(lm, size / 4, size - lm, size / 4);
        g.drawLine(lm, size / 2, size - lm, size / 2);
        g.drawLine(lm, size * 3 / 4, size - lm, size * 3 / 4);
    }

    private static void drawDefaultIcon(Graphics2D g, int size)
    {
        g.setColor(Theme.TEXT_SECONDARY);
        g.fillOval(2, 2, size - 4, size - 4);
    }

    /**
     * Clears the icon cache. Useful when reloading resources.
     */
    public static void clearCache()
    {
        iconCache.clear();
    }
}

package com.mylosis.roster.ui;

import com.mylosis.roster.RosterConfig;
import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.ui.components.InlineAccountForm;
import com.mylosis.roster.ui.components.Theme;

import javax.swing.*;
import java.awt.*;

/**
 * Manages the expand/collapse behavior and inline edit form for a AccountCardPanel.
 */
public class CardExpansionHandler
{
    private final RosterPlugin plugin;
    private final Account profile;
    private final RosterConfig config;
    private final RosterPanel parentPanel;
    private final JPanel ownerCard;
    private final JPanel headerPanel;

    private JPanel formPanel;
    private InlineAccountForm editForm;
    private boolean expanded = false;

    public CardExpansionHandler(RosterPlugin plugin, Account profile,
                                RosterPanel parentPanel, JPanel ownerCard, JPanel headerPanel)
    {
        this.plugin = plugin;
        this.profile = profile;
        this.config = plugin.getConfig();
        this.parentPanel = parentPanel;
        this.ownerCard = ownerCard;
        this.headerPanel = headerPanel;
    }

    public JPanel createFormPanel()
    {
        JPanel panel = new JPanel(new BorderLayout());
        panel.setBackground(Theme.FORM_BACKGROUND);
        panel.setBorder(BorderFactory.createMatteBorder(1, 0, 0, 0, Theme.CARD_BORDER));

        editForm = new InlineAccountForm(plugin, profile, true, null);
        editForm.setOnSave(savedAccount -> {
            plugin.getAccountStorage().saveAccount(savedAccount);
            collapse();
            plugin.getPanel().rebuild();
        });
        editForm.setOnCancel(this::collapse);

        panel.add(editForm, BorderLayout.CENTER);
        formPanel = panel;
        return panel;
    }

    public boolean isExpanded()
    {
        return expanded;
    }

    public void toggleExpanded()
    {
        if (expanded) collapse();
        else expand();
    }

    public void expand()
    {
        if (expanded) return;
        if (parentPanel != null)
        {
            parentPanel.collapseExpandedCard();
            parentPanel.setExpandedCard((AccountCardPanel) ownerCard);
        }
        expanded = true;
        formPanel.setVisible(true);

        // Calculate exact needed height: header + form + border
        int headerHeight = headerPanel.getPreferredSize().height;
        int formHeight = formPanel.getPreferredSize().height;
        Insets insets = ownerCard.getInsets();
        int totalHeight = headerHeight + formHeight + insets.top + insets.bottom;
        ownerCard.setMaximumSize(new Dimension(Integer.MAX_VALUE, totalHeight));
        ownerCard.setPreferredSize(new Dimension(ownerCard.getWidth(), totalHeight));

        editForm.focusUsernameField();
        revalidateAncestors();
    }

    public void collapse()
    {
        if (!expanded) return;
        expanded = false;
        formPanel.setVisible(false);
        int cardHeight = Theme.CARD_HEIGHT;
        ownerCard.setMaximumSize(new Dimension(Integer.MAX_VALUE, cardHeight));
        ownerCard.setPreferredSize(null);
        if (parentPanel != null) parentPanel.setExpandedCard(null);
        revalidateAncestors();
    }

    private void revalidateAncestors()
    {
        Container ancestor = ownerCard.getParent();
        while (ancestor != null)
        {
            ancestor.revalidate();
            ancestor.repaint();
            ancestor = ancestor.getParent();
        }
    }
}

package com.mylosis.roster.ui.dnd;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.AccountData;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.ui.RosterPanel;
import lombok.extern.slf4j.Slf4j;

import javax.swing.*;
import java.util.ArrayList;
import java.util.List;

/**
 * Executes drop operations for profiles and categories.
 * Handles moving profiles between categories and reordering.
 */
@Slf4j
public class DropExecutor
{
    private final RosterPlugin plugin;
    private final RosterPanel panel;

    public DropExecutor(RosterPlugin plugin, RosterPanel panel)
    {
        this.plugin = plugin;
        this.panel = panel;
    }

    /**
     * Perform a profile drop (move to category or reorder).
     */
    public void executeProfileDrop(DragDropManager.DropTarget target, Account draggedAccount)
    {
        if (target.type != DragDropManager.DropTarget.Type.CATEGORY_DROP &&
            target.type != DragDropManager.DropTarget.Type.UNCATEGORIZED)
        {
            return;
        }

        String newGroupId = target.groupId;
        String currentGroupId = draggedAccount.getGroupId();
        int insertIndex = target.insertIndex;

        boolean isDifferentCategory = (currentGroupId == null && newGroupId != null) ||
            (currentGroupId != null && !currentGroupId.equals(newGroupId));

        if (isDifferentCategory)
        {
            moveProfileToCategory(draggedAccount, newGroupId, insertIndex);
        }
        else if (insertIndex >= 0)
        {
            reorderProfileInCategory(currentGroupId, draggedAccount, insertIndex);
            SwingUtilities.invokeLater(() -> panel.rebuild());
            log.debug("Reordered account {} to position {} in category {}",
                draggedAccount.getDisplayName(), insertIndex, currentGroupId);
        }
    }

    /**
     * Perform a category drop (reorder categories).
     */
    public void executeCategoryDrop(DragDropManager.DropTarget target, ProfileGroup draggedCategory)
    {
        if (target.type != DragDropManager.DropTarget.Type.CATEGORY_REORDER) return;

        List<ProfileGroup> groups = new ArrayList<>(plugin.getAccountStorage().getGroups());
        groups.sort((a, b) -> Integer.compare(a.getSortOrder(), b.getSortOrder()));

        int currentIndex = findGroupIndex(groups, draggedCategory.getId());
        if (currentIndex == -1) return;

        groups.remove(currentIndex);

        int insertIndex = target.insertIndex;
        if (currentIndex < insertIndex) insertIndex--;
        insertIndex = Math.max(0, Math.min(insertIndex, groups.size()));
        groups.add(insertIndex, draggedCategory);

        for (int i = 0; i < groups.size(); i++)
        {
            ProfileGroup g = groups.get(i);
            g.setSortOrder(i);
            plugin.getAccountStorage().saveGroup(g);
        }

        SwingUtilities.invokeLater(() -> panel.rebuild());
        log.debug("Reordered category {} to position {}", draggedCategory.getName(), insertIndex);
    }

    private void moveProfileToCategory(Account profile, String newGroupId, int insertIndex)
    {
        profile.setGroupId(newGroupId);
        if (profile.getMetadata() != null && insertIndex >= 0)
        {
            profile.getMetadata().setSortOrder(insertIndex);
        }
        plugin.getAccountStorage().saveAccount(profile);
        updateProfileSortOrders(newGroupId, profile.getId(), insertIndex);
        SwingUtilities.invokeLater(() -> panel.rebuild());
        log.debug("Moved account {} to category {} at position {}",
            profile.getDisplayName(), newGroupId, insertIndex);
    }

    private void updateProfileSortOrders(String groupId, String insertedProfileId, int insertIndex)
    {
        List<Account> categoryProfiles = getAccountsInCategory(groupId, insertedProfileId);
        categoryProfiles.sort(AccountData.SORT_ORDER_COMPARATOR);

        for (int i = 0; i < categoryProfiles.size(); i++)
        {
            Account p = categoryProfiles.get(i);
            int newOrder = i >= insertIndex ? i + 1 : i;
            if (p.getMetadata() != null)
            {
                p.getMetadata().setSortOrder(newOrder);
                plugin.getAccountStorage().saveAccount(p);
            }
        }
    }

    private void reorderProfileInCategory(String groupId, Account profile, int newIndex)
    {
        List<Account> categoryProfiles = getAccountsInCategory(groupId, null);
        categoryProfiles.sort(AccountData.SORT_ORDER_COMPARATOR);

        categoryProfiles.removeIf(p -> p.getId().equals(profile.getId()));
        newIndex = Math.max(0, Math.min(newIndex, categoryProfiles.size()));
        categoryProfiles.add(newIndex, profile);

        for (int i = 0; i < categoryProfiles.size(); i++)
        {
            Account p = categoryProfiles.get(i);
            if (p.getMetadata() != null)
            {
                p.getMetadata().setSortOrder(i);
                plugin.getAccountStorage().saveAccount(p);
            }
        }
    }

    private List<Account> getAccountsInCategory(String groupId, String excludeProfileId)
    {
        List<Account> result = new ArrayList<>();
        for (Account p : plugin.getAccountStorage().getAccounts())
        {
            String pGroupId = p.getGroupId();
            boolean sameCategory = (groupId == null && pGroupId == null) ||
                (groupId != null && groupId.equals(pGroupId));

            if (sameCategory && (excludeProfileId == null || !p.getId().equals(excludeProfileId)))
            {
                result.add(p);
            }
        }
        return result;
    }

    private int findGroupIndex(List<ProfileGroup> groups, String groupId)
    {
        for (int i = 0; i < groups.size(); i++)
        {
            if (groups.get(i).getId().equals(groupId)) return i;
        }
        return -1;
    }
}

package com.mylosis.roster.ui.dnd;

import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.ui.CategoryPanel;
import com.mylosis.roster.ui.AccountCardPanel;
import com.mylosis.roster.ui.RosterPanel;
import lombok.extern.slf4j.Slf4j;

import javax.swing.*;
import java.awt.*;
import java.util.ArrayList;
import java.util.List;

/**
 * Finds drop targets for drag-and-drop operations by walking the component tree.
 */
@Slf4j
public class DropTargetFinder
{
    private final RosterPanel panel;

    public DropTargetFinder(RosterPanel panel)
    {
        this.panel = panel;
    }

    /**
     * Find the drop target at the given screen point for a profile drag.
     */
    public DragDropManager.DropTarget findForProfile(Point screenPoint, Account draggedAccount)
    {
        DragDropManager.DropTarget target = checkCategoryPanels(screenPoint, draggedAccount);
        if (target != null)
        {
            return target;
        }
        return checkUncategorizedHeader(screenPoint, draggedAccount);
    }

    /**
     * Find the drop target at the given screen point for a category drag.
     */
    public DragDropManager.DropTarget findForCategory(Point screenPoint, ProfileGroup draggedCategory)
    {
        List<CategoryPanel> categoryPanels = findCategoryPanels();

        for (int i = 0; i < categoryPanels.size(); i++)
        {
            CategoryPanel categoryPanel = categoryPanels.get(i);
            if (!categoryPanel.isShowing()) continue;
            if (draggedCategory != null &&
                categoryPanel.getGroup().getId().equals(draggedCategory.getId()))
            {
                continue;
            }

            try
            {
                Point panelLocation = categoryPanel.getLocationOnScreen();
                Rectangle headerBounds = new Rectangle(
                    panelLocation.x, panelLocation.y,
                    categoryPanel.getWidth(), 45
                );

                if (headerBounds.contains(screenPoint))
                {
                    int midY = headerBounds.y + headerBounds.height / 2;
                    int insertIndex = screenPoint.y < midY ? i : i + 1;
                    return new DragDropManager.DropTarget(
                        DragDropManager.DropTarget.Type.CATEGORY_REORDER,
                        categoryPanel.getGroup().getId(),
                        headerBounds, insertIndex
                    );
                }
            }
            catch (Exception e)
            {
                // Component might not be showing
            }
        }
        return null;
    }

    private DragDropManager.DropTarget checkCategoryPanels(Point screenPoint, Account draggedAccount)
    {
        List<CategoryPanel> categoryPanels = findCategoryPanels();

        for (CategoryPanel categoryPanel : categoryPanels)
        {
            if (!categoryPanel.isShowing()) continue;

            try
            {
                Point panelLocation = categoryPanel.getLocationOnScreen();
                Rectangle panelBounds = new Rectangle(
                    panelLocation.x, panelLocation.y,
                    categoryPanel.getWidth(), categoryPanel.getHeight()
                );

                if (panelBounds.contains(screenPoint))
                {
                    String groupId = categoryPanel.getGroup().getId();
                    int insertIndex = calculateInsertIndex(categoryPanel, screenPoint);
                    return new DragDropManager.DropTarget(
                        DragDropManager.DropTarget.Type.CATEGORY_DROP,
                        groupId, panelBounds, insertIndex
                    );
                }
            }
            catch (Exception e)
            {
                // Component might not be showing
            }
        }
        return null;
    }

    private DragDropManager.DropTarget checkUncategorizedHeader(Point screenPoint, Account draggedAccount)
    {
        JPanel header = findUncategorizedHeader();
        if (header == null || !header.isShowing()) return null;

        try
        {
            Point headerLocation = header.getLocationOnScreen();
            Rectangle headerBounds = new Rectangle(
                headerLocation.x, headerLocation.y,
                header.getWidth(), header.getHeight()
            );

            if (headerBounds.contains(screenPoint))
            {
                if (draggedAccount != null && draggedAccount.getGroupId() == null)
                {
                    return null;
                }
                return new DragDropManager.DropTarget(
                    DragDropManager.DropTarget.Type.UNCATEGORIZED, null, headerBounds
                );
            }
        }
        catch (Exception e)
        {
            // Component might not be showing
        }
        return null;
    }

    /**
     * Calculate insert index based on mouse position relative to profile cards.
     */
    int calculateInsertIndex(CategoryPanel categoryPanel, Point screenPoint)
    {
        List<AccountCardPanel> cards = new ArrayList<>();
        findProfileCards(categoryPanel, cards);

        if (cards.isEmpty()) return 0;

        for (int i = 0; i < cards.size(); i++)
        {
            AccountCardPanel card = cards.get(i);
            if (!card.isShowing()) continue;

            try
            {
                Point cardLocation = card.getLocationOnScreen();
                int cardMidY = cardLocation.y + card.getHeight() / 2;
                if (screenPoint.y < cardMidY) return i;
            }
            catch (Exception e)
            {
                // Component might not be showing
            }
        }
        return cards.size();
    }

    private void findProfileCards(Container container, List<AccountCardPanel> result)
    {
        for (Component comp : container.getComponents())
        {
            if (comp instanceof AccountCardPanel)
            {
                result.add((AccountCardPanel) comp);
            }
            if (comp instanceof Container)
            {
                findProfileCards((Container) comp, result);
            }
        }
    }

    List<CategoryPanel> findCategoryPanels()
    {
        List<CategoryPanel> result = new ArrayList<>();
        findCategoryPanelsRecursive(panel, result);
        return result;
    }

    private void findCategoryPanelsRecursive(Container container, List<CategoryPanel> result)
    {
        if (container instanceof JScrollPane)
        {
            JScrollPane scrollPane = (JScrollPane) container;
            Component view = scrollPane.getViewport().getView();
            if (view instanceof CategoryPanel) result.add((CategoryPanel) view);
            if (view instanceof Container) findCategoryPanelsRecursive((Container) view, result);
            return;
        }

        for (Component comp : container.getComponents())
        {
            if (comp instanceof CategoryPanel) result.add((CategoryPanel) comp);
            if (comp instanceof Container) findCategoryPanelsRecursive((Container) comp, result);
        }
    }

    private JPanel findUncategorizedHeader()
    {
        List<JPanel> result = new ArrayList<>();
        findUncategorizedHeaderRecursive(panel, result);
        return result.isEmpty() ? null : result.get(0);
    }

    private void findUncategorizedHeaderRecursive(Container container, List<JPanel> result)
    {
        if (container instanceof JScrollPane)
        {
            JScrollPane scrollPane = (JScrollPane) container;
            Component view = scrollPane.getViewport().getView();
            if (view instanceof JPanel && Boolean.TRUE.equals(((JPanel) view).getClientProperty("UNCATEGORIZED_HEADER")))
            {
                result.add((JPanel) view);
                return;
            }
            if (view instanceof Container) findUncategorizedHeaderRecursive((Container) view, result);
            return;
        }

        for (Component comp : container.getComponents())
        {
            if (comp instanceof JPanel && Boolean.TRUE.equals(((JPanel) comp).getClientProperty("UNCATEGORIZED_HEADER")))
            {
                result.add((JPanel) comp);
                return;
            }
            if (comp instanceof Container) findUncategorizedHeaderRecursive((Container) comp, result);
        }
    }
}

package com.mylosis.roster.ui.dnd;

import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.ui.components.Theme;

import javax.swing.*;
import java.awt.*;
import java.awt.geom.RoundRectangle2D;

/**
 * Overlay component that shows drag feedback - a ghost of the dragged item
 * following the mouse cursor, and highlighting of valid drop targets.
 */
public class DragOverlay extends JComponent
{
    private final DragDropManager dragManager;

    private Point mouseLocation = null;
    private Image dragImage = null;
    private int dragImageWidth = 0;
    private int dragImageHeight = 0;

    public DragOverlay(DragDropManager dragManager)
    {
        this.dragManager = dragManager;
        setOpaque(false);
    }

    public void setMouseLocation(Point screenPoint)
    {
        if (screenPoint != null && getParent() != null)
        {
            Point parentLocation = getParent().getLocationOnScreen();
            this.mouseLocation = new Point(
                screenPoint.x - parentLocation.x,
                screenPoint.y - parentLocation.y
            );
        }
        else
        {
            this.mouseLocation = null;
        }
        repaint();
    }

    public void setDragImage(Component source)
    {
        if (source != null && source.getWidth() > 0 && source.getHeight() > 0)
        {
            dragImageWidth = Math.min(source.getWidth(), 250);
            dragImageHeight = Math.min(source.getHeight(), 80);

            // Create image from component
            dragImage = new java.awt.image.BufferedImage(
                dragImageWidth, dragImageHeight,
                java.awt.image.BufferedImage.TYPE_INT_ARGB
            );
            Graphics2D g2d = (Graphics2D) dragImage.getGraphics();
            g2d.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

            // Scale if needed
            double scaleX = (double) dragImageWidth / source.getWidth();
            double scaleY = (double) dragImageHeight / source.getHeight();
            double scale = Math.min(scaleX, scaleY);

            g2d.scale(scale, scale);
            source.paint(g2d);
            g2d.dispose();
        }
        else
        {
            dragImage = null;
        }
    }

    public void clearDragImage()
    {
        dragImage = null;
        mouseLocation = null;
        repaint();
    }

    @Override
    protected void paintComponent(Graphics g)
    {
        if (!dragManager.isDragging())
        {
            return;
        }

        Graphics2D g2d = (Graphics2D) g.create();
        g2d.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

        // Draw drop target highlight
        DragDropManager.DropTarget target = dragManager.getCurrentDropTarget();
        if (target != null)
        {
            drawDropTargetHighlight(g2d, target);
        }

        // Draw drag ghost at mouse position
        if (mouseLocation != null && dragImage != null)
        {
            int x = mouseLocation.x - dragImageWidth / 2;
            int y = mouseLocation.y - dragImageHeight / 2;

            // Draw shadow
            g2d.setColor(new Color(0, 0, 0, 30));
            g2d.fillRoundRect(x + 4, y + 4, dragImageWidth, dragImageHeight, 8, 8);

            // Draw semi-transparent image
            g2d.setComposite(AlphaComposite.getInstance(AlphaComposite.SRC_OVER, 0.85f));
            g2d.drawImage(dragImage, x, y, null);

            // Draw border
            g2d.setComposite(AlphaComposite.getInstance(AlphaComposite.SRC_OVER, 1.0f));
            g2d.setColor(Theme.BUTTON_PRIMARY);
            g2d.setStroke(new BasicStroke(2));
            g2d.drawRoundRect(x, y, dragImageWidth - 1, dragImageHeight - 1, 8, 8);
        }
        else if (mouseLocation != null)
        {
            // Fallback: draw a simple indicator if no image
            drawDragIndicator(g2d);
        }

        g2d.dispose();
    }

    private void drawDropTargetHighlight(Graphics2D g2d, DragDropManager.DropTarget target)
    {
        try
        {
            // Convert target bounds from screen to local coordinates
            Rectangle bounds = target.bounds;
            Point parentScreen = getParent().getLocationOnScreen();

            int x = bounds.x - parentScreen.x;
            int y = bounds.y - parentScreen.y;
            int width = bounds.width;
            int height = bounds.height;

            // Draw highlight background
            g2d.setColor(new Color(Theme.BUTTON_PRIMARY.getRed(),
                Theme.BUTTON_PRIMARY.getGreen(),
                Theme.BUTTON_PRIMARY.getBlue(), 40));
            g2d.fillRoundRect(x, y, width, height, 6, 6);

            // Draw highlight border
            g2d.setColor(Theme.BUTTON_PRIMARY);
            g2d.setStroke(new BasicStroke(2, BasicStroke.CAP_ROUND, BasicStroke.JOIN_ROUND,
                0, new float[]{6, 4}, 0));
            g2d.drawRoundRect(x + 1, y + 1, width - 2, height - 2, 6, 6);

            // Draw "drop here" indicator for category reordering or profile positioning
            if (target.type == DragDropManager.DropTarget.Type.CATEGORY_REORDER)
            {
                g2d.setStroke(new BasicStroke(3));
                g2d.setColor(Theme.BUTTON_PRIMARY);

                // Draw line at insert position
                int lineY = (target.insertIndex <= 0) ? y : y + height;
                g2d.drawLine(x + 10, lineY, x + width - 10, lineY);

                // Draw arrow heads
                int arrowSize = 6;
                g2d.fillPolygon(
                    new int[]{x + 10, x + 10 + arrowSize, x + 10},
                    new int[]{lineY - arrowSize, lineY, lineY + arrowSize},
                    3
                );
                g2d.fillPolygon(
                    new int[]{x + width - 10, x + width - 10 - arrowSize, x + width - 10},
                    new int[]{lineY - arrowSize, lineY, lineY + arrowSize},
                    3
                );
            }
            else if (target.type == DragDropManager.DropTarget.Type.CATEGORY_DROP && target.insertIndex >= 0)
            {
                // Draw insert position indicator for profile drops
                g2d.setStroke(new BasicStroke(2));
                g2d.setColor(Theme.BUTTON_PRIMARY);

                // Draw a small "insert here" line
                int lineX = x + 20;
                int lineWidth = width - 40;

                // Calculate approximate Y position for insert indicator
                // This is an approximation - the actual card positions would need to be passed
                int insertY = y + 45 + (target.insertIndex * 75); // header height + card heights
                insertY = Math.min(insertY, y + height - 5);

                g2d.drawLine(lineX, insertY, lineX + lineWidth, insertY);

                // Draw small triangles
                int arrowSize = 5;
                g2d.fillPolygon(
                    new int[]{lineX, lineX + arrowSize, lineX},
                    new int[]{insertY - arrowSize, insertY, insertY + arrowSize},
                    3
                );
                g2d.fillPolygon(
                    new int[]{lineX + lineWidth, lineX + lineWidth - arrowSize, lineX + lineWidth},
                    new int[]{insertY - arrowSize, insertY, insertY + arrowSize},
                    3
                );
            }
        }
        catch (Exception e)
        {
            // Component might not be showing
        }
    }

    private void drawDragIndicator(Graphics2D g2d)
    {
        // Simple fallback indicator
        int size = 40;
        int x = mouseLocation.x - size / 2;
        int y = mouseLocation.y - size / 2;

        g2d.setColor(new Color(Theme.BUTTON_PRIMARY.getRed(),
            Theme.BUTTON_PRIMARY.getGreen(),
            Theme.BUTTON_PRIMARY.getBlue(), 100));
        g2d.fillOval(x, y, size, size);

        g2d.setColor(Theme.BUTTON_PRIMARY);
        g2d.setStroke(new BasicStroke(2));
        g2d.drawOval(x, y, size, size);

        // Draw move icon
        g2d.setColor(Theme.TEXT_PRIMARY);
        int cx = mouseLocation.x;
        int cy = mouseLocation.y;
        int arrowLen = 8;

        // Four arrows pointing outward
        g2d.setStroke(new BasicStroke(2, BasicStroke.CAP_ROUND, BasicStroke.JOIN_ROUND));
        g2d.drawLine(cx, cy - arrowLen, cx, cy + arrowLen);
        g2d.drawLine(cx - arrowLen, cy, cx + arrowLen, cy);
    }
}

package com.mylosis.roster.ui.dnd;

import com.mylosis.roster.model.Account;
import com.mylosis.roster.ui.AccountCardPanel;

import javax.swing.*;
import java.awt.Component;
import java.awt.Container;
import java.awt.Point;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;

/**
 * Mouse listener for dragging profiles between categories.
 * Attaches to a AccountCardPanel and all its children to ensure drag works from anywhere on the card.
 * Also handles click detection to trigger profile selection and edit.
 */
public class AccountDragListener extends MouseAdapter
{
    private final DragDropManager dragManager;
    private final Account profile;
    private final AccountCardPanel card;

    private Point pressPoint = null;
    private long pressTime = 0;
    private boolean dragStarted = false;
    private static long lastClickTime = 0;
    private static Account lastClickAccount = null;

    private static final int DRAG_THRESHOLD = 10;
    private static final int CLICK_TIME_THRESHOLD = 300;
    private static final int DOUBLE_CLICK_THRESHOLD = 400;

    public AccountDragListener(DragDropManager dragManager, Account profile, AccountCardPanel card)
    {
        this.dragManager = dragManager;
        this.profile = profile;
        this.card = card;
    }

    /**
     * Attach this listener to the card and all its children recursively.
     */
    public void attachToComponent(Component component)
    {
        component.addMouseListener(this);
        component.addMouseMotionListener(this);

        if (component instanceof Container)
        {
            for (Component child : ((Container) component).getComponents())
            {
                // Don't attach to buttons (let them handle their own clicks)
                if (!(child instanceof JButton))
                {
                    attachToComponent(child);
                }
            }
        }
    }

    @Override
    public void mousePressed(MouseEvent e)
    {
        if (e.getButton() == MouseEvent.BUTTON1 && !card.isExpanded())
        {
            pressPoint = e.getLocationOnScreen();
            pressTime = System.currentTimeMillis();
            dragStarted = false;
        }
    }

    @Override
    public void mouseReleased(MouseEvent e)
    {
        if (e.getButton() != MouseEvent.BUTTON1)
        {
            return;
        }

        if (dragStarted)
        {
            dragManager.endDrag(e.getLocationOnScreen());
        }
        else if (pressPoint != null)
        {
            // This was a click, not a drag - handle it
            long duration = System.currentTimeMillis() - pressTime;
            Point current = e.getLocationOnScreen();
            int dx = Math.abs(current.x - pressPoint.x);
            int dy = Math.abs(current.y - pressPoint.y);

            if (duration < CLICK_TIME_THRESHOLD && dx < DRAG_THRESHOLD && dy < DRAG_THRESHOLD)
            {
                // Check for double-click
                long now = System.currentTimeMillis();
                if (lastClickAccount == profile && (now - lastClickTime) < DOUBLE_CLICK_THRESHOLD)
                {
                    // Double-click: expand card for inline editing
                    SwingUtilities.invokeLater(() -> card.expand());
                    lastClickTime = 0;
                    lastClickAccount = null;
                }
                else
                {
                    // Single-click: select profile (only if card not expanded)
                    lastClickTime = now;
                    lastClickAccount = profile;
                    if (!card.isExpanded())
                    {
                        dragManager.getPlugin().selectAccount(profile);
                    }
                }
            }
        }

        pressPoint = null;
        dragStarted = false;
    }

    @Override
    public void mouseDragged(MouseEvent e)
    {
        if (pressPoint == null) return;

        Point current = e.getLocationOnScreen();

        if (!dragStarted)
        {
            int dx = Math.abs(current.x - pressPoint.x);
            int dy = Math.abs(current.y - pressPoint.y);

            if (dx > DRAG_THRESHOLD || dy > DRAG_THRESHOLD)
            {
                dragStarted = true;
                dragManager.startProfileDrag(profile, card, pressPoint);
            }
        }

        if (dragStarted)
        {
            dragManager.updateDrag(current);
        }
    }
}

package com.mylosis.roster.ui.dnd;

import com.mylosis.roster.model.ProfileGroup;

import java.awt.Point;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;

/**
 * Mouse listener for dragging categories to reorder them.
 */
public class CategoryDragListener extends MouseAdapter
{
    private final DragDropManager dragManager;
    private final ProfileGroup category;

    private Point pressPoint = null;
    private boolean dragStarted = false;

    private static final int DRAG_THRESHOLD = 10;

    public CategoryDragListener(DragDropManager dragManager, ProfileGroup category)
    {
        this.dragManager = dragManager;
        this.category = category;
    }

    @Override
    public void mousePressed(MouseEvent e)
    {
        if (e.getButton() == MouseEvent.BUTTON1)
        {
            pressPoint = e.getLocationOnScreen();
            dragStarted = false;
        }
    }

    @Override
    public void mouseReleased(MouseEvent e)
    {
        if (dragStarted)
        {
            dragManager.endDrag(e.getLocationOnScreen());
        }
        pressPoint = null;
        dragStarted = false;
    }

    @Override
    public void mouseDragged(MouseEvent e)
    {
        if (pressPoint == null) return;

        Point current = e.getLocationOnScreen();

        if (!dragStarted)
        {
            int dx = Math.abs(current.x - pressPoint.x);
            int dy = Math.abs(current.y - pressPoint.y);

            if (dx > DRAG_THRESHOLD || dy > DRAG_THRESHOLD)
            {
                dragStarted = true;
                dragManager.startCategoryDrag(category, e.getComponent(), pressPoint);
            }
        }

        if (dragStarted)
        {
            dragManager.updateDrag(current);
        }
    }
}

package com.mylosis.roster.ui.dnd;

import com.mylosis.roster.RosterPlugin;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.model.ProfileGroup;
import com.mylosis.roster.ui.RosterPanel;
import lombok.extern.slf4j.Slf4j;

import java.awt.*;

/**
 * Manages drag and drop for profiles and categories.
 * Delegates drop target finding to DropTargetFinder and drop execution to DropExecutor.
 */
@Slf4j
public class DragDropManager
{
    private final RosterPlugin plugin;
    private final DragOverlay overlay;
    private final DropTargetFinder targetFinder;
    private final DropExecutor dropExecutor;

    // Drag state
    private boolean isDragging = false;
    private DragType dragType = null;
    private Account draggedAccount = null;
    private ProfileGroup draggedCategory = null;
    private Component dragSource = null;
    private Point dragStartPoint = null;
    private Point currentDragPoint = null;
    private DropTarget currentDropTarget = null;

    public enum DragType
    {
        PROFILE,
        CATEGORY
    }

    public static class DropTarget
    {
        public enum Type { CATEGORY_DROP, UNCATEGORIZED, CATEGORY_REORDER }

        public final Type type;
        public final String groupId;
        public final Rectangle bounds;
        public final int insertIndex;

        public DropTarget(Type type, String groupId, Rectangle bounds)
        {
            this(type, groupId, bounds, -1);
        }

        public DropTarget(Type type, String groupId, Rectangle bounds, int insertIndex)
        {
            this.type = type;
            this.groupId = groupId;
            this.bounds = bounds;
            this.insertIndex = insertIndex;
        }
    }

    public DragDropManager(RosterPlugin plugin, RosterPanel panel)
    {
        this.plugin = plugin;
        this.overlay = new DragOverlay(this);
        this.targetFinder = new DropTargetFinder(panel);
        this.dropExecutor = new DropExecutor(plugin, panel);
    }

    public DragOverlay getOverlay()
    {
        return overlay;
    }

    public RosterPlugin getPlugin()
    {
        return plugin;
    }

    public void startProfileDrag(Account profile, Component source, Point screenPoint)
    {
        if (isDragging) return;
        isDragging = true;
        dragType = DragType.PROFILE;
        draggedAccount = profile;
        dragSource = source;
        dragStartPoint = screenPoint;
        currentDragPoint = screenPoint;
        overlay.setDragImage(source);
        overlay.setMouseLocation(screenPoint);
        overlay.setVisible(true);
        log.debug("Started dragging account: {}", profile.getDisplayName());
    }

    public void startCategoryDrag(ProfileGroup category, Component source, Point screenPoint)
    {
        if (isDragging) return;
        isDragging = true;
        dragType = DragType.CATEGORY;
        draggedCategory = category;
        dragSource = source;
        dragStartPoint = screenPoint;
        currentDragPoint = screenPoint;
        overlay.setDragImage(source);
        overlay.setMouseLocation(screenPoint);
        overlay.setVisible(true);
        log.debug("Started dragging category: {}", category.getName());
    }

    public void updateDrag(Point screenPoint)
    {
        if (!isDragging) return;
        currentDragPoint = screenPoint;
        currentDropTarget = findDropTarget(screenPoint);
        overlay.setMouseLocation(screenPoint);
        overlay.repaint();
    }

    public void endDrag(Point screenPoint)
    {
        if (!isDragging) return;
        currentDragPoint = screenPoint;
        DropTarget target = findDropTarget(screenPoint);

        if (target != null)
        {
            performDrop(target);
        }

        resetDragState();
    }

    public void cancelDrag()
    {
        resetDragState();
    }

    public boolean isDragging()
    {
        return isDragging;
    }

    public DropTarget getCurrentDropTarget()
    {
        return currentDropTarget;
    }

    public Account getDraggedProfile()
    {
        return draggedAccount;
    }

    public ProfileGroup getDraggedCategory()
    {
        return draggedCategory;
    }

    private DropTarget findDropTarget(Point screenPoint)
    {
        if (dragType == DragType.PROFILE)
        {
            return targetFinder.findForProfile(screenPoint, draggedAccount);
        }
        else if (dragType == DragType.CATEGORY)
        {
            return targetFinder.findForCategory(screenPoint, draggedCategory);
        }
        return null;
    }

    private void performDrop(DropTarget target)
    {
        if (dragType == DragType.PROFILE && draggedAccount != null)
        {
            dropExecutor.executeProfileDrop(target, draggedAccount);
        }
        else if (dragType == DragType.CATEGORY && draggedCategory != null)
        {
            dropExecutor.executeCategoryDrop(target, draggedCategory);
        }
    }

    private void resetDragState()
    {
        isDragging = false;
        dragType = null;
        draggedAccount = null;
        draggedCategory = null;
        dragSource = null;
        dragStartPoint = null;
        currentDragPoint = null;
        currentDropTarget = null;
        overlay.clearDragImage();
        overlay.setVisible(false);
        overlay.repaint();
    }
}

package com.mylosis.roster;

import com.google.gson.Gson;
import com.google.inject.Provides;
import com.mylosis.roster.model.Account;
import com.mylosis.roster.storage.ImportExportService;
import com.mylosis.roster.storage.AccountStorage;
import com.mylosis.roster.ui.RosterPanel;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;

import net.runelite.client.events.ConfigChanged;
import net.runelite.api.events.GameStateChanged;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.components.colorpicker.ColorPickerManager;
import net.runelite.client.ui.NavigationButton;
import net.runelite.client.util.ImageUtil;

import javax.inject.Inject;
import javax.swing.SwingUtilities;
import java.awt.image.BufferedImage;

@Slf4j
@PluginDescriptor(
    name = "Roster",
    description = "Enhanced account management for OSRS with groups, import/export, and drag-and-drop",
    tags = {"account", "roster", "login", "management", "utility"}
)
public class RosterPlugin extends Plugin
{
    private static final String ICON_PATH = "/com/mylosis/roster/icon.png";

    @Inject
    private Client client;

    @Inject
    private ClientThread clientThread;

    @Inject
    private ClientToolbar clientToolbar;

    @Inject
    @Getter
    private ColorPickerManager colorPickerManager;

    @Inject
    @Getter
    private RosterConfig config;

    @Inject
    @Getter
    private AccountStorage accountStorage;

    @Inject
    @Getter
    private ImportExportService importExportService;

    @Inject
    @Getter
    private ConfigManager configManager;

    @Inject
    @Getter
    private Gson gson;

    private RosterPanel panel;
    private NavigationButton navButton;

    @Getter
    private volatile String loggedInDisplayName;

    @Getter
    private volatile String selectedAccountId;

    @Override
    protected void startUp() throws Exception
    {
        log.info("Roster started");

        panel = new RosterPanel(this);

        BufferedImage icon = loadIcon();

        navButton = NavigationButton.builder()
            .tooltip("Roster")
            .icon(icon)
            .priority(5)
            .panel(panel)
            .build();

        clientToolbar.addNavigation(navButton);
    }

    @Override
    protected void shutDown() throws Exception
    {
        log.info("Roster stopped");
        clientToolbar.removeNavigation(navButton);
        panel = null;
        navButton = null;
    }

    private BufferedImage loadIcon()
    {
        try
        {
            return ImageUtil.loadImageResource(getClass(), ICON_PATH);
        }
        catch (Exception e)
        {
            log.warn("Failed to load plugin icon, using default");
            BufferedImage defaultIcon = new BufferedImage(16, 16, BufferedImage.TYPE_INT_ARGB);
            java.awt.Graphics2D g = defaultIcon.createGraphics();
            g.setRenderingHint(java.awt.RenderingHints.KEY_ANTIALIASING, java.awt.RenderingHints.VALUE_ANTIALIAS_ON);

            java.awt.Color iconColor = new java.awt.Color(200, 200, 200);
            g.setColor(iconColor);

            g.fillOval(1, 3, 5, 5);
            g.fillArc(-1, 8, 8, 8, 0, 180);
            g.fillOval(7, 2, 6, 6);
            g.fillArc(5, 8, 10, 10, 0, 180);

            g.dispose();
            return defaultIcon;
        }
    }

    @Subscribe
    public void onGameStateChanged(GameStateChanged event)
    {
        if (event.getGameState() == GameState.LOGGED_IN)
        {
            // Player object may not be available immediately — retries on next game tick
            clientThread.invokeLater(() -> {
                if (client.getLocalPlayer() == null || client.getLocalPlayer().getName() == null)
                {
                    return false;
                }
                loggedInDisplayName = client.getLocalPlayer().getName();
                log.debug("Detected logged-in player: {}", loggedInDisplayName);
                SwingUtilities.invokeLater(() -> {
                    if (panel != null) panel.rebuild();
                });
                return true;
            });
        }
        else if (event.getGameState() == GameState.LOGIN_SCREEN
            || event.getGameState() == GameState.CONNECTION_LOST)
        {
            loggedInDisplayName = null;
            SwingUtilities.invokeLater(() -> {
                if (panel != null) panel.rebuild();
            });
        }
    }

    @Subscribe
    public void onConfigChanged(ConfigChanged event)
    {
        if (!RosterConfig.CONFIG_GROUP.equals(event.getGroup()))
        {
            return;
        }

        if (panel != null)
        {
            SwingUtilities.invokeLater(() -> panel.rebuild());
        }
    }

    public void selectAccount(Account profile)
    {
        if (profile == null)
        {
            return;
        }

        clientThread.invokeLater(() -> {
            if (client.getGameState() != GameState.LOGIN_SCREEN)
            {
                log.debug("Not on login screen, cannot select account");
                return;
            }

            client.setUsername(profile.getUsername());
            selectedAccountId = profile.getId();

            log.info("Selected account: {}", profile.getDisplayName());

            if (panel != null)
            {
                SwingUtilities.invokeLater(() -> panel.rebuild());
            }
        });
    }

    public RosterPanel getPanel()
    {
        return panel;
    }

    @Provides
    RosterConfig provideConfig(ConfigManager configManager)
    {
        return configManager.getConfig(RosterConfig.class);
    }
}

