            panelComponent.setBackgroundColor(ResourceAreaNotifierPlugin.getBoxColorPrimary());
        }

        setPosition(OverlayPosition.BOTTOM_LEFT);
        setLayer(OverlayLayer.ABOVE_WIDGETS); //Renders under the right-click menu
