                    plugin.config.UserData.PlannedTasks.remove(taskData.GUID);
                    plugin.config.UserData.PlannedTasks.put(taskData.GUID, new TaskSortData(Integer.valueOf(((TextField)(e.getSource())).getText()), taskData.bIsCustomTask));
