            for (int i = 6; i < parts.length; i++) {
                rest.append(parts[i]);
                if (i < parts.length - 1) rest.append(" ");
            }

            System.out.println("this.addTransport(" + p1 + ", " + p2 + ", \"" + rest.toString() + "\");");
        }
    }
