package com.killClips.video;

import com.killClips.KillClipsConfig;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.ChatMessageType;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.widgets.Widget;
import net.runelite.api.gameval.InterfaceID;
import net.runelite.client.chat.ChatMessageManager;
import net.runelite.client.chat.QueuedMessage;
import net.runelite.client.ui.DrawManager;
import net.runelite.client.util.ImageUtil;

import javax.imageio.IIOImage;
import javax.imageio.ImageIO;
import javax.imageio.ImageWriteParam;
import javax.imageio.ImageWriter;
import javax.imageio.stream.ImageOutputStream;
import javax.inject.Inject;
import javax.inject.Singleton;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;

// Core recording engine: maintains a rolling circular buffer of JPEG-compressed frames
// in memory and, on demand, extracts a time-windowed slice into an AVI container.
@Slf4j
@Singleton
public class VideoRecorder
{
    // Absolute upper bounds
    private static final int CEILING_DURATION_SEC = 60;
    private static final int CEILING_FPS = 30;
    private static final int RING_CAPACITY = CEILING_DURATION_SEC * CEILING_FPS;

    // Post-event capture: how long to keep recording after the triggering event
    private static final int DEFAULT_POST_EVENT_MS = 4000;

    // Encoding pipeline backpressure
    private static final int ENCODE_CONCURRENCY_LIMIT = 4;

    // How often we re-evaluate whether login/bank-pin widgets are visible
    private static final long SENSITIVE_RECHECK_MS = 500;

    // Absolute maximum output resolution
    private static final int ABS_CAP_W = 1920;
    private static final int ABS_CAP_H = 1080;

    // Frame deduplication: reuse previous JPEG when the new encode is byte-identical.
    // Only catches truly static frames (menus, afk in empty room) — never collapses real motion.
    private volatile byte[] previousFrameJpeg = null;
    private static final int DEDUP_SIZE_TOLERANCE = 2048;

    // Box-blur kernel radius for sensitive-content redaction
    private static final int REDACT_RADIUS = 15;

    // -- Injected dependencies --
    private final DrawManager drawMgr;
    private final KillClipsConfig cfg;
    private final Client gameClient;
    private final ChatMessageManager chatMgr;

    // -- Thread pools --
    private ScheduledExecutorService timer;
    private ExecutorService encoderPool;
    private ExecutorService serializerPool;

    // -- Shutdown / lifecycle tracking --
    private final AtomicBoolean shutDown = new AtomicBoolean(false);
    // Futures for scheduled assembleClip tasks so we can cancel them on stop
    private final java.util.Set<java.util.concurrent.ScheduledFuture<?>> pendingAssembly =
        java.util.Collections.newSetFromMap(new java.util.concurrent.ConcurrentHashMap<>());

    // -- RGBA buffer pool (reused by AsyncFrameCapture instead of per-frame allocation) --
    private final java.util.concurrent.ConcurrentLinkedQueue<byte[]> rgbaPool =
        new java.util.concurrent.ConcurrentLinkedQueue<>();
    private static final int RGBA_POOL_MAX = 4;
    private volatile int rgbaPoolSize = 0;

    // -- Ring buffer --
    private final byte[][] ringJpeg = new byte[RING_CAPACITY][];
    private final long[] ringTs = new long[RING_CAPACITY];
    private final boolean[] ringBlurFlag = new boolean[RING_CAPACITY];
    private final AtomicInteger ringHead = new AtomicInteger(0);
    private final AtomicInteger ringSize = new AtomicInteger(0);
    private final Object ringLock = new Object();

    // -- State flags --
    private final AtomicBoolean recording = new AtomicBoolean(false);
    private final AtomicBoolean postEventActive = new AtomicBoolean(false);
    private final AtomicInteger inflightEncodes = new AtomicInteger(0);

    // -- Sensitive content cache --
    private final AtomicBoolean cachedSensitive = new AtomicBoolean(false);
    private final AtomicLong sensitiveCheckedAt = new AtomicLong(0);

    // -- Async GPU capture --
    private AsyncFrameCapture gpuCapture;
    private volatile int activeFps = 0;
    private volatile float activeJpegQuality = 0.5f;
    private volatile boolean noGpu = false;
    private volatile boolean gpuMsgSent = false;

    @Inject
    public VideoRecorder(DrawManager drawMgr, KillClipsConfig cfg, Client gameClient, ChatMessageManager chatMgr)
    {
        this.drawMgr = drawMgr;
        this.cfg = cfg;
        this.gameClient = gameClient;
        this.chatMgr = chatMgr;

        initExecutors();
        log.debug("Recorder ready (ring capacity={})", computeEffectiveCapacity());
    }

    private void initExecutors()
    {
        this.timer = Executors.newScheduledThreadPool(1, r ->
        {
            Thread th = new Thread(r, "KillClips-Scheduler");
            th.setDaemon(true);
            return th;
        });
        this.encoderPool = Executors.newFixedThreadPool(2, r ->
        {
            Thread th = new Thread(r, "KillClips-Encoder");
            th.setDaemon(true);
            return th;
        });
        this.serializerPool = Executors.newSingleThreadExecutor(r ->
        {
            Thread th = new Thread(r, "KillClips-Serializer");
            th.setDaemon(true);
            return th;
        });
    }

    // Full teardown: cancel pending work, shut down executors, release the buffer pool.
    // Called from the plugin's shutDown hook. Idempotent.
    public void shutdown()
    {
        if (shutDown.getAndSet(true))
        {
            return;
        }
        stopRecording();
        pendingAssembly.forEach(f -> f.cancel(false));
        pendingAssembly.clear();

        safeShutdown(timer);
        safeShutdown(encoderPool);
        safeShutdown(serializerPool);

        rgbaPool.clear();
        rgbaPoolSize = 0;
        log.debug("VideoRecorder shut down");
    }

    private static void safeShutdown(ExecutorService es)
    {
        if (es == null) return;
        try
        {
            es.shutdown();
            if (!es.awaitTermination(2, TimeUnit.SECONDS))
            {
                es.shutdownNow();
            }
        }
        catch (InterruptedException ex)
        {
            es.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }

    // Acquire a reusable RGBA buffer sized exactly to `bytes`. Called from the GL thread —
    // avoids allocating up to 8MB per frame at 1080p/30fps (~240MB/sec of GC pressure).
    public byte[] acquireRgbaBuffer(int bytes)
    {
        byte[] b = rgbaPool.poll();
        if (b != null)
        {
            rgbaPoolSize--;
            if (b.length == bytes)
            {
                return b;
            }
            // Size mismatch (viewport changed) — drop this one, allocate fresh
        }
        return new byte[bytes];
    }

    // Return a buffer to the pool once the encoder is finished with it.
    void releaseRgbaBuffer(byte[] buf)
    {
        if (buf == null) return;
        if (rgbaPoolSize < RGBA_POOL_MAX)
        {
            rgbaPool.offer(buf);
            rgbaPoolSize++;
        }
    }

    // ------------------------------------------------------------------
    //  Effective config helpers
    // ------------------------------------------------------------------

    private int computeEffectiveCapacity()
    {
        int sec = clampDuration();
        int fps = cfg.videoFps().getFps();
        return sec * fps;
    }

    private int computeEffectiveDurationMs()
    {
        return clampDuration() * 1000;
    }

    private int clampDuration()
    {
        return Math.max(10, Math.min(CEILING_DURATION_SEC, cfg.recordingDuration()));
    }

    // ------------------------------------------------------------------
    //  Package-level API consumed by AsyncFrameCapture
    // ------------------------------------------------------------------

    boolean isCurrentlyRecording()
    {
        return recording.get();
    }

    int getCaptureFps()
    {
        return activeFps;
    }

    boolean canAcceptFrame()
    {
        return inflightEncodes.get() < ENCODE_CONCURRENCY_LIMIT;
    }

    // Accepts raw RGBA pixels from the PBO readback and schedules encoding.
    // `rgbaArray` is a byte[] owned by the buffer pool — we return it after use.
    void submitCapturedFrame(byte[] rgbaArray, int w, int h)
    {
        if (shutDown.get() || !recording.get())
        {
            releaseRgbaBuffer(rgbaArray);
            return;
        }
        long now = System.currentTimeMillis();
        boolean redact = fetchSensitiveFlag(now);

        inflightEncodes.incrementAndGet();
        try
        {
            encoderPool.submit(() ->
            {
                try
                {
                    processRawFrame(rgbaArray, w, h, now, redact);
                }
                catch (Exception ex)
                {
                    log.error("Frame encoding failed", ex);
                }
                finally
                {
                    releaseRgbaBuffer(rgbaArray);
                    inflightEncodes.decrementAndGet();
                }
            });
        }
        catch (java.util.concurrent.RejectedExecutionException ex)
        {
            // Pool was shut down between our check and submit; drop the frame
            releaseRgbaBuffer(rgbaArray);
            inflightEncodes.decrementAndGet();
        }
    }

    // ------------------------------------------------------------------
    //  Sensitive content detection
    // ------------------------------------------------------------------

    private boolean querySensitiveWidgets()
    {
        try
        {
            GameState gs = gameClient.getGameState();
            if (gs == GameState.LOGIN_SCREEN
                || gs == GameState.LOGIN_SCREEN_AUTHENTICATOR
                || gs == GameState.LOGGING_IN)
            {
                return true;
            }

            Widget pinPad = gameClient.getWidget(InterfaceID.BANKPIN_KEYPAD, 0);
            if (pinPad != null && !pinPad.isHidden())
            {
                return true;
            }

            Widget pinSettings = gameClient.getWidget(InterfaceID.BANKPIN_SETTINGS, 0);
            if (pinSettings != null && !pinSettings.isHidden())
            {
                return true;
            }
        }
        catch (Exception ex)
        {
            log.debug("Widget check error: {}", ex.getMessage());
        }
        return false;
    }

    // Returns a cached result, refreshing at most every SENSITIVE_RECHECK_MS
    private boolean fetchSensitiveFlag(long nowMs)
    {
        long prev = sensitiveCheckedAt.get();
        if (nowMs - prev >= SENSITIVE_RECHECK_MS)
        {
            if (sensitiveCheckedAt.compareAndSet(prev, nowMs))
            {
                boolean vis = querySensitiveWidgets();
                cachedSensitive.set(vis);
                return vis;
            }
        }
        return cachedSensitive.get();
    }

    // ------------------------------------------------------------------
    //  Blur / redaction
    // ------------------------------------------------------------------

    private BufferedImage redactImage(BufferedImage src)
    {
        int w = src.getWidth();
        int h = src.getHeight();

        BufferedImage out = new BufferedImage(w, h, BufferedImage.TYPE_INT_RGB);
        Graphics2D g2 = out.createGraphics();
        g2.drawImage(src, 0, 0, null);
        g2.dispose();

        // Three passes of box blur to thoroughly obscure
        for (int p = 0; p < 3; p++)
        {
            out = singlePassBoxBlur(out, REDACT_RADIUS);
        }

        // Dark overlay + warning text
        g2 = out.createGraphics();
        g2.setColor(new Color(0, 0, 0, 100));
        g2.fillRect(0, 0, w, h);
        g2.setColor(Color.WHITE);
        g2.setFont(new Font("Arial", Font.BOLD, 24));
        FontMetrics fm = g2.getFontMetrics();
        String notice = "SENSITIVE CONTENT HIDDEN";
        int tx = (w - fm.stringWidth(notice)) / 2;
        int ty = h / 2;
        g2.drawString(notice, tx, ty);
        g2.dispose();

        return out;
    }

    // Horizontal then vertical averaging
    private BufferedImage singlePassBoxBlur(BufferedImage src, int rad)
    {
        int w = src.getWidth();
        int h = src.getHeight();
        int[] px = new int[w * h];
        int[] tmp = new int[w * h];
        src.getRGB(0, 0, w, h, px, 0, w);

        // Horizontal
        for (int row = 0; row < h; row++)
        {
            for (int col = 0; col < w; col++)
            {
                int rAcc = 0, gAcc = 0, bAcc = 0, n = 0;
                for (int dx = -rad; dx <= rad; dx++)
                {
                    int sx = Math.max(0, Math.min(w - 1, col + dx));
                    int c = px[row * w + sx];
                    rAcc += (c >> 16) & 0xFF;
                    gAcc += (c >> 8) & 0xFF;
                    bAcc += c & 0xFF;
                    n++;
                }
                tmp[row * w + col] = (0xFF << 24)
                    | ((rAcc / n) << 16)
                    | ((gAcc / n) << 8)
                    | (bAcc / n);
            }
        }

        // Vertical
        for (int row = 0; row < h; row++)
        {
            for (int col = 0; col < w; col++)
            {
                int rAcc = 0, gAcc = 0, bAcc = 0, n = 0;
                for (int dy = -rad; dy <= rad; dy++)
                {
                    int sy = Math.max(0, Math.min(h - 1, row + dy));
                    int c = tmp[sy * w + col];
                    rAcc += (c >> 16) & 0xFF;
                    gAcc += (c >> 8) & 0xFF;
                    bAcc += c & 0xFF;
                    n++;
                }
                px[row * w + col] = (0xFF << 24)
                    | ((rAcc / n) << 16)
                    | ((gAcc / n) << 8)
                    | (bAcc / n);
            }
        }

        BufferedImage result = new BufferedImage(w, h, BufferedImage.TYPE_INT_RGB);
        result.setRGB(0, 0, w, h, px, 0, w);
        return result;
    }

    // ------------------------------------------------------------------
    //  Recording lifecycle
    // ------------------------------------------------------------------

    public void startRecording()
    {
        if (shutDown.get())
        {
            // Plugin was re-enabled after a full shutdown — bring executors back
            shutDown.set(false);
            initExecutors();
        }
        if (recording.getAndSet(true))
        {
            return;
        }

        resetRing();
        previousFrameJpeg = null;
        noGpu = false;
        gpuMsgSent = false;

        activeFps = cfg.videoFps().getFps();
        activeJpegQuality = cfg.videoResolution().getJpegQuality();
        log.debug("Recording at {} fps, JPEG quality {}%", activeFps, (int) (activeJpegQuality * 100));

        gpuCapture = new AsyncFrameCapture(drawMgr, this, this::handleGpuMissing);
        gpuCapture.start();
    }

    public void stopRecording()
    {
        if (!recording.getAndSet(false))
        {
            return;
        }

        // Cancel any pending scheduled assembleClip tasks so they don't fire after shutdown
        pendingAssembly.forEach(f -> f.cancel(false));
        pendingAssembly.clear();
        postEventActive.set(false);

        synchronized (ringLock)
        {
            if (gpuCapture != null)
            {
                gpuCapture.stop();
                gpuCapture = null;
            }
        }

        resetRing();
        previousFrameJpeg = null;
        activeFps = 0;
    }

    private synchronized void handleGpuMissing()
    {
        log.debug("GPU unavailable -- disabling video capture");
        if (gpuCapture != null)
        {
            gpuCapture.stop();
            gpuCapture = null;
        }
        recording.set(false);
        activeFps = 0;
        noGpu = true;
    }

    // Detects quality/mode changes and adjusts the live capture accordingly.
    // Synchronized because gpuCapture may be replaced, and the GL thread concurrently
    // calls back via submitCapturedFrame.
    public synchronized void updateCaptureRateIfNeeded()
    {
        if (shutDown.get() || postEventActive.get() || noGpu)
        {
            return;
        }

        float wantedQuality = cfg.videoResolution().getJpegQuality();
        if (wantedQuality != activeJpegQuality)
        {
            activeJpegQuality = wantedQuality;
        }

        int wantedFps = cfg.videoFps().getFps();
        if (wantedFps != activeFps)
        {
            log.debug("FPS change: {} -> {}", activeFps, wantedFps);
            resetRing();
            activeFps = wantedFps;

            if (gpuCapture == null)
            {
                gpuCapture = new AsyncFrameCapture(drawMgr, this, this::handleGpuMissing);
                gpuCapture.start();
            }
            recording.set(true);
        }
    }

    // ------------------------------------------------------------------
    //  Event capture API
    // ------------------------------------------------------------------

    public void captureEventVideo(VideoCallback cb)
    {
        captureEventVideo(cb, null, DEFAULT_POST_EVENT_MS);
    }

    public void captureEventVideo(VideoCallback cb, Runnable onEncodingStart)
    {
        captureEventVideo(cb, onEncodingStart, DEFAULT_POST_EVENT_MS);
    }

    public void captureEventVideo(VideoCallback cb, Runnable onEncodingStart, int postMs)
    {
        if (!recording.get())
        {
            // One-time warning when GPU plugin is not loaded
            if (noGpu && !gpuMsgSent)
            {
                gpuMsgSent = true;
                if (chatMgr != null)
                {
                    chatMgr.queue(QueuedMessage.builder()
                        .type(ChatMessageType.GAMEMESSAGE)
                        .runeLiteFormattedMessage("<col=ff9040>[Kill Clips] GPU plugin required for video. Using screenshot-only mode.</col>")
                        .build());
                }
            }
            if (onEncodingStart != null)
            {
                onEncodingStart.run();
            }
            captureScreenshotOnly(cb);
            return;
        }

        // If another capture is already in its post-event window, fall back to screenshot
        if (postEventActive.get())
        {
            if (onEncodingStart != null)
            {
                onEncodingStart.run();
            }
            captureScreenshotOnly(cb);
            return;
        }

        int totalMs = computeEffectiveDurationMs();
        int preMs = Math.max(1000, totalMs - postMs);

        postEventActive.set(true);

        long eventTime = System.currentTimeMillis();
        long windowStart = eventTime - preMs;
        long windowEnd = eventTime + postMs;

        try
        {
            final java.util.concurrent.ScheduledFuture<?>[] holder = new java.util.concurrent.ScheduledFuture<?>[1];
            holder[0] = timer.schedule(() ->
            {
                pendingAssembly.remove(holder[0]);
                postEventActive.set(false);
                // Bail out if the plugin was stopped during the post-event wait
                if (shutDown.get())
                {
                    return;
                }
                try
                {
                    if (onEncodingStart != null)
                    {
                        onEncodingStart.run();
                    }
                    assembleClip(cb, windowStart, windowEnd);
                }
                catch (Exception ex)
                {
                    log.error("Post-event assembly failed", ex);
                }
            }, postMs, TimeUnit.MILLISECONDS);
            pendingAssembly.add(holder[0]);
        }
        catch (java.util.concurrent.RejectedExecutionException ex)
        {
            postEventActive.set(false);
            log.debug("Scheduler rejected post-event task (shutdown in progress)");
        }
    }

    // Grabs a single frame for events that do not need video
    public void captureScreenshotOnly(VideoCallback cb)
    {
        if (shutDown.get())
        {
            return;
        }
        boolean redact = querySensitiveWidgets();

        drawMgr.requestNextFrameListener(img ->
        {
            if (shutDown.get())
            {
                return;
            }
            try
            {
                encoderPool.submit(() ->
                {
                    try
                    {
                        BufferedImage shot = ImageUtil.bufferedImageFromImage(img);
                        if (redact)
                        {
                            shot = redactImage(shot);
                        }
                        String b64 = bufferedImageToPngBase64(shot);
                        safeInvoke(cb, b64, null);
                    }
                    catch (Exception ex)
                    {
                        log.error("Screenshot capture failed", ex);
                        safeInvoke(cb, null, null);
                    }
                });
            }
            catch (java.util.concurrent.RejectedExecutionException rex)
            {
                // Pool shut down
            }
        });
    }

    // ------------------------------------------------------------------
    //  Frame encoding pipeline
    // ------------------------------------------------------------------

    private void processRawFrame(byte[] rgba, int w, int h, long ts, boolean redact)
    {
        try
        {
            if (rgba == null || w <= 0 || h <= 0)
            {
                return;
            }
            BufferedImage bimg = rgbaToBufferedImage(rgba, w, h);
            bimg = constrainResolution(bimg, w, h);
            byte[] jpeg = compressJpeg(bimg);

            // Byte-exact dedup: only reuse if the new JPEG encode is identical to the previous one.
            if (!redact && isDuplicateFrame(jpeg))
            {
                pushToRing(previousFrameJpeg, ts, false);
            }
            else
            {
                previousFrameJpeg = jpeg;
                pushToRing(jpeg, ts, redact);
            }
        }
        catch (IOException ex)
        {
            log.error("Frame processing failed at ts={}", ts, ex);
        }
    }

    private boolean isDuplicateFrame(byte[] jpeg)
    {
        byte[] prev = previousFrameJpeg;
        if (prev == null || jpeg == null)
        {
            return false;
        }
        if (Math.abs(jpeg.length - prev.length) > DEDUP_SIZE_TOLERANCE)
        {
            return false;
        }
        return java.util.Arrays.equals(jpeg, prev);
    }

    // Converts bottom-up RGBA pixels (OpenGL convention) into a top-down BufferedImage
    private BufferedImage rgbaToBufferedImage(byte[] rgba, int w, int h)
    {
        BufferedImage bimg = new BufferedImage(w, h, BufferedImage.TYPE_INT_RGB);
        int stride = w * 4;
        int[] row = new int[w];

        for (int destY = 0; destY < h; destY++)
        {
            int srcY = h - 1 - destY;
            int rowBase = srcY * stride;
            for (int x = 0; x < w; x++)
            {
                int off = rowBase + x * 4;
                int red = rgba[off] & 0xFF;
                int grn = rgba[off + 1] & 0xFF;
                int blu = rgba[off + 2] & 0xFF;
                row[x] = (red << 16) | (grn << 8) | blu;
            }
            bimg.setRGB(0, destY, w, 1, row, 0, w);
        }
        return bimg;
    }

    // Downscales to the resolution cap based on quality preset
    private BufferedImage constrainResolution(Image src, int srcW, int srcH)
    {
        int capH = cfg.videoResolution().getMaxHeight();
        int capW = (int) (capH * 16.0 / 9.0);

        // Also enforce absolute maximum
        capW = Math.min(capW, ABS_CAP_W);
        capH = Math.min(capH, ABS_CAP_H);

        int dstW = srcW;
        int dstH = srcH;
        if (srcW > capW || srcH > capH)
        {
            double ratio = Math.min((double) capW / srcW, (double) capH / srcH);
            dstW = (int) (srcW * ratio);
            dstH = (int) (srcH * ratio);
        }
        BufferedImage out = new BufferedImage(dstW, dstH, BufferedImage.TYPE_INT_RGB);
        Graphics2D g2 = out.createGraphics();
        g2.setRenderingHint(RenderingHints.KEY_INTERPOLATION, RenderingHints.VALUE_INTERPOLATION_BILINEAR);
        g2.drawImage(src, 0, 0, dstW, dstH, null);
        g2.dispose();
        return out;
    }

    private byte[] compressJpeg(BufferedImage bimg) throws IOException
    {
        ByteArrayOutputStream buf = new ByteArrayOutputStream(30_000);
        ImageWriter writer = ImageIO.getImageWritersByFormatName("jpg").next();
        ImageWriteParam params = writer.getDefaultWriteParam();
        params.setCompressionMode(ImageWriteParam.MODE_EXPLICIT);
        params.setCompressionQuality(activeJpegQuality);

        ImageOutputStream ios = ImageIO.createImageOutputStream(buf);
        writer.setOutput(ios);
        writer.write(null, new IIOImage(bimg, null, null), params);
        writer.dispose();
        ios.close();
        return buf.toByteArray();
    }

    // ------------------------------------------------------------------
    //  Ring buffer operations
    // ------------------------------------------------------------------

    private void pushToRing(byte[] jpeg, long ts, boolean blur)
    {
        synchronized (ringLock)
        {
            int cap = computeEffectiveCapacity();
            int slot = ringHead.getAndIncrement() % RING_CAPACITY;
            ringJpeg[slot] = jpeg;
            ringTs[slot] = ts;
            ringBlurFlag[slot] = blur;

            int sz = ringSize.get();
            if (sz < cap)
            {
                ringSize.incrementAndGet();
            }
            else
            {
                // Evict the oldest entry beyond our effective window
                int oldSlot = (ringHead.get() - cap - 1 + RING_CAPACITY) % RING_CAPACITY;
                ringJpeg[oldSlot] = null;
            }
        }
    }

    private void resetRing()
    {
        synchronized (ringLock)
        {
            for (int i = 0; i < RING_CAPACITY; i++)
            {
                ringJpeg[i] = null;
                ringTs[i] = 0;
                ringBlurFlag[i] = false;
            }
            ringHead.set(0);
            ringSize.set(0);
        }
    }

    // ------------------------------------------------------------------
    //  Clip assembly
    // ------------------------------------------------------------------

    private void assembleClip(VideoCallback cb, long tStart, long tEnd)
    {
        if (shutDown.get())
        {
            return;
        }
        boolean redact = querySensitiveWidgets();

        drawMgr.requestNextFrameListener(img ->
        {
            if (shutDown.get())
            {
                return;
            }
            try
            {
                encoderPool.submit(() ->
                {
                    try
                    {
                        BufferedImage shot = ImageUtil.bufferedImageFromImage(img);
                        if (redact)
                        {
                            shot = redactImage(shot);
                        }
                        String screenshotB64 = bufferedImageToPngBase64(shot);

                        FrameBatch batch = extractFrames(tStart, tEnd);
                        if (batch == null || batch.jpegList.isEmpty())
                        {
                            safeInvoke(cb, screenshotB64, null);
                            return;
                        }

                        try
                        {
                            serializerPool.submit(() ->
                            {
                                try
                                {
                                    byte[] video = framesToVideoBytes(batch.jpegList);
                                    // Free the frame list before invoking the callback
                                    // so its byte[] references become collectible
                                    batch.jpegList = null;
                                    safeInvoke(cb, screenshotB64, video);
                                }
                                catch (Exception ex)
                                {
                                    log.error("AVI serialization failed", ex);
                                    safeInvoke(cb, screenshotB64, null);
                                }
                            });
                        }
                        catch (java.util.concurrent.RejectedExecutionException rex)
                        {
                            safeInvoke(cb, screenshotB64, null);
                        }
                    }
                    catch (Exception ex)
                    {
                        log.error("Clip assembly failed", ex);
                        safeInvoke(cb, null, null);
                    }
                });
            }
            catch (java.util.concurrent.RejectedExecutionException rex)
            {
                // Encoder pool is shut down; nothing we can do
            }
        });
    }

    private void safeInvoke(VideoCallback cb, String screenshotB64, byte[] video)
    {
        if (cb == null || shutDown.get())
        {
            return;
        }
        try
        {
            cb.onComplete(screenshotB64, video);
        }
        catch (Exception ex)
        {
            log.error("VideoCallback threw", ex);
        }
    }

    // Snapshot + apply deferred blur for frames in the time window
    private FrameBatch extractFrames(long tStart, long tEnd)
    {
        List<PendingFrame> pending = new ArrayList<>();

        synchronized (ringLock)
        {
            int sz = ringSize.get();
            int head = ringHead.get() % RING_CAPACITY;
            for (int i = 0; i < sz; i++)
            {
                int slot = (head - sz + i + RING_CAPACITY) % RING_CAPACITY;
                long ts = ringTs[slot];
                byte[] data = ringJpeg[slot];
                boolean needsBlur = ringBlurFlag[slot];
                if (ts >= tStart && ts <= tEnd && data != null)
                {
                    pending.add(new PendingFrame(data, needsBlur));
                }
            }
        }

        List<byte[]> finalFrames = new ArrayList<>();
        for (PendingFrame pf : pending)
        {
            byte[] frameData = pf.jpeg;
            if (pf.blur)
            {
                try
                {
                    BufferedImage decoded = ImageIO.read(new ByteArrayInputStream(frameData));
                    if (decoded != null)
                    {
                        BufferedImage blurred = redactImage(decoded);
                        ByteArrayOutputStream bos = new ByteArrayOutputStream();
                        ImageIO.write(blurred, "jpg", bos);
                        frameData = bos.toByteArray();
                    }
                }
                catch (IOException ex)
                {
                    log.error("Deferred blur application failed", ex);
                }
            }
            finalFrames.add(frameData);
        }

        if (finalFrames.isEmpty())
        {
            return null;
        }
        FrameBatch batch = new FrameBatch();
        batch.jpegList = finalFrames;
        return batch;
    }

    private static class FrameBatch
    {
        List<byte[]> jpegList;
    }

    private static class PendingFrame
    {
        final byte[] jpeg;
        final boolean blur;

        PendingFrame(byte[] jpeg, boolean blur)
        {
            this.jpeg = jpeg;
            this.blur = blur;
        }
    }

    // ------------------------------------------------------------------
    //  MJPEG AVI builder
    // ------------------------------------------------------------------

    private byte[] framesToVideoBytes(List<byte[]> jpegs) throws IOException
    {
        byte[] avi = assembleMjpegAvi(jpegs);
        log.info("MJPEG AVI: {} frames -> {} bytes", jpegs.size(), avi.length);
        return avi;
    }

    private byte[] assembleMjpegAvi(List<byte[]> jpegs) throws IOException
    {
        if (jpegs.isEmpty())
        {
            return new byte[0];
        }

        int[] dim = parseJpegSize(jpegs.get(0));
        int imgW = dim[0];
        int imgH = dim[1];
        int fps = (activeFps > 0) ? activeFps : 30;
        int numFrames = jpegs.size();

        int biggestFrame = 0;
        for (byte[] j : jpegs)
        {
            biggestFrame = Math.max(biggestFrame, j.length);
        }

        // Build the movi chunk list, tracking offsets for the index
        ByteArrayOutputStream moviBody = new ByteArrayOutputStream();
        int[] offsets = new int[numFrames];
        int cursor = 4; // "movi" fourcc precedes these chunks

        for (int i = 0; i < numFrames; i++)
        {
            byte[] f = jpegs.get(i);
            offsets[i] = cursor;
            emitFourCC(moviBody, "00dc");
            emitLE32(moviBody, f.length);
            moviBody.write(f);
            if (f.length % 2 != 0)
            {
                moviBody.write(0);
            }
            cursor += 8 + f.length + (f.length % 2);
        }
        byte[] moviRaw = moviBody.toByteArray();

        // Size arithmetic for the RIFF structure
        int idx1Payload = 16 * numFrames;
        int riffPayload = 4           // "AVI "
            + 8 + 192                 // hdrl LIST
            + 8 + 4 + moviRaw.length  // movi LIST
            + 8 + idx1Payload;        // idx1

        ByteArrayOutputStream avi = new ByteArrayOutputStream();

        // RIFF wrapper
        emitFourCC(avi, "RIFF");
        emitLE32(avi, riffPayload);
        emitFourCC(avi, "AVI ");

        // hdrl LIST
        emitFourCC(avi, "LIST");
        emitLE32(avi, 192);
        emitFourCC(avi, "hdrl");

        // avih chunk (main AVI header, 56 bytes payload)
        emitFourCC(avi, "avih");
        emitLE32(avi, 56);
        emitLE32(avi, 1_000_000 / fps);    // microseconds per frame
        emitLE32(avi, biggestFrame * fps);  // max bytes/sec
        emitLE32(avi, 0);                   // padding granularity
        emitLE32(avi, 0x10);                // flags: AVIF_HASINDEX
        emitLE32(avi, numFrames);           // total frames
        emitLE32(avi, 0);                   // initial frames
        emitLE32(avi, 1);                   // stream count
        emitLE32(avi, biggestFrame);        // suggested buffer
        emitLE32(avi, imgW);
        emitLE32(avi, imgH);
        emitLE32(avi, 0);                   // reserved[4]
        emitLE32(avi, 0);
        emitLE32(avi, 0);
        emitLE32(avi, 0);

        // strl LIST
        emitFourCC(avi, "LIST");
        emitLE32(avi, 116);
        emitFourCC(avi, "strl");

        // strh (stream header, 56 bytes payload)
        emitFourCC(avi, "strh");
        emitLE32(avi, 56);
        emitFourCC(avi, "vids");
        emitFourCC(avi, "MJPG");
        emitLE32(avi, 0);               // flags
        emitLE16(avi, 0);               // priority
        emitLE16(avi, 0);               // language
        emitLE32(avi, 0);               // initial frames
        emitLE32(avi, 1);               // scale
        emitLE32(avi, fps);             // rate
        emitLE32(avi, 0);               // start
        emitLE32(avi, numFrames);       // length
        emitLE32(avi, biggestFrame);    // suggested buffer
        emitLE32(avi, 0xFFFFFFFF);      // quality (-1)
        emitLE32(avi, 0);               // sample size
        emitLE16(avi, 0);               // rcFrame left
        emitLE16(avi, 0);               // rcFrame top
        emitLE16(avi, imgW);            // rcFrame right
        emitLE16(avi, imgH);            // rcFrame bottom

        // strf (BITMAPINFOHEADER, 40 bytes payload)
        emitFourCC(avi, "strf");
        emitLE32(avi, 40);
        emitLE32(avi, 40);              // biSize
        emitLE32(avi, imgW);            // biWidth
        emitLE32(avi, imgH);            // biHeight
        emitLE16(avi, 1);               // biPlanes
        emitLE16(avi, 24);              // biBitCount
        emitFourCC(avi, "MJPG");        // biCompression
        emitLE32(avi, imgW * imgH * 3); // biSizeImage
        emitLE32(avi, 0);               // biXPelsPerMeter
        emitLE32(avi, 0);               // biYPelsPerMeter
        emitLE32(avi, 0);               // biClrUsed
        emitLE32(avi, 0);               // biClrImportant

        // movi LIST
        emitFourCC(avi, "LIST");
        emitLE32(avi, 4 + moviRaw.length);
        emitFourCC(avi, "movi");
        avi.write(moviRaw);

        // idx1 (legacy AVI index for seeking)
        emitFourCC(avi, "idx1");
        emitLE32(avi, idx1Payload);
        for (int i = 0; i < numFrames; i++)
        {
            emitFourCC(avi, "00dc");
            emitLE32(avi, 0x10);            // AVIIF_KEYFRAME
            emitLE32(avi, offsets[i]);
            emitLE32(avi, jpegs.get(i).length);
        }

        return avi.toByteArray();
    }

    // Scans JPEG SOF markers to find the image dimensions
    private static int[] parseJpegSize(byte[] jpeg)
    {
        for (int i = 0; i < jpeg.length - 9; i++)
        {
            if ((jpeg[i] & 0xFF) == 0xFF)
            {
                int mk = jpeg[i + 1] & 0xFF;
                if (mk == 0xC0 || mk == 0xC1 || mk == 0xC2)
                {
                    int h = ((jpeg[i + 5] & 0xFF) << 8) | (jpeg[i + 6] & 0xFF);
                    int w = ((jpeg[i + 7] & 0xFF) << 8) | (jpeg[i + 8] & 0xFF);
                    if (w > 0 && h > 0)
                    {
                        return new int[]{w, h};
                    }
                }
            }
        }
        return new int[]{1280, 720};
    }

    // ------------------------------------------------------------------
    //  Binary helpers
    // ------------------------------------------------------------------

    private static void emitFourCC(ByteArrayOutputStream s, String tag)
    {
        byte[] b = tag.getBytes(StandardCharsets.US_ASCII);
        s.write(b, 0, 4);
    }

    private static void emitLE32(ByteArrayOutputStream s, int v)
    {
        s.write(v & 0xFF);
        s.write((v >>> 8) & 0xFF);
        s.write((v >>> 16) & 0xFF);
        s.write((v >>> 24) & 0xFF);
    }

    private static void emitLE16(ByteArrayOutputStream s, int v)
    {
        s.write(v & 0xFF);
        s.write((v >>> 8) & 0xFF);
    }

    // ------------------------------------------------------------------
    //  Image utilities
    // ------------------------------------------------------------------

    private String bufferedImageToPngBase64(BufferedImage bimg) throws IOException
    {
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        ImageIO.write(bimg, "PNG", bos);
        return Base64.getEncoder().encodeToString(bos.toByteArray());
    }

    // ------------------------------------------------------------------
    //  Public callback interface
    // ------------------------------------------------------------------

    public interface VideoCallback
    {
        /**
         * @param screenshotBase64 PNG-encoded still, base64 string (small, ~100KB)
         * @param videoBytes       raw MJPEG AVI bytes, or null if video unavailable
         */
        void onComplete(String screenshotBase64, byte[] videoBytes);
    }
}

package com.killClips.video;

import lombok.extern.slf4j.Slf4j;
import net.runelite.client.ui.DrawManager;
import org.lwjgl.opengl.GL;
import org.lwjgl.opengl.GL11;
import org.lwjgl.opengl.GL15;
import org.lwjgl.opengl.GL21;
import org.lwjgl.opengl.GLCapabilities;
import org.lwjgl.system.MemoryStack;

import java.nio.ByteBuffer;
import java.nio.IntBuffer;
import java.util.concurrent.atomic.AtomicBoolean;

// Double-buffered PBO readback that avoids stalling the render thread.
// On each rendered frame we issue an async glReadPixels into the "active" PBO
// while mapping the "previous" PBO whose DMA transfer has already completed.
@Slf4j
public class AsyncFrameCapture
{
    private final DrawManager drawMgr;
    private final VideoRecorder recorder;
    private final Runnable gpuFallback;

    // Two PBOs for ping-pong
    private final int[] bufferIds = new int[2];
    private int activeSlot = 0;

    // Viewport dimensions of the last initialised PBO pair
    private int knownW = 0;
    private int knownH = 0;

    private boolean buffersReady = false;
    private boolean initialFrame = true;
    private volatile boolean glMissing = false;
    private final AtomicBoolean stopping = new AtomicBoolean(false);

    private Runnable frameHook;

    // Fixed-rate schedule tracking to avoid FPS drift
    private long nextAllowedNs = 0;

    public AsyncFrameCapture(DrawManager drawMgr, VideoRecorder recorder, Runnable gpuFallback)
    {
        this.drawMgr = drawMgr;
        this.recorder = recorder;
        this.gpuFallback = gpuFallback;
    }

    public void start()
    {
        if (frameHook != null)
        {
            return;
        }

        stopping.set(false);
        glMissing = false;
        initialFrame = true;
        activeSlot = 0;
        nextAllowedNs = 0;

        frameHook = this::tick;
        drawMgr.registerEveryFrameListener(frameHook);
        log.debug("PBO double-buffer capture started");
    }

    public void stop()
    {
        stopping.set(true);

        if (frameHook != null)
        {
            drawMgr.unregisterEveryFrameListener(frameHook);
            frameHook = null;
        }

        // Tear down GPU resources on the GL thread
        if (buffersReady)
        {
            drawMgr.requestNextFrameListener(img -> destroyBuffers());
        }

        log.debug("PBO capture halted");
    }

    public boolean isPboUnsupported()
    {
        return glMissing;
    }

    // Runs on the GL thread every frame
    private void tick()
    {
        if (stopping.get() || !recorder.isCurrentlyRecording() || glMissing)
        {
            return;
        }

        // Rate-limit to the configured capture FPS using fixed-rate advancement
        int targetFps = recorder.getCaptureFps();
        if (targetFps <= 0)
        {
            return;
        }

        long nowNs = System.nanoTime();
        long intervalNs = 1_000_000_000L / targetFps;
        if (nextAllowedNs == 0)
        {
            nextAllowedNs = nowNs;
        }
        if (nowNs < nextAllowedNs)
        {
            return;
        }
        nextAllowedNs += intervalNs;
        // Catch up if we fell behind by more than one interval
        if (nowNs - nextAllowedNs > intervalNs)
        {
            nextAllowedNs = nowNs + intervalNs;
        }

        if (!recorder.canAcceptFrame())
        {
            return;
        }

        try
        {
            // Verify GL availability
            GLCapabilities glCaps;
            try
            {
                glCaps = GL.getCapabilities();
            }
            catch (IllegalStateException ex)
            {
                glMissing = true;
                log.debug("GL context unavailable -- triggering fallback");
                gpuFallback.run();
                return;
            }
            if (glCaps == null || !glCaps.OpenGL21)
            {
                glMissing = true;
                log.debug("OpenGL 2.1 not present -- triggering fallback");
                gpuFallback.run();
                return;
            }

            // Read current viewport size
            int vpW, vpH;
            try (MemoryStack stack = MemoryStack.stackPush())
            {
                IntBuffer vp = stack.mallocInt(4);
                GL11.glGetIntegerv(GL11.GL_VIEWPORT, vp);
                vpW = vp.get(2);
                vpH = vp.get(3);
            }
            if (vpW <= 0 || vpH <= 0)
            {
                return;
            }

            // (Re-)allocate PBOs when viewport changes
            if (!buffersReady || vpW != knownW || vpH != knownH)
            {
                if (buffersReady)
                {
                    destroyBuffers();
                }
                allocateBuffers(vpW, vpH);
                initialFrame = true;
            }

            int prev = 1 - activeSlot;
            int cur = activeSlot;

            // Map the previous PBO (DMA already finished) and hand off pixels
            if (!initialFrame)
            {
                GL15.glBindBuffer(GL21.GL_PIXEL_PACK_BUFFER, bufferIds[prev]);
                ByteBuffer mapped = GL15.glMapBuffer(GL21.GL_PIXEL_PACK_BUFFER, GL15.GL_READ_ONLY);
                if (mapped != null)
                {
                    int bytes = knownW * knownH * 4;
                    byte[] copy = recorder.acquireRgbaBuffer(bytes);
                    mapped.rewind();
                    mapped.get(copy, 0, bytes);
                    GL15.glUnmapBuffer(GL21.GL_PIXEL_PACK_BUFFER);
                    recorder.submitCapturedFrame(copy, knownW, knownH);
                }
                // If mapped is null, the buffer was never mapped — DO NOT call glUnmapBuffer
            }

            // Kick off async readback into the current PBO.
            // GL_BACK is correct for double-buffered contexts; GL_FRONT is undefined on many drivers.
            GL15.glBindBuffer(GL21.GL_PIXEL_PACK_BUFFER, bufferIds[cur]);
            GL11.glReadBuffer(GL11.GL_BACK);
            GL11.glReadPixels(0, 0, vpW, vpH, GL11.GL_RGBA, GL11.GL_UNSIGNED_BYTE, 0);
            GL15.glBindBuffer(GL21.GL_PIXEL_PACK_BUFFER, 0);

            activeSlot = prev;
            initialFrame = false;
        }
        catch (Exception ex)
        {
            log.error("PBO capture tick failed", ex);
        }
    }

    private void allocateBuffers(int w, int h)
    {
        int bytes = w * h * 4;
        GL15.glGenBuffers(bufferIds);
        for (int i = 0; i < 2; i++)
        {
            GL15.glBindBuffer(GL21.GL_PIXEL_PACK_BUFFER, bufferIds[i]);
            GL15.glBufferData(GL21.GL_PIXEL_PACK_BUFFER, bytes, GL15.GL_STREAM_READ);
        }
        GL15.glBindBuffer(GL21.GL_PIXEL_PACK_BUFFER, 0);

        knownW = w;
        knownH = h;
        buffersReady = true;
        log.debug("PBO pair allocated for {}x{}", w, h);
    }

    private void destroyBuffers()
    {
        if (!buffersReady)
        {
            return;
        }
        GL15.glDeleteBuffers(bufferIds);
        bufferIds[0] = 0;
        bufferIds[1] = 0;
        buffersReady = false;
        knownW = 0;
        knownH = 0;
    }
}

package com.killClips.api;

import com.google.gson.Gson;
import com.google.gson.JsonObject;
import com.killClips.KillClipsConfig;
import lombok.extern.slf4j.Slf4j;
import okhttp3.Call;
import okhttp3.Callback;
import okhttp3.Credentials;
import okhttp3.MediaType;
import okhttp3.MultipartBody;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.concurrent.TimeUnit;
import java.util.function.BiConsumer;

@Slf4j
@Singleton
public class StreamableUploader
{
    private static final String API_ENDPOINT = "https://api.streamable.com/upload";
    private static final MediaType BINARY = MediaType.parse("application/octet-stream");

    private final OkHttpClient http;
    private final KillClipsConfig cfg;
    private final Gson gson;

    // Listener called on successful upload: (description, url)
    private volatile BiConsumer<String, String> onClipUploaded;

    @Inject
    public StreamableUploader(OkHttpClient http, KillClipsConfig cfg, Gson gson)
    {
        // Override the shared RuneLite client's timeouts so uploads never hang forever.
        this.http = http.newBuilder()
            .connectTimeout(15, TimeUnit.SECONDS)
            .writeTimeout(5, TimeUnit.MINUTES)
            .readTimeout(60, TimeUnit.SECONDS)
            .callTimeout(10, TimeUnit.MINUTES)
            .build();
        this.cfg = cfg;
        this.gson = gson;
    }

    public void setOnClipUploaded(BiConsumer<String, String> listener)
    {
        this.onClipUploaded = listener;
    }

    public void upload(Path clip, String description)
    {
        if (!cfg.streamableEnabled())
        {
            return;
        }

        String user = cfg.streamableEmail();
        String pass = cfg.streamablePassword();
        if (user == null || user.isEmpty() || pass == null || pass.isEmpty())
        {
            log.warn("Streamable credentials not configured -- skipping upload");
            return;
        }

        if (!Files.exists(clip))
        {
            log.warn("Video file missing, cannot upload: {}", clip);
            return;
        }

        try
        {
            String name = clip.getFileName().toString();
            // Stream the file from disk instead of loading it into memory
            RequestBody filePart = RequestBody.create(BINARY, clip.toFile());
            MultipartBody payload = new MultipartBody.Builder()
                .setType(MultipartBody.FORM)
                .addFormDataPart("file", name, filePart)
                .build();

            Request req = new Request.Builder()
                .url(API_ENDPOINT)
                .header("Authorization", Credentials.basic(user, pass))
                .post(payload)
                .build();

            log.info("Starting Streamable upload: {}", name);

            final String desc = (description != null) ? description : name;

            http.newCall(req).enqueue(new Callback()
            {
                @Override
                public void onFailure(Call call, IOException ex)
                {
                    log.error("Streamable upload error for {}", name, ex);
                }

                @Override
                public void onResponse(Call call, Response resp) throws IOException
                {
                    try (resp)
                    {
                        String body = resp.body() != null ? resp.body().string() : "";
                        if (!resp.isSuccessful())
                        {
                            log.error("Streamable returned HTTP {} -- {}", resp.code(), body);
                            return;
                        }

                        JsonObject obj = gson.fromJson(body, JsonObject.class);
                        if (obj != null && obj.has("shortcode"))
                        {
                            String code = obj.get("shortcode").getAsString();
                            String url = "https://streamable.com/" + code;
                            log.info("Streamable upload finished: {}", url);

                            BiConsumer<String, String> listener = onClipUploaded;
                            if (listener != null)
                            {
                                listener.accept(desc, url);
                            }
                        }
                        else
                        {
                            log.warn("Unexpected Streamable response: {}", body);
                        }
                    }
                }
            });
        }
        catch (Exception ex)
        {
            log.error("Could not prepare Streamable upload: {}", clip, ex);
        }
    }
}

package com.killClips.api;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import lombok.extern.slf4j.Slf4j;
import net.runelite.client.RuneLite;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

@Slf4j
@Singleton
public class ApiClient
{
    private static final DateTimeFormatter TS_FMT = DateTimeFormatter.ofPattern("yyyyMMdd_HHmmss_SSS");
    private static final DateTimeFormatter DISPLAY_DATE = DateTimeFormatter.ofPattern("MMM d");
    private static final Path CLIPS_JSON = RuneLite.RUNELITE_DIR.toPath().resolve("videos").resolve("clips.json");

    private final Gson gson;
    private final StreamableUploader streamable;

    @Inject
    public ApiClient(Gson gson, StreamableUploader streamable)
    {
        this.gson = gson;
        this.streamable = streamable;
    }

    public void sendEventToApi(String endpoint, String jsonBody, String label, byte[] videoBytes)
    {
        try
        {
            String kind = extractEventKind(endpoint);
            String ts = LocalDateTime.now().format(TS_FMT);
            String stem = kind + "_" + ts;

            JsonObject meta = toJsonObject(jsonBody);
            meta.addProperty("event_type", kind);
            meta.addProperty("saved_at", LocalDateTime.now().toString());

            String rawPlayer = meta.has("playername") ? meta.get("playername").getAsString() : "unknown";
            String player = sanitizePathSegment(rawPlayer);
            Path folder = RuneLite.RUNELITE_DIR.toPath().resolve("videos").resolve(player).resolve(kind);
            Files.createDirectories(folder);

            if (videoBytes != null && videoBytes.length > 0)
            {
                String ext = (videoBytes.length >= 8 && "ftyp".equals(new String(videoBytes, 4, 4, StandardCharsets.US_ASCII))) ? ".mp4" : ".avi";
                Path vidPath = folder.resolve(stem + ext);
                Files.write(vidPath, videoBytes);
                meta.addProperty("video_file", vidPath.toString());

                String clipDesc = buildClipDescription(meta);
                streamable.upload(vidPath, clipDesc);
            }

            appendToClipsJson(meta);
            log.debug("Persisted {} to clips.json", label);
        }
        catch (Exception ex)
        {
            log.error("Failed to persist {}", label, ex);
        }
    }

    // Keep only letters, digits, underscore, dash, and space — prevents any path-traversal
    // (.. or / or \) if a malformed player name ever reaches this code path.
    private static String sanitizePathSegment(String raw)
    {
        if (raw == null || raw.isEmpty())
        {
            return "unknown";
        }
        String cleaned = raw.replaceAll("[^a-zA-Z0-9 _-]", "_").trim();
        if (cleaned.isEmpty() || ".".equals(cleaned) || "..".equals(cleaned))
        {
            return "unknown";
        }
        if (cleaned.length() > 32)
        {
            cleaned = cleaned.substring(0, 32);
        }
        return cleaned;
    }

    private synchronized void appendToClipsJson(JsonObject entry)
    {
        try
        {
            Files.createDirectories(CLIPS_JSON.getParent());

            JsonArray clips;
            if (Files.exists(CLIPS_JSON))
            {
                String existing = Files.readString(CLIPS_JSON, StandardCharsets.UTF_8);
                JsonElement parsed = gson.fromJson(existing, JsonElement.class);
                clips = (parsed != null && parsed.isJsonArray()) ? parsed.getAsJsonArray() : new JsonArray();
            }
            else
            {
                clips = new JsonArray();
            }

            clips.add(entry);
            Files.writeString(CLIPS_JSON, gson.toJson(clips), StandardCharsets.UTF_8);
        }
        catch (Exception ex)
        {
            log.error("Failed to update clips.json", ex);
        }
    }

    private JsonObject toJsonObject(String raw)
    {
        try
        {
            JsonElement el = gson.fromJson(raw, JsonElement.class);
            if (el != null && el.isJsonObject())
            {
                return el.getAsJsonObject();
            }
        }
        catch (Exception ignored) {}

        JsonObject wrapper = new JsonObject();
        wrapper.addProperty("raw_payload", raw != null ? raw : "");
        return wrapper;
    }

    private String buildClipDescription(JsonObject meta)
    {
        String kind = meta.has("event_type") ? meta.get("event_type").getAsString() : "clip";
        String player = meta.has("playername") ? meta.get("playername").getAsString() : "unknown";
        String date = LocalDateTime.now().format(DISPLAY_DATE);

        switch (kind)
        {
            case "death":
                return player + " - death - " + date;
            case "kills":
                String victim = meta.has("killed_player") ? meta.get("killed_player").getAsString() : "someone";
                return victim + " - kill - " + date;
            default:
                return kind + " - " + date;
        }
    }

    private String extractEventKind(String ep)
    {
        if (ep == null || ep.isEmpty())
        {
            return "event";
        }
        int slash = ep.lastIndexOf('/');
        String segment = (slash >= 0) ? ep.substring(slash + 1) : ep;
        segment = segment.replaceAll("[^a-zA-Z0-9_\\-]", "_").toLowerCase();
        return segment.isEmpty() ? "event" : segment;
    }
}

package com.killClips;

import com.google.gson.Gson;
import com.google.inject.Provides;
import com.killClips.api.StreamableUploader;
import com.killClips.death.DeathTracker;
import com.killClips.playerdeath.CombatTracker;
import com.killClips.playerdeath.KillTracker;
import com.killClips.video.VideoRecorder;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.*;
import net.runelite.api.events.*;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.EventBus;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDependency;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.plugins.gpu.GpuPlugin;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.NavigationButton;

import javax.inject.Inject;
import java.awt.image.BufferedImage;

@Slf4j
@PluginDescriptor(
    name = "Kill Clips",
    description = "Automatically captures deaths and kills to local video files with Streamable upload",
    tags = {"kill", "clips", "deaths", "video", "streamable"}
)
@PluginDependency(GpuPlugin.class)
public class KillClipsPlugin extends Plugin
{
    @Inject private Client client;
    @Inject private KillClipsConfig config;
    @Inject private DeathTracker deathTracker;
    @Inject private KillTracker killTracker;
    @Inject private CombatTracker combatTracker;
    @Inject private VideoRecorder videoRecorder;
    @Inject private StreamableUploader streamableUploader;
    @Inject private ClientToolbar clientToolbar;
    @Inject private EventBus eventBus;
    @Inject private Gson gson;

    private NavigationButton navBtn;
    private KillClipsPanel sidePanel;
    private volatile boolean inSession = false;

    private EventBus.Subscriber gameStateSub;
    private EventBus.Subscriber interactingSub;
    private EventBus.Subscriber actorDeathSub;
    private EventBus.Subscriber gameTickSub;

    @Override
    protected void startUp() throws Exception
    {
        log.debug("Kill Clips starting");
        videoRecorder.startRecording();

        if (client.getGameState() == GameState.LOGGED_IN)
        {
            inSession = true;
        }

        sidePanel = new KillClipsPanel(gson);
        streamableUploader.setOnClipUploaded((desc, url) -> sidePanel.addClip(desc, url));

        BufferedImage icon = new BufferedImage(16, 16, BufferedImage.TYPE_INT_ARGB);
        java.awt.Graphics2D gfx = icon.createGraphics();
        gfx.setRenderingHint(java.awt.RenderingHints.KEY_ANTIALIASING, java.awt.RenderingHints.VALUE_ANTIALIAS_ON);
        gfx.setColor(new java.awt.Color(220, 40, 40));
        gfx.fillOval(2, 2, 12, 12);
        gfx.dispose();

        navBtn = NavigationButton.builder()
            .tooltip("Kill Clips")
            .icon(icon)
            .priority(10)
            .panel(sidePanel)
            .build();
        clientToolbar.addNavigation(navBtn);

        gameStateSub = eventBus.register(GameStateChanged.class, this::onGameStateChanged, 0);
        interactingSub = eventBus.register(InteractingChanged.class, this::onInteractingChanged, 0);
        actorDeathSub = eventBus.register(ActorDeath.class, this::onActorDeath, 0);
        gameTickSub = eventBus.register(GameTick.class, this::onGameTick, 0);
    }

    @Override
    protected void shutDown() throws Exception
    {
        log.debug("Kill Clips stopping");

        if (gameStateSub != null) eventBus.unregister(gameStateSub);
        if (interactingSub != null) eventBus.unregister(interactingSub);
        if (actorDeathSub != null) eventBus.unregister(actorDeathSub);
        if (gameTickSub != null) eventBus.unregister(gameTickSub);
        gameStateSub = interactingSub = actorDeathSub = gameTickSub = null;

        if (navBtn != null)
        {
            clientToolbar.removeNavigation(navBtn);
        }
        streamableUploader.setOnClipUploaded(null);
        try
        {
            videoRecorder.shutdown();
        }
        catch (Exception ex)
        {
            log.warn("VideoRecorder shutdown threw", ex);
        }
        inSession = false;
    }

    // All @Subscribe handlers below are wrapped in try/catch. An uncaught exception here
    // would detach the subscriber from the event bus for the rest of the session.

    private void onGameStateChanged(GameStateChanged evt)
    {
        try
        {
            GameState gs = evt.getGameState();
            if (gs == GameState.LOGGED_IN && !inSession)
            {
                inSession = true;
            }
            else if (gs == GameState.LOGIN_SCREEN && inSession)
            {
                inSession = false;
                combatTracker.reset();
            }
            else if (gs == GameState.HOPPING && inSession)
            {
                inSession = false;
                combatTracker.reset();
            }
        }
        catch (Exception ex)
        {
            log.warn("onGameStateChanged threw", ex);
        }
    }

    private void onInteractingChanged(InteractingChanged evt)
    {
        try
        {
            combatTracker.onInteractingChanged(evt.getSource(), evt.getTarget());
        }
        catch (Exception ex)
        {
            log.warn("onInteractingChanged threw", ex);
        }
    }

    private void onActorDeath(ActorDeath evt)
    {
        try
        {
            Actor who = evt.getActor();
            if (!(who instanceof Player))
            {
                return;
            }
            deathTracker.processActorDeath(who);
            killTracker.processActorDeath(who);
        }
        catch (Exception ex)
        {
            log.warn("onActorDeath threw", ex);
        }
    }

    private void onGameTick(GameTick tick)
    {
        try
        {
            videoRecorder.updateCaptureRateIfNeeded();
            combatTracker.onGameTick();
        }
        catch (Exception ex)
        {
            log.warn("onGameTick threw", ex);
        }
    }

    @Provides
    KillClipsConfig provideConfig(ConfigManager cfgMgr)
    {
        return cfgMgr.getConfig(KillClipsConfig.class);
    }
}

package com.killClips.death;

import com.google.gson.JsonObject;
import com.killClips.KillClipsConfig;
import com.killClips.api.ApiClient;
import com.killClips.video.VideoRecorder;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Actor;
import net.runelite.api.Client;
import net.runelite.api.Player;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.time.Instant;

// Records the local player's own deaths
@Slf4j
@Singleton
public class DeathTracker
{
    private static final int POST_DEATH_DELAY_MS = 5000;

    private final Client gameClient;
    private final ApiClient storage;
    private final KillClipsConfig cfg;
    private final VideoRecorder recorder;

    @Inject
    public DeathTracker(Client gameClient, ApiClient storage, KillClipsConfig cfg, VideoRecorder recorder)
    {
        this.gameClient = gameClient;
        this.storage = storage;
        this.cfg = cfg;
        this.recorder = recorder;
    }

    public void processActorDeath(Actor who)
    {
        Player me = gameClient.getLocalPlayer();
        if (me == null || who != me)
        {
            return;
        }

        log.debug("Local player died");
        captureAndStore();
    }

    private void captureAndStore()
    {
        recorder.captureEventVideo(
            (screenshotData, videoBytes) ->
            {
                String rsn = resolvePlayerName();

                JsonObject info = new JsonObject();
                info.addProperty("playername", rsn);
                info.addProperty("timestamp", Instant.now().toString());

                storage.sendEventToApi(
                    "/api/webhooks/death",
                    info.toString(),
                    "death",
                    videoBytes
                );
            },
            null,
            POST_DEATH_DELAY_MS
        );
    }

    private String resolvePlayerName()
    {
        Player me = gameClient.getLocalPlayer();
        if (me != null && me.getName() != null)
        {
            return me.getName();
        }
        return "unknown";
    }
}

