public class RightClickConsumer extends MouseAdapter
{
	@Override
	public MouseEvent mouseClicked(MouseEvent event)
	{
		if (event.getButton() != MouseEvent.BUTTON1)
		{
			event.consume();
		}
		return event;
	}

	@Override
	public MouseEvent mousePressed(MouseEvent event)
	{
		if (event.getButton() != MouseEvent.BUTTON1)
		{
			event.consume();
		}
		return event;
	}
}

