    private final JPanel      calendarGrid   = new JPanel();
    private final JLabel      monthYearLabel = new JLabel();

    private YearMonth         viewMonth      = YearMonth.now();
    private LocalDate         selectedDate   = null;   // null = all dates
    private Set<LocalDate>    datesWithData  = new HashSet<>();

    @Setter
    private Consumer<LocalDate> onDateSelected = date -> {};

    // endregion

    // region Constructor

    public DailyAgilityPanel()
    {
        super(false);
        setLayout(new BorderLayout(0, 8));
        setBackground(COLOR_BG);
        setBorder(new EmptyBorder(8, 8, 8, 8));

        add(buildNorth(), BorderLayout.NORTH);

        logContainer = new JPanel();
        logContainer.setLayout(new BoxLayout(logContainer, BoxLayout.Y_AXIS));
        logContainer.setBackground(COLOR_BG);

        JScrollPane scrollPane = new JScrollPane(logContainer);
        scrollPane.setBorder(null);
        scrollPane.setBackground(COLOR_BG);
        scrollPane.getViewport().setBackground(COLOR_BG);
        add(scrollPane, BorderLayout.CENTER);
    }

    // endregion

    // region Public API

    /**
     * Tell the calendar which dates have log data so it can highlight them.
     * Call this once after LogStore is ready, and again if new data comes in.
     */
    public void setDatesWithData(Set<LocalDate> dates)
    {
        this.datesWithData = dates;
        SwingUtilities.invokeLater(this::rebuildCalendarGrid);
    }

    public void setLogEntries(List<LogEntry> entries)
    {
        SwingUtilities.invokeLater(() ->
        {
            logContainer.removeAll();

            if (entries.isEmpty())
            {
                JLabel empty = new JLabel("No data for this selection.");
                empty.setForeground(COLOR_MUTED);
                empty.setFont(FontManager.getRunescapeSmallFont());
                empty.setBorder(new EmptyBorder(4, 0, 0, 0));
                logContainer.add(empty);
            }
            else
            {
                for (LogEntry entry : entries)
                {
                    logContainer.add(buildRow(entry));
                    logContainer.add(Box.createVerticalStrut(4));
                }
            }

            logContainer.revalidate();
            logContainer.repaint();
        });
    }

    // endregion

    // region Header + Title

    private JPanel buildNorth()
    {
        JPanel north = new JPanel();
        north.setLayout(new BoxLayout(north, BoxLayout.Y_AXIS));
        north.setBackground(COLOR_BG);

        // Title
        JLabel title = new JLabel("Daily Agility Log");
        title.setForeground(COLOR_TEXT);
        title.setFont(FontManager.getRunescapeBoldFont());
        title.setAlignmentX(Component.LEFT_ALIGNMENT);
        north.add(title);

        north.add(Box.createVerticalStrut(8));

        // Calendar card
        JPanel calendarCard = new JPanel(new BorderLayout(0, 4));
        calendarCard.setBackground(COLOR_CARD);
        calendarCard.setBorder(new EmptyBorder(8, 8, 8, 8));
        calendarCard.setAlignmentX(Component.LEFT_ALIGNMENT);

        calendarCard.add(buildMonthNav(), BorderLayout.NORTH);
        calendarCard.add(buildDayHeaders(), BorderLayout.CENTER);

        calendarGrid.setBackground(COLOR_CARD);
        calendarCard.add(calendarGrid, BorderLayout.SOUTH);

        north.add(calendarCard);
        north.add(Box.createVerticalStrut(4));

        // "Show all" button beneath the calendar
        JButton allButton = buildAllButton();
        allButton.setAlignmentX(Component.LEFT_ALIGNMENT);
        north.add(allButton);

        north.add(Box.createVerticalStrut(6));

        // Separator
        JSeparator sep = new JSeparator();
        sep.setForeground(ColorScheme.MEDIUM_GRAY_COLOR);
        sep.setAlignmentX(Component.LEFT_ALIGNMENT);
        sep.setMaximumSize(new Dimension(Integer.MAX_VALUE, 1));
        north.add(sep);

        rebuildCalendarGrid();

        return north;
    }

    // endregion

    // region Month navigation

    private JPanel buildMonthNav()
    {
        JPanel nav = new JPanel(new BorderLayout());
        nav.setBackground(COLOR_CARD);

        JButton prev = buildNavArrow("‹");
        prev.addActionListener(e ->
        {
            viewMonth = viewMonth.minusMonths(1);
            rebuildCalendarGrid();
        });

        JButton next = buildNavArrow("›");
        next.addActionListener(e ->
        {
            // Don't navigate into the future
            if (viewMonth.isBefore(YearMonth.now()))
            {
                viewMonth = viewMonth.plusMonths(1);
                rebuildCalendarGrid();
            }
        });

        monthYearLabel.setForeground(COLOR_TEXT);
        monthYearLabel.setFont(FontManager.getRunescapeSmallFont());
        monthYearLabel.setHorizontalAlignment(SwingConstants.CENTER);

        nav.add(prev, BorderLayout.WEST);
        nav.add(monthYearLabel, BorderLayout.CENTER);
        nav.add(next, BorderLayout.EAST);

        return nav;
    }

    private JButton buildNavArrow(String symbol)
    {
        JButton btn = new JButton(symbol);
        btn.setForeground(COLOR_MUTED);
        btn.setBackground(COLOR_CARD);
        btn.setBorder(new EmptyBorder(2, 6, 2, 6));
        btn.setFocusPainted(false);
        btn.setBorderPainted(false);
        btn.setContentAreaFilled(false);
        btn.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        btn.setFont(btn.getFont().deriveFont(16f));
        return btn;
    }

    // endregion

    // region Calendar grid

    /**
     * Day-of-week column headers: Mo Tu We Th Fr Sa Su
     */
    private JPanel buildDayHeaders()
    {
        JPanel headers = new JPanel(new GridLayout(1, 7, 2, 0));
        headers.setBackground(COLOR_CARD);
        headers.setBorder(new EmptyBorder(4, 0, 2, 0));

        // Start week on Monday to match EU convention
        for (DayOfWeek dow : DayOfWeek.values())
        {
            JLabel lbl = new JLabel(
                    dow.getDisplayName(TextStyle.SHORT, Locale.getDefault()).substring(0, 2),
                    SwingConstants.CENTER
            );
            lbl.setForeground(COLOR_HEADER_TEXT);
            lbl.setFont(FontManager.getRunescapeSmallFont());
            headers.add(lbl);
        }

        return headers;
    }

    private void rebuildCalendarGrid()
    {
        calendarGrid.removeAll();

        // 6 rows max, 7 columns
        calendarGrid.setLayout(new GridLayout(0, 7, 2, 2));

        monthYearLabel.setText(
                viewMonth.getMonth().getDisplayName(TextStyle.FULL, Locale.getDefault())
                        + " " + viewMonth.getYear()
        );

        LocalDate firstOfMonth = viewMonth.atDay(1);
        LocalDate today        = LocalDate.now();

        // Monday = 1, so offset = dayOfWeek - 1
        int leadingBlanks = firstOfMonth.getDayOfWeek().getValue() - 1;

        for (int i = 0; i < leadingBlanks; i++)
        {
            calendarGrid.add(emptyCell());
        }

        for (int day = 1; day <= viewMonth.lengthOfMonth(); day++)
        {
            LocalDate date = viewMonth.atDay(day);
            boolean isToday    = date.equals(today);
            boolean isSelected = date.equals(selectedDate);
            boolean hasData    = datesWithData.contains(date);
            boolean isFuture   = date.isAfter(today);

            calendarGrid.add(buildDayCell(date, isToday, isSelected, hasData, isFuture));
        }

        calendarGrid.revalidate();
        calendarGrid.repaint();
    }

    private JPanel buildDayCell(LocalDate date, boolean isToday, boolean isSelected,
                                boolean hasData, boolean isFuture)
    {
        JPanel cell = new JPanel(new BorderLayout());
        cell.setPreferredSize(new Dimension(28, 24));

        if (isSelected)
        {
            cell.setBackground(COLOR_SELECTED_BG);
            cell.setBorder(new LineBorder(COLOR_ACCENT, 1));
        }
        else if (isToday)
        {
            cell.setBackground(COLOR_CARD);
            cell.setBorder(new LineBorder(COLOR_TODAY_BORDER, 1));
        }
        else if (hasData)
        {
            cell.setBackground(COLOR_HAS_DATA);
            cell.setBorder(new EmptyBorder(1, 1, 1, 1));
        }
        else
        {
            cell.setBackground(COLOR_CARD);
            cell.setBorder(new EmptyBorder(1, 1, 1, 1));
        }

        JLabel lbl = new JLabel(String.valueOf(date.getDayOfMonth()), SwingConstants.CENTER);
        lbl.setFont(FontManager.getRunescapeSmallFont());
        lbl.setForeground(isFuture ? COLOR_HEADER_TEXT : COLOR_TEXT);
        cell.add(lbl, BorderLayout.CENTER);

        if (!isFuture)
        {
            cell.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
            cell.addMouseListener(new java.awt.event.MouseAdapter()
            {
                @Override
                public void mouseClicked(java.awt.event.MouseEvent e)
                {
                    selectedDate = date;
                    rebuildCalendarGrid();
                    onDateSelected.accept(date);
                }

                @Override
                public void mouseEntered(java.awt.event.MouseEvent e)
                {
                    if (!date.equals(selectedDate))
                    {
                        cell.setBackground(ColorScheme.MEDIUM_GRAY_COLOR);
                    }
                }

                @Override
                public void mouseExited(java.awt.event.MouseEvent e)
                {
                    if (!date.equals(selectedDate))
                    {
                        cell.setBackground(hasData ? COLOR_HAS_DATA : COLOR_CARD);
                    }
                }
            });
        }

        return cell;
    }

    private JPanel emptyCell()
    {
        JPanel cell = new JPanel();
        cell.setBackground(COLOR_CARD);
        cell.setPreferredSize(new Dimension(28, 24));
        return cell;
    }

    // endregion

    // region All button

    private JButton buildAllButton()
    {
        JButton btn = new JButton("Show all dates");
        btn.setFont(FontManager.getRunescapeSmallFont());
        btn.setForeground(COLOR_TEXT);
        btn.setBackground(ColorScheme.MEDIUM_GRAY_COLOR);
        btn.setBorder(new EmptyBorder(4, 8, 4, 8));
        btn.setFocusPainted(false);
        btn.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        btn.setMaximumSize(new Dimension(Integer.MAX_VALUE, 28));
        btn.addActionListener(e ->
        {
            selectedDate = null;
            rebuildCalendarGrid();
            onDateSelected.accept(null);
        });
        return btn;
    }

    // endregion

    // region Log rows

    private JPanel buildRow(LogEntry entry)
    {
        JPanel row = new JPanel(new BorderLayout());
        row.setBackground(COLOR_CARD);
        row.setBorder(new EmptyBorder(6, 8, 6, 8));
        row.setMaximumSize(new Dimension(Integer.MAX_VALUE, 50));

        row.add(getLeft(entry), BorderLayout.WEST);
        row.add(getRight(entry), BorderLayout.EAST);

        return row;
    }

    @Nonnull
    private static JPanel getLeft(LogEntry entry)
    {
        JPanel left = new JPanel();
        left.setLayout(new BoxLayout(left, BoxLayout.Y_AXIS));
        left.setBackground(ColorScheme.DARKER_GRAY_COLOR);

        JLabel dateLabel = new JLabel(entry.getDate());
        dateLabel.setForeground(Color.WHITE);
        dateLabel.setFont(FontManager.getRunescapeSmallFont());

        JLabel courseLabel = new JLabel(entry.getCourse());
        courseLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
        courseLabel.setFont(FontManager.getRunescapeSmallFont());

        left.add(dateLabel);
        left.add(courseLabel);
        return left;
    }

    @Nonnull
    private static JPanel getRight(LogEntry entry)
    {
        JPanel right = new JPanel();
        right.setLayout(new BoxLayout(right, BoxLayout.Y_AXIS));
        right.setBackground(ColorScheme.DARKER_GRAY_COLOR);

        JLabel lapsLabel = new JLabel(entry.getLaps() + " laps");
        lapsLabel.setForeground(Color.WHITE);
        lapsLabel.setFont(FontManager.getRunescapeSmallFont());
        lapsLabel.setAlignmentX(Component.RIGHT_ALIGNMENT);

        JLabel marksLabel = new JLabel(entry.getMarks() + " marks");
        marksLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
        marksLabel.setFont(FontManager.getRunescapeSmallFont());
        marksLabel.setAlignmentX(Component.RIGHT_ALIGNMENT);

        right.add(lapsLabel);
        right.add(marksLabel);
        return right;
    }

    // endregion
}

package com.mvpief;

import net.runelite.client.config.ConfigManager;
import lombok.extern.slf4j.Slf4j;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Singleton
public class LogStore
{
    private static final String KEY_KNOWN_COURSES = "knownCourses";
    private static final String KEY_KNOWN_DATES = "knownDates";

    @Inject private ConfigManager configManager;
    @Inject private DailyAgilityConfig config;

    // region Public API

    /**
     * Increments the lap count for the given course on today's date.
     * Also registers the course and date if it hasn't been seen before.
     */
    public void recordLap(String course)
    {
        if (!config.logEntries()) return;
        String date = LocalDate.now().toString();
        LogEntry current = getEntry(date, course);
        saveEntry(date, course, current.getLaps() + 1, current.getMarks());
        registerCourse(course);
        registerDate(date);
    }

    /**
     * Increments the mark count for the given course on today's date.
     */
    public void recordMarks(String course, int count)
    {
        if (!config.logEntries()) return;
        String date = LocalDate.now().toString();
        LogEntry current = getEntry(date, course);
        saveEntry(date, course, current.getLaps(), current.getMarks() + count);
    }

    public List<LogEntry> getEntries(String courseFilter)
    {
        return getEntries(courseFilter, null);
    }

    public List<LogEntry> getEntries(String courseFilter, LocalDate dateFilter)
    {
        List<String> courses = courseFilter != null
                ? Collections.singletonList(courseFilter)
                : getKnownCourses();

        List<String> dates = dateFilter != null
                ? Collections.singletonList(dateFilter.toString())
                : getKnownDates();

        List<LogEntry> entries = new ArrayList<>();

        for (String dateStr : dates)
        {
            for (String course : courses)
            {
                String key = buildKey(dateStr, course);
                String stored = configManager.getConfiguration(DailyAgilityConfig.GROUP, key);
                if (stored != null && !stored.isEmpty())
                {
                    entries.add(parse(dateStr, course, stored));
                }
            }
        }

        return entries;
    }

    public List<String> getKnownDates()
    {
        String stored = configManager.getConfiguration(DailyAgilityConfig.GROUP, KEY_KNOWN_DATES);
        if (stored == null || stored.isEmpty()) return new ArrayList<>();
        return Arrays.stream(stored.split(","))
                .map(String::trim)
                .filter(s -> !s.isEmpty())
                // ISO date strings sort lexicographically, newest first
                .sorted(Collections.reverseOrder())
                .collect(Collectors.toList());
    }

    /**
     * Returns the list of every course that has ever been logged.
     */
    public List<String> getKnownCourses()
    {
        String stored = configManager.getConfiguration(DailyAgilityConfig.GROUP, KEY_KNOWN_COURSES);
        if (stored == null || stored.isEmpty()) return new ArrayList<>();
        return Arrays.stream(stored.split(","))
                .map(String::trim)
                .filter(s -> !s.isEmpty())
                .collect(Collectors.toList());
    }

    // endregion

    // region Internals

    private LogEntry getEntry(String date, String course)
    {
        String key = buildKey(date, course);
        String stored = configManager.getConfiguration(DailyAgilityConfig.GROUP, key);
        if (stored == null || stored.isEmpty()) return new LogEntry(date, course, 0, 0);
        return parse(date, course, stored);
    }

    private void saveEntry(String date, String course, int laps, int marks)
    {
        String key = buildKey(date, course);
        configManager.setConfiguration(DailyAgilityConfig.GROUP, key, laps + "," + marks);
    }

    private void registerCourse(String course)
    {
        List<String> courses = getKnownCourses();
        if (courses.contains(course)) return;
        courses.add(course);
        configManager.setConfiguration(
                DailyAgilityConfig.GROUP,
                KEY_KNOWN_COURSES,
                String.join(",", courses)
        );
    }

    private void registerDate(String date)
    {
        List<String> dates = getKnownDates();
        if (dates.contains(date)) return;
        dates.add(date);
        configManager.setConfiguration(
                DailyAgilityConfig.GROUP,
                KEY_KNOWN_DATES,
                String.join(",", dates)
        );
    }

    private LogEntry parse(String date, String course, String stored)
    {
        try
        {
            String[] parts = stored.split(",");
            int laps = Integer.parseInt(parts[0]);
            int marks = parts.length > 1 ? Integer.parseInt(parts[1]) : 0;
            return new LogEntry(date, course, laps, marks);
        }
        catch (Exception e)
        {
            log.error("Failed to parse log entry for {} on {}: {}", course, date, stored);
            return new LogEntry(date, course, 0, 0);
        }
    }

    private String buildKey(String date, String course)
    {
        // e.g. "log_2026-05-05_seers_village"
        return "log_" + date + "_" + course.toLowerCase().replace(" ", "_");
    }

    // endregion
}

package com.mvpief;

import net.runelite.client.config.Config;
import net.runelite.client.config.ConfigGroup;
import net.runelite.client.config.ConfigItem;
import net.runelite.client.config.ConfigSection;

@ConfigGroup(DailyAgilityConfig.GROUP)
public interface DailyAgilityConfig extends Config
{
	String GROUP = "dailyAgility";

	@ConfigSection(name = "Laps", description = "Lap goal and display settings", position = 0)
	String lapsSection = "laps";

	@ConfigSection(name = "Marks of Grace", description = "Marks of Grace goal settings", position = 1)
	String marksSection = "marks";

	@ConfigSection(name = "Display", description = "Overlay display options", position = 2)
	String displaySection = "display";

	@ConfigSection(name = "Logging", description = "Logging options", position = 3)
	String loggingSection = "logging";

	// --- Laps ---
	@ConfigItem(keyName = "dailyGoal", name = "Daily Lap Goal", description = "How many rooftop laps to complete today.", position = 0, section = lapsSection)
	default int dailyGoal() { return 100; }

	@ConfigItem(keyName = "lapsRemaining", name = "", description = "", hidden = true, section = lapsSection)
	default int lapsRemaining() { return -1; }

	// --- Marks ---
	@ConfigItem(keyName = "marksGoal", name = "Daily Marks Goal", description = "Marks of Grace to collect today.", position = 0, section = marksSection)
	default int marksGoal() { return 10; }

	@ConfigItem(keyName = "marksRemaining", name = "", description = "", hidden = true, section = marksSection)
	default int marksRemaining() { return 0; }

	// --- Display ---
	@ConfigItem(
			keyName = "overlayDisplayMode",
			name = "Overlay Mode",
			description = "Controls which overlay panels are rendered.",
			position = 0,
			section = displaySection
	)
	default OverlayDisplayMode overlayDisplayMode() { return OverlayDisplayMode.ALWAYS; }

	@ConfigItem(keyName = "showLapsLeft", name = "Show Laps Left", description = "Show the laps left on the overlay.", position = 0, section = displaySection)
	default boolean showLapsLeft() { return true; }

	@ConfigItem(keyName = "showMarksLeft", name = "Show Marks Left", description = "Show the marks left on the overlay.", position = 1, section = displaySection)
	default boolean showMarksLeft() { return true; }

	@ConfigItem(keyName = "showLapTime", name = "Show Last Lap Time", description = "Show the last lap time on the overlay.", position = 2, section = displaySection)
	default boolean showLapTime() { return true; }

	@ConfigItem(keyName = "showAverageTime", name = "Show Average Time", description = "Show average lap time on the overlay.", position = 3, section = displaySection)
	default boolean showAverageTime() { return true; }

	@ConfigItem(keyName = "showETA", name = "Show ETA", description = "Show estimated time remaining on the overlay.", position = 4, section = displaySection)
	default boolean showETA() { return true; }

	@ConfigItem(keyName = "logEntries", name = "Log daily laps", description = "Logs the daily laps and mark of grace.", position = 0, section = loggingSection)
	default boolean logEntries() { return true; }

	// --- Internal ---
	@ConfigItem(keyName = "lastSavedDate", name = "", description = "", hidden = true)
	default String lastSavedDate() { return ""; }

	@ConfigItem(keyName = "lastKnownCourse", name = "", description = "", hidden = true)
	default String lastKnownCourse() { return ""; }
}

