        compassToggle.setSouthUp(southUp);
    }

    private static void copyText(String text)
    {
        if (text == null || text.isEmpty())
        {
            return;
        }
        String out = text;
        if (out.startsWith("[") && out.endsWith("]") && out.length() >= 2)
        {
            out = out.substring(1, out.length() - 1);
        }
        try
        {
            Toolkit.getDefaultToolkit().getSystemClipboard().setContents(new StringSelection(out), null);
        }
        catch (Exception ignored)
        {
            // User can still select and Ctrl+C.
        }
    }

    private JPanel makeLegendRow(ColorSwatch swatch, String text)
    {
        JPanel row = new JPanel(new BorderLayout(6, 0));
        row.setOpaque(false);

        JLabel label = new JLabel(text);
        label.setFont(new Font(Font.SANS_SERIF, Font.PLAIN, 12));

        row.add(swatch, BorderLayout.WEST);
        row.add(label, BorderLayout.CENTER);
        return row;
    }

    private static void setButtonAction(JButton button, Runnable action)
    {
        for (ActionListener listener : button.getActionListeners())
        {
            button.removeActionListener(listener);
        }
        if (action != null)
        {
            button.addActionListener(e -> action.run());
        }
    }

    private static final class ColorSwatch extends JPanel
    {
        private ColorSwatch()
        {
            setPreferredSize(new Dimension(12, 12));
            setMinimumSize(new Dimension(12, 12));
            setMaximumSize(new Dimension(12, 12));
            setBorder(BorderFactory.createLineBorder(Color.DARK_GRAY));
            setOpaque(true);
        }

        private void setColor(Color color)
        {
            if (color != null)
            {
                setBackground(color);
            }
        }
    }

    private final class CompassToggle extends JPanel
    {
        private boolean southUp = true;

        private CompassToggle()
        {
            setPreferredSize(new Dimension(26, 26));
            setMinimumSize(new Dimension(26, 26));
            setMaximumSize(new Dimension(26, 26));
            setOpaque(false);
            setToolTipText("Toggle map orientation");
            setCursor(new Cursor(Cursor.HAND_CURSOR));
            addMouseListener(new java.awt.event.MouseAdapter()
            {
                @Override
                public void mouseClicked(java.awt.event.MouseEvent e)
                {
                    InfernoScouterPanel.this.setSouthUp(!southUp);
                }
            });
        }

        private void setSouthUp(boolean southUp)
        {
            this.southUp = southUp;
            repaint();
        }

        @Override
        protected void paintComponent(Graphics g)
        {
            super.paintComponent(g);
            Graphics2D g2 = (Graphics2D) g.create();
            try
            {
                g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
                int size = Math.min(getWidth(), getHeight()) - 2;
                int x = (getWidth() - size) / 2;
                int y = (getHeight() - size) / 2;

                g2.setColor(new Color(40, 40, 40));
                g2.fillOval(x, y, size, size);
                g2.setColor(new Color(120, 120, 120));
                g2.drawOval(x, y, size, size);

                String letter = southUp ? "S" : "N";
                Font font = g2.getFont().deriveFont(Font.BOLD, 12f);
                g2.setFont(font);
                FontMetrics fm = g2.getFontMetrics(font);
                int textWidth = fm.stringWidth(letter);
                int textX = x + (size - textWidth) / 2;
                int textY = y + (size + fm.getAscent() - fm.getDescent()) / 2;
                g2.setColor(Color.WHITE);
                g2.drawString(letter, textX, textY);
            }
            finally
            {
                g2.dispose();
            }
        }
    }
}

package com.infernoscouter;

import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics2D;
import java.awt.Polygon;
import java.util.Collection;
import javax.inject.Inject;
import javax.inject.Singleton;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.Point;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayPriority;
import net.runelite.client.ui.overlay.OverlayUtil;

@Singleton
public class InfernoStartTileOverlay extends Overlay
{
    private final Client client;
    private final InfernoScouterPlugin plugin;

    @Inject
    public InfernoStartTileOverlay(Client client, InfernoScouterPlugin plugin)
    {
        this.client = client;
        this.plugin = plugin;
        setLayer(OverlayLayer.ABOVE_SCENE);
        setPosition(OverlayPosition.DYNAMIC);
        setPriority(OverlayPriority.LOW);
    }

    @Override
    public Dimension render(Graphics2D graphics)
    {
        InfernoScouterPlugin.StartTile tile = plugin.getStartTile();
        if (tile == null || !plugin.isInInferno())
        {
            return null;
        }

        Collection<WorldPoint> candidates = WorldPoint.toLocalInstance(client, tile.worldPoint);
        if (candidates == null || candidates.isEmpty())
        {
            candidates = java.util.List.of(tile.worldPoint);
        }

        Color color = tile.color;
        String label = tile.label;

        for (WorldPoint worldPoint : candidates)
        {
            if (client.getPlane() != worldPoint.getPlane())
            {
                continue;
            }

            LocalPoint localPoint = LocalPoint.fromWorld(client, worldPoint);
            if (localPoint == null)
            {
                continue;
            }

            Polygon poly = Perspective.getCanvasTilePoly(client, localPoint);
            if (poly == null)
            {
                continue;
            }

            Color fill = new Color(0, 0, 0, 50);
            OverlayUtil.renderPolygon(graphics, poly, color, fill, new BasicStroke(2));

            if (label != null && !label.isEmpty())
            {
                Point textLocation = Perspective.getCanvasTextLocation(client, graphics, localPoint, label, 0);
                if (textLocation != null)
                {
                    OverlayUtil.renderTextLocation(graphics, textLocation, label, color);
                }
            }
        }

        return null;
    }
}

